// svt.js — Donnees SVT (7 sections, 280+ flashcards, 160+ quiz)
(function() {
    if (!window.StudFlow || !window.StudFlow.subjects) return;

    window.StudFlow.subjects.register({
        id: 'svt',
        name: 'SVT',
        icon: '\uD83E\uDDEC',
        color: 'hot',
        sections: [
            // ===== SECTION 1 : GENETIQUE & ADN =====
            {
                id: 'genetique',
                title: 'Genetique et ADN',
                icon: '\uD83E\uDDEC',
                content: '<h3>ADN et expression genetique</h3>'
                    + '<ul>'
                    + '<li><strong>ADN</strong> : acide desoxyribonucleique, double helice composee de nucleotides (A, T, C, G). Les bases sont complementaires : A-T et C-G</li>'
                    + '<li><strong>Gene</strong> : portion d\'ADN codant pour un polypeptide. Un gene peut exister sous differentes versions appelees alleles</li>'
                    + '<li><strong>Transcription</strong> : copie de l\'ADN en ARN messager (ARNm) dans le noyau, par l\'ARN polymerase. U remplace T dans l\'ARNm</li>'
                    + '<li><strong>Traduction</strong> : synthese d\'un polypeptide a partir de l\'ARNm par les ribosomes dans le cytoplasme. Chaque codon (triplet de nucleotides) code un acide amine</li>'
                    + '</ul>'
                    + '<h3>Code genetique et mutations</h3>'
                    + '<ul>'
                    + '<li><strong>Code genetique</strong> : universel, degenere (plusieurs codons pour un meme acide amine), non chevauchant, lu dans un seul cadre de lecture</li>'
                    + '<li><strong>Mutations</strong> : substitution, insertion ou deletion. Faux-sens, non-sens, silencieuse</li>'
                    + '<li><strong>Agents mutagenes</strong> : UV, radiations ionisantes, substances chimiques (benzene, amiante)</li>'
                    + '</ul>'
                    + '<h3>Genie genetique et biotechnologies</h3>'
                    + '<ul>'
                    + '<li><strong>CRISPR-Cas9</strong> : ciseaux moleculaires permettant de modifier precisement l\'ADN d\'un organisme</li>'
                    + '<li><strong>OGM</strong> : organisme dont le genome a ete modifie par introduction d\'un gene etranger (transgenese)</li>'
                    + '<li><strong>Therapie genique</strong> : introduction d\'un gene fonctionnel pour corriger une maladie genetique</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Quelle est la structure de l\'ADN ?', answer: 'L\'ADN est une double helice formee de deux brins antiparalleles de nucleotides relies par des liaisons hydrogene entre bases complementaires : adenine (A) avec thymine (T), cytosine (C) avec guanine (G). Chaque nucleotide comprend un sucre (desoxyribose), un phosphate et une base azotee. 🤯 Le savais-tu ? Ton ADN mis bout a bout mesurerait environ 2 fois le diametre du systeme solaire !' },
                    { question: 'Qu\'est-ce qu\'un nucleotide ?', answer: 'Un nucleotide est l\'unite de base de l\'ADN. Il est compose de trois elements : un sucre (desoxyribose pour l\'ADN, ribose pour l\'ARN), un groupement phosphate et une base azotee (A, T, C ou G). Les nucleotides sont relies entre eux par des liaisons phosphodiester. 💡 ASTUCE MEMO : Pense a un collier de perles — chaque perle est un nucleotide, le fil est la liaison phosphodiester.' },
                    { question: 'Qu\'est-ce qu\'un allele ?', answer: 'Un allele est une version d\'un gene. Differents alleles d\'un meme gene different par leur sequence de nucleotides et peuvent coder des proteines aux proprietes differentes. Exemples : alleles des groupes sanguins (IA, IB, i). On herite d\'un allele de chaque parent. ⚠️ PIEGE BAC : Un allele n\'est PAS un gene different, c\'est une VARIANTE du meme gene !' },
                    { question: 'Decrire les etapes de la transcription.', answer: 'L\'ARN polymerase se fixe sur le promoteur du gene, separe les deux brins d\'ADN et synthetise un brin d\'ARNm complementaire du brin matrice (sens 5\' vers 3\'). Dans l\'ARNm, l\'uracile (U) remplace la thymine (T). La transcription se termine quand l\'ARN polymerase atteint un signal de terminaison. 🧠 TRUC POUR RETENIR : TransCRIPTion = on ECRIT une COPIE (comme recopier un livre en bibliotheque, l\'original reste sur place).' },
                    { question: 'Qu\'est-ce que la traduction ?', answer: 'La traduction est la synthese d\'un polypeptide a partir de l\'ARNm par les ribosomes. L\'ARNm est lu codon par codon (triplets). Chaque codon correspond a un acide amine via le code genetique. La synthese commence au codon AUG (methionine) et s\'arrete a un codon stop (UAA, UAG, UGA). 💡 ASTUCE MEMO : TraDUCTion = on TRADUIT une langue (celle des nucleotides) en une autre langue (celle des acides amines).' },
                    { question: 'Quelles sont les proprietes du code genetique ?', answer: 'Le code genetique est : 1) Universel — le meme chez presque tous les etres vivants (preuve d\'une origine commune). 2) Degenere (ou redondant) — plusieurs codons codent le meme acide amine. 3) Non chevauchant — chaque nucleotide n\'appartient qu\'a un seul codon. 4) Non ambigu — un codon ne code que pour un seul acide amine. 🧠 TRUC POUR RETENIR : "UNDN" — Universel, Non-ambigu, Degenere, Non-chevauchant.' },
                    { question: 'Quels sont les trois types de mutations ponctuelles ?', answer: 'Substitution : remplacement d\'un nucleotide par un autre. Insertion : ajout d\'un nucleotide. Deletion : perte d\'un nucleotide. Les insertions et deletions provoquent un decalage du cadre de lecture (frameshift), ce qui modifie tous les codons en aval — consequences generalement plus graves ! ⚠️ PIEGE BAC : Ne confonds pas mutation ponctuelle (1 nucleotide) et mutation chromosomique (portion entiere de chromosome).' },
                    { question: 'Quelle difference entre mutation faux-sens, non-sens et silencieuse ?', answer: 'Faux-sens : le codon modifie code un acide amine DIFFERENT (peut alterer la proteine). Non-sens : le codon modifie devient un codon STOP — la proteine est tronquee (souvent grave). Silencieuse : le codon modifie code le MEME acide amine grace a la degenerescence du code (pas de consequence). 💡 ASTUCE MEMO : Faux-sens = Faux acide amine. Non-sens = ca N\'a plus de sens, on s\'arrete !' },
                    { question: 'Qu\'est-ce qu\'un agent mutagene ? Donner des exemples.', answer: 'Un agent mutagene est un facteur qui augmente la frequence des mutations. Exemples physiques : UV (dimeres de thymine), rayons X, radioactivite. Exemples chimiques : benzene, amiante, goudrons du tabac. Exemples biologiques : certains virus (HPV). 🤯 Le savais-tu ? Les UV sont responsables de 80% des cancers de la peau — voila pourquoi la creme solaire n\'est pas optionnelle !' },
                    { question: 'Qu\'est-ce que le dogme central de la biologie moleculaire ?', answer: 'Le dogme central decrit le flux d\'information genetique : ADN → (transcription) → ARNm → (traduction) → Proteine. L\'information va de l\'ADN vers les proteines, jamais en sens inverse (sauf la transcription inverse par les retrovirus comme le VIH). C\'est le principe fondateur de la biologie moleculaire, enonce par Francis Crick en 1958.' },
                    { question: 'Qu\'est-ce que la replication de l\'ADN ?', answer: 'La replication est la copie integrale de l\'ADN avant la division cellulaire (phase S). L\'ADN helicase separe les deux brins, l\'ADN polymerase synthetise un nouveau brin complementaire sur chaque brin matrice. Le resultat : deux molecules d\'ADN identiques a l\'originale. Chaque molecule contient un brin ancien et un brin neuf = replication SEMI-CONSERVATIVE. 🧠 TRUC POUR RETENIR : Semi-conservative = Semi veut dire moitie — chaque fille garde la moitie de la mere.' },
                    { question: 'Qu\'est-ce qu\'un ARN de transfert (ARNt) ?', answer: 'L\'ARNt est une petite molecule d\'ARN en forme de trefle qui fait le lien entre le code genetique et les acides amines. Chaque ARNt porte un anticodon (complementaire du codon de l\'ARNm) et l\'acide amine correspondant. C\'est le "traducteur" moleculaire qui permet de convertir le langage des nucleotides en langage des acides amines. 💡 ASTUCE MEMO : ARNt = ARN Taxi — il TRANSPORTE l\'acide amine jusqu\'au ribosome !' },
                    { question: 'Qu\'est-ce que CRISPR-Cas9 ?', answer: 'CRISPR-Cas9 est un outil de genie genetique revolutionnaire, decouvert en 2012 par Charpentier et Doudna (Prix Nobel 2020). Il fonctionne comme des "ciseaux moleculaires" : un ARN guide dirige la proteine Cas9 vers une sequence precise d\'ADN pour la couper. On peut ainsi supprimer, remplacer ou inserer un gene avec une precision inedite. 🤯 Le savais-tu ? Ce systeme vient a l\'origine des bacteries qui l\'utilisent pour se defendre contre les virus !' },
                    { question: 'Qu\'est-ce qu\'un OGM ?', answer: 'Un Organisme Genetiquement Modifie est un organisme dont le genome a ete modifie par transgenese : introduction d\'un gene provenant d\'une autre espece. Exemples : mais Bt (gene de resistance aux insectes issu d\'une bacterie), riz dore (enrichi en vitamine A). Les OGM suscitent des debats ethiques et environnementaux importants.' },
                    { question: 'Qu\'est-ce que la therapie genique ?', answer: 'La therapie genique consiste a introduire un gene fonctionnel dans les cellules d\'un patient pour corriger une maladie genetique. Le gene est vehicule par un vecteur (souvent un virus inactive). Exemples de reussites : traitement de l\'amyotrophie spinale (Zolgensma), de certaines immunodeficiences (bebes-bulle). Elle ne modifie pas les cellules germinales (pas de transmission a la descendance).' },
                    { question: 'Expliquer la difference entre genotype et phenotype.', answer: 'Le genotype est l\'ensemble des alleles portes par un individu. Le phenotype est l\'ensemble des caracteres observables (morphologiques, physiologiques, moleculaires), resultant de l\'expression du genotype en interaction avec l\'environnement. Un meme genotype peut donner des phenotypes differents selon l\'environnement ! ⚠️ PIEGE BAC : Le phenotype ne depend PAS que du genotype — l\'environnement joue aussi (ex : la couleur du pelage du chat siamois depend de la temperature).' },
                    { question: 'Qu\'est-ce que l\'epigenetique ?', answer: 'L\'epigenetique etudie les modifications de l\'expression des genes SANS changement de la sequence d\'ADN. Les mecanismes principaux sont la methylation de l\'ADN (ajout de CH3 sur les cytosines, ce qui "eteint" le gene) et la modification des histones. Ces modifications sont reversibles mais parfois transmissibles. 🤯 Le savais-tu ? Deux vrais jumeaux ont le meme ADN mais pas le meme epigenome — c\'est pour ca qu\'ils ne sont jamais 100% identiques !' },
                    { question: 'Qu\'est-ce qu\'un codon ? Combien y en a-t-il ?', answer: 'Un codon est un triplet de 3 nucleotides consecutifs sur l\'ARNm qui code pour un acide amine (ou un signal stop). Il existe 4³ = 64 codons possibles, codant pour 20 acides amines + 3 codons stop (UAA, UAG, UGA). Le codon AUG code la methionine ET sert de codon initiateur. 💡 ASTUCE MEMO : 64 codons pour 20 acides amines = code degenere (comme avoir 64 cles pour 20 serrures).' },
                    { question: 'Pourquoi dit-on que le code genetique est universel ?', answer: 'Le code genetique est dit universel car il est quasiment identique chez tous les etres vivants, de la bacterie a l\'humain. Le codon AUG code toujours la methionine, UAA est toujours un codon stop, etc. C\'est une preuve majeure de l\'origine commune de tous les etres vivants. Quelques exceptions existent (mitochondries, certains protistes) mais elles sont tres rares.' },
                    { question: 'Comment l\'environnement influence-t-il l\'expression des genes ?', answer: 'L\'environnement peut moduler l\'expression genetique sans changer la sequence d\'ADN (epigenetique). Exemples : l\'alimentation (carences en folates = methylation alteree), le stress (activation de genes de reponse), la temperature (couleur du pelage chez le chat siamois), l\'exposition aux polluants (perturbateurs endocriniens). Le phenotype est donc le resultat de l\'interaction genotype x environnement.' },
                    { question: 'Qu\'est-ce qu\'un gene de predisposition ?', answer: 'Un gene de predisposition est un gene dont certains alleles augmentent le RISQUE de developper une maladie, sans la provoquer systematiquement. Exemples : BRCA1/BRCA2 (cancer du sein — risque multiplie par 5-10), allele ApoE4 (maladie d\'Alzheimer). La maladie survient si d\'autres facteurs (environnement, mode de vie) s\'ajoutent. ⚠️ PIEGE BAC : Predisposition ≠ determinisme ! Avoir l\'allele ne signifie pas avoir la maladie.' },
                    { question: 'Quel est le role du promoteur d\'un gene ?', answer: 'Le promoteur est une sequence d\'ADN situee en amont (avant) du gene, qui sert de site de fixation pour l\'ARN polymerase. C\'est lui qui controle le DEBUT de la transcription. Sans promoteur, le gene ne peut pas etre transcrit. Certains promoteurs contiennent la sequence TATA (TATA box), reconnue par des facteurs de transcription. Le promoteur est comme l\'interrupteur "ON/OFF" d\'un gene.' },
                    { question: 'Qu\'est-ce que l\'ARNm mature (ARNm fonctionnel) chez les eucaryotes ?', answer: 'Chez les eucaryotes, l\'ARN pre-messager subit une maturation avant de quitter le noyau : 1) Ajout d\'une coiffe en 5\' (protection). 2) Ajout d\'une queue poly-A en 3\' (stabilite). 3) Epissage : retrait des introns (sequences non codantes) et reunion des exons (sequences codantes). L\'epissage alternatif permet de produire PLUSIEURS proteines a partir d\'un SEUL gene !' },
                    { question: 'Qu\'est-ce que l\'electrophorese de l\'ADN ?', answer: 'L\'electrophorese est une technique qui separe les fragments d\'ADN selon leur taille dans un gel d\'agarose soumis a un champ electrique. L\'ADN, charge negativement (phosphates), migre vers le pole positif. Les petits fragments migrent plus vite, les grands restent en haut. On peut ainsi comparer des profils genetiques (empreintes ADN), verifier une amplification PCR, etc.' },
                    { question: 'Qu\'est-ce que la PCR et a quoi sert-elle ?', answer: 'La PCR (Polymerase Chain Reaction) est une technique qui permet d\'amplifier (copier en millions d\'exemplaires) un fragment specifique d\'ADN. Elle utilise une ADN polymerase thermoresistante (Taq polymerase), des amorces et des cycles de temperature (denaturation, hybridation, elongation). Applications : tests COVID, enquetes criminelles, diagnostic genetique. 🤯 Le savais-tu ? On peut amplifier l\'ADN d\'une seule cellule !' },
                    { question: 'Qu\'est-ce qu\'un chromosome ? Quelle difference entre chromatine et chromosome condense ?', answer: 'Un chromosome est une molecule d\'ADN associee a des proteines (histones). En interphase, l\'ADN est sous forme de chromatine (decondensee, active, transcription possible). Avant la division, la chromatine se condense en chromosomes visibles au microscope (en forme de X si repliques = 2 chromatides soeurs). 💡 ASTUCE MEMO : Chromatine = fil de laine emmele (actif). Chromosome condense = pelote bien enroulee (pret pour la division).' },
                    { question: 'Qu\'est-ce qu\'un caryotype et que peut-il reveler ?', answer: 'Un caryotype est la photographie de l\'ensemble des chromosomes d\'une cellule, classes par paires et par taille. Chez l\'humain : 46 chromosomes = 22 paires d\'autosomes + 1 paire de chromosomes sexuels (XX ou XY). Il permet de detecter des anomalies chromosomiques : trisomie 21 (3 chromosomes 21), syndrome de Turner (45,X), syndrome de Klinefelter (47,XXY).' },
                    { question: 'Qu\'est-ce que l\'ADN polymerase et son role dans la replication ?', answer: 'L\'ADN polymerase est l\'enzyme qui synthetise le nouveau brin d\'ADN pendant la replication. Elle lit le brin matrice dans le sens 3\'→5\' et synthetise le nouveau brin dans le sens 5\'→3\'. Elle possede aussi une activite de CORRECTION (exonuclease 3\'→5\') qui lui permet de verifier et corriger les erreurs — seulement 1 erreur pour 10 milliards de nucleotides apres reparation ! 🤯 Le savais-tu ? L\'ADN polymerase est comme un correcteur orthographique biologique ultra-performant.' },
                    { question: 'Qu\'est-ce que la drepanocytose ?', answer: 'La drepanocytose (anemie falciforme) est une maladie genetique causee par une mutation PONCTUELLE du gene de la beta-globine (hemoglobine). Un SEUL nucleotide change : GAG→GTG, remplacement de l\'acide glutamique par la valine en position 6. L\'hemoglobine S deforme les globules rouges en faucille (sickle). 💡 ASTUCE MEMO : 1 nucleotide change = 1 acide amine change = 1 maladie grave. C\'est l\'exemple classique de mutation faux-sens au Bac !' },
                    { question: 'Qu\'est-ce que la transgenese ?', answer: 'La transgenese est le transfert d\'un gene d\'une espece a une autre pour conferer un caractere nouveau. Etapes : 1) Identifier et isoler le gene d\'interet. 2) L\'inserer dans un vecteur (plasmide, virus). 3) Introduire le vecteur dans la cellule cible. 4) Verifier l\'expression du transgene. Exemples : mais Bt (gene bacterien de resistance aux insectes), bacteries produisant de l\'insuline humaine. C\'est la base des OGM.' },
                    { question: 'Que sont les exons et les introns ?', answer: 'Chez les eucaryotes, un gene est constitue d\'EXONS (sequences CODANTES, conservees dans l\'ARNm mature) et d\'INTRONS (sequences NON codantes, eliminees lors de l\'epissage). Seuls les exons sont traduits en proteine. 💡 ASTUCE MEMO : EXons = EXprimes (gardes). INtrons = INutiles (enleves). L\'epissage alternatif peut combiner differemment les exons, permettant a un seul gene de produire PLUSIEURS proteines differentes !' },
                    { question: 'Qu\'est-ce qu\'un plasmide ?', answer: 'Un plasmide est une petite molecule d\'ADN circulaire presente chez les bacteries, independante du chromosome principal. Il se replique de facon autonome et porte souvent des genes de resistance aux antibiotiques. En genie genetique, les plasmides sont utilises comme VECTEURS pour inserer des genes d\'interet dans des bacteries. C\'est un outil fondamental de la biotechnologie moderne.' },
                    { question: 'Qu\'est-ce qu\'une enzyme de restriction ?', answer: 'Une enzyme de restriction est une proteine qui coupe l\'ADN a des sequences specifiques (sites de restriction). Par exemple, EcoRI coupe la sequence GAATTC. Elles sont les "ciseaux moleculaires" naturels des bacteries (defense contre les virus). En genie genetique, elles servent a decouper l\'ADN pour inserer des genes dans des vecteurs. Chaque enzyme reconnait une sequence palindromique specifique.' },
                    { question: 'Qu\'est-ce qu\'une maladie genetique dominante vs recessive ?', answer: 'Maladie DOMINANTE : un seul allele mute suffit pour etre malade (heterozygote = malade). Exemples : choree de Huntington, achondroplasie. Maladie RECESSIVE : il faut DEUX alleles mutes (homozygote) pour etre malade. L\'heterozygote est porteur sain (non malade mais peut transmettre). Exemples : mucoviscidose, drepanocytose. ⚠️ PIEGE BAC : Un porteur sain d\'une maladie recessive est HETEROZYGOTE — il porte l\'allele mute mais n\'est pas malade !' },
                    { question: 'Qu\'est-ce que le sequencage de l\'ADN ?', answer: 'Le sequencage est la determination de l\'ordre precis des nucleotides (A, T, C, G) dans une molecule d\'ADN. Le Projet Genome Humain (termine en 2003) a sequence les 3,2 milliards de paires de bases de notre ADN. Aujourd\'hui, le sequencage est devenu rapide et peu couteux grace aux technologies de nouvelle generation (NGS). 🤯 Le savais-tu ? Sequencer un genome humain coutait 3 milliards de dollars en 2001 — aujourd\'hui moins de 1000 dollars ! La puissance de la technologie.' },
                    { question: 'Qu\'est-ce qu\'un ribosome et ou se trouve-t-il ?', answer: 'Le ribosome est la "machine" cellulaire qui realise la traduction (synthese des proteines a partir de l\'ARNm). Il est compose de deux sous-unites (grande et petite) faites d\'ARN ribosomique (ARNr) et de proteines. Localisation : dans le cytoplasme (ribosomes libres = proteines cytoplasmiques) ou sur le reticulum endoplasmique rugueux (proteines secretees ou membranaires). Les ribosomes sont identiques chez tous les etres vivants — encore une preuve de l\'universalite du vivant.' },
                    { question: 'Quelle est la structure d\'un nucleotide d\'ADN ?', answer: 'Un nucleotide d\'ADN est compose de 3 elements : 1) Un SUCRE a 5 carbones : le desoxyribose (pas de OH en position 2\', d\'ou "desoxy"). 2) Un groupement PHOSPHATE (charge negative, constitue le "squelette" de l\'ADN). 3) Une BASE AZOTEE : purine (Adenine ou Guanine — 2 cycles) ou pyrimidine (Thymine ou Cytosine — 1 cycle). 💡 ASTUCE MEMO : PURines = les PLUS GROSSES (A, G = 2 cycles). PYRimidines = les Plus petites (T, C = 1 cycle). A-G = Au Garage (gros vehicules), T-C = Tout Compact (petites voitures).' },
                    { question: 'Qu\'est-ce qu\'un vecteur en genie genetique ?', answer: 'Un vecteur est une molecule d\'ADN utilisee pour transporter un gene d\'interet dans une cellule cible. Types principaux : 1) Plasmides bacteriens (petits genes, bacteries). 2) Virus modifies (desactives, pour cellules humaines). 3) Chromosomes artificiels (grands fragments). Le vecteur doit posseder : une origine de replication, un gene de selection (resistance antibiotique), un site de clonage (pour inserer le gene). C\'est le "vehicule de livraison" du genie genetique.' },
                    { question: 'Qu\'est-ce qu\'une mutation chromosomique ?', answer: 'Contrairement aux mutations ponctuelles (1 nucleotide), les mutations chromosomiques affectent de GRANDES portions de chromosomes. Types : deletion (perte d\'un segment), duplication (segment copie en double), inversion (segment retourne), translocation (segment deplace sur un autre chromosome). Exemple : la translocation 9-22 cree le "chromosome Philadelphie" implique dans la leucemie myeloide chronique.' },
                    { question: 'Qu\'est-ce que l\'heredite liee au sexe ?', answer: 'L\'heredite liee au sexe concerne les genes portes par les chromosomes sexuels, surtout le X. Les hommes (XY) n\'ont qu\'un seul X : un allele recessif sur le X s\'exprime TOUJOURS chez eux. Les femmes (XX) doivent avoir les 2 X porteurs de l\'allele recessif pour etre atteintes. Exemples : daltonisme, hemophilie, myopathie de Duchenne. 💡 ASTUCE MEMO : Les maladies liees au X touchent surtout les GARCONS car ils n\'ont pas de "X de secours" pour compenser !' },
                    { question: 'Qu\'est-ce que la mucoviscidose ?', answer: 'La mucoviscidose est la maladie genetique RECESSIVE autosomique la plus frequente en France (1/4500 naissances). Elle est causee par une mutation du gene CFTR (chromosome 7) qui code un canal chlorure. Le mucus des voies respiratoires et digestives devient anormalement epais, causant infections pulmonaires et problemes digestifs. La mutation la plus frequente est la deletion F508del (perte d\'un acide amine). Les porteurs sains (heterozygotes) sont 1/30 en France.' },
                    { question: 'Qu\'est-ce qu\'un arbre genealogique en genetique ?', answer: 'Un arbre genealogique (pedigree) est un schema representant la transmission d\'un caractere au sein d\'une famille sur plusieurs generations. Conventions : carres = hommes, ronds = femmes, colores = atteints, non colores = sains. L\'analyse permet de determiner : 1) Si le caractere est dominant ou recessif. 2) S\'il est autosomal ou lie au sexe. 💡 ASTUCE MEMO : Si deux parents sains ont un enfant atteint → maladie RECESSIVE. Si un parent atteint a un enfant sain → dominant. Filles saines + garcons atteints → lie au X recessif.' },
                    { question: 'Qu\'est-ce que la codominance ?', answer: 'La codominance est un cas ou les deux alleles d\'un gene s\'expriment simultanement chez l\'heterozygote, sans que l\'un domine l\'autre. Exemple classique : les groupes sanguins AB. L\'allele IA code l\'antigene A, l\'allele IB code l\'antigene B. L\'heterozygote IA/IB exprime les DEUX antigenes A et B = groupe AB. Ce n\'est ni dominance ni recessivite, c\'est l\'expression des deux alleles a la fois.' },
                    { question: 'Qu\'est-ce que le genome humain et combien de genes contient-il ?', answer: 'Le genome humain est l\'ensemble de l\'ADN contenu dans nos cellules. Il comprend environ 3,2 milliards de paires de bases reparties sur 23 paires de chromosomes. Surprise : il ne contient que ~20 000 genes codants (seulement 1,5% du genome total !). Le reste etait autrefois appele "ADN poubelle" mais on sait maintenant qu\'il a des roles regulateurs importants. 🤯 Le savais-tu ? Le genome humain a ete integralement sequence en 2003 apres 13 ans de travail et 3 milliards de dollars. Aujourd\'hui, ca prend quelques heures !' },
                    { question: 'Qu\'est-ce qu\'un test genetique et ses enjeux ?', answer: 'Un test genetique analyse l\'ADN d\'un individu pour detecter des mutations associees a des maladies. Types : diagnostic (confirmer une maladie), presymptomatique (risque futur, ex : Huntington), prenatal (trisomie 21). Enjeux ethiques : droit de savoir vs droit de ne pas savoir, discrimination genetique, confidentialite des donnees, anxiete liee au resultat. En France, les tests genetiques sont encadres par la loi et necessitent un consentement eclaire + accompagnement medical.' },
                    { question: 'Qu\'est-ce que la PCR quantitative (qPCR) ?', answer: 'La qPCR (ou PCR en temps reel) est une variante de la PCR classique qui permet de QUANTIFIER la quantite d\'ADN amplifie en temps reel grace a des marqueurs fluorescents. Plus il y a d\'ADN cible au depart, plus la fluorescence apparait tot. Applications : mesurer la charge virale du VIH, quantifier l\'expression d\'un gene, detecter le COVID-19 (RT-qPCR = transcription inverse + qPCR car le SARS-CoV-2 est un virus a ARN).' },
                    { question: 'Expliquer le lien entre ADN, gene, chromosome et genome.', answer: 'L\'ADN est la molecule porteuse de l\'information genetique. Un GENE est un segment d\'ADN qui code une proteine (ou un ARN fonctionnel). Les genes sont organises sur des CHROMOSOMES (= ADN + histones). L\'ensemble des chromosomes d\'un organisme constitue son GENOME. Chez l\'humain : 3,2 milliards de pb d\'ADN, ~20 000 genes, 46 chromosomes = 1 genome. 💡 ASTUCE MEMO : ADN = la phrase. Gene = un mot. Chromosome = un chapitre. Genome = le livre entier.' },
                    { question: 'Qu\'est-ce que la therapie genique par CRISPR pour la drepanocytose ?', answer: 'Depuis 2023, un traitement par CRISPR (Casgevy) est autorise contre la drepanocytose. Principe : on preleve les cellules souches hematopoietiques du patient, on utilise CRISPR pour reactiver le gene de l\'hemoglobine foetale (HbF, normalement eteint apres la naissance), puis on reinjecte les cellules modifiees. L\'HbF fonctionnelle compense l\'hemoglobine S defectueuse. C\'est le PREMIER traitement par CRISPR approuve chez l\'humain. 🤯 Le savais-tu ? Ce traitement coute environ 2 millions d\'euros par patient mais c\'est une guerison potentiellement definitive !' },
                    { question: 'Qu\'est-ce que le polymorphisme genetique ?', answer: 'Le polymorphisme genetique designe l\'existence de PLUSIEURS alleles pour un meme gene dans une population (quand l\'allele le plus frequent est present chez moins de 99% des individus). Exemples : groupes sanguins ABO (3 alleles), couleur des yeux (multiples genes). Le polymorphisme est la base de la biodiversite genetique et la matiere premiere de l\'evolution. Plus une population est polymorphe, plus elle a de chances de s\'adapter aux changements environnementaux.' },
                    { question: 'Qu\'est-ce que l\'empreinte genetique (profil ADN) ?', answer: 'L\'empreinte genetique est une technique d\'identification basee sur l\'analyse des sequences repetees (STR/microsatellites) de l\'ADN, qui varient d\'un individu a l\'autre. On amplifie par PCR une dizaine de marqueurs STR et on compare les profils. Applications : enquetes criminelles (identification de suspects), tests de paternite, identification de victimes. Chaque individu (sauf jumeaux identiques) a un profil ADN UNIQUE. La probabilite de trouver deux profils identiques par hasard est de ~1 sur un milliard.' },
                    { question: 'Qu\'est-ce que les ARN non codants et leur importance ?', answer: 'La majorite de notre genome ne code PAS de proteines, mais produit des ARN non codants aux roles regulateurs essentiels. Types : ARN ribosomique (ARNr, composant des ribosomes), ARN de transfert (ARNt), microARN (miARN, regulateurs de l\'expression genetique — ils bloquent la traduction d\'ARNm specifiques), long ARN non codant (lncARN). 🤯 Le savais-tu ? On pensait que l\'ADN non codant etait "poubelle" — on sait maintenant qu\'il represente >98% du genome et joue des roles cruciaux dans la regulation des genes !' },
                    { question: 'Qu\'est-ce que la pharmacogenomique ?', answer: 'La pharmacogenomique etudie comment les variations genetiques d\'un individu influencent sa reponse aux medicaments. Certains alleles modifient l\'efficacite ou la toxicite d\'un medicament (metaboliseurs rapides vs lents du cytochrome P450). But : adapter le traitement au profil genetique du patient = medecine PERSONNALISEE. Exemple : le gene DPYD — certains alleles rendent le 5-fluorouracile (chimio) potentiellement mortel chez 3-5% des patients.' },
                    { question: 'Qu\'est-ce que la bioinformatique et son role en genetique ?', answer: 'La bioinformatique utilise l\'informatique et les statistiques pour analyser les donnees biologiques massives, notamment les sequences d\'ADN. Applications : assemblage de genomes sequences, comparaison de sequences entre especes (phylogenie), identification de genes impliques dans des maladies (GWAS), prediction de la structure des proteines (AlphaFold). Sans la bioinformatique, il serait impossible de traiter les milliards de donnees generees par le sequencage moderne.' },
                    { question: 'Qu\'est-ce que le clonage positionnel et comment identifie-t-on un gene de maladie ?', answer: 'Le clonage positionnel est une strategie pour identifier le gene responsable d\'une maladie SANS connaitre la proteine impliquee. Etapes : 1) Etude de familles atteintes pour localiser le gene sur un chromosome (liaison genetique/marqueurs). 2) Sequencage de la region candidate. 3) Identification de la mutation. C\'est ainsi qu\'ont ete decouverts les genes de la mucoviscidose (CFTR, 1989), de la myopathie de Duchenne (dystrophine) et du cancer du sein (BRCA1, 1994). 💡 ASTUCE MEMO : C\'est comme chercher une faute d\'orthographe dans un livre de 3 milliards de lettres — il faut d\'abord trouver le bon chapitre !' }
                ],
                quiz: [
                    { question: 'Les bases complementaires de l\'ADN sont :', options: ['A-C et T-G', 'A-T et C-G', 'A-G et T-C', 'A-U et C-G'], correctIndex: 1, explanation: 'Dans l\'ADN, l\'adenine (A) s\'apparie avec la thymine (T) par 2 liaisons hydrogene, et la cytosine (C) avec la guanine (G) par 3 liaisons hydrogene. Moyen mnemotechnique : A Table Charlie et Georges !' },
                    { question: 'Un codon est compose de :', options: ['2 nucleotides', '3 nucleotides', '4 nucleotides', '1 nucleotide'], correctIndex: 1, explanation: 'Un codon est un triplet de 3 nucleotides consecutifs sur l\'ARNm. Avec 4 bases possibles, on obtient 4³ = 64 codons possibles pour coder 20 acides amines + 3 stop.' },
                    { question: 'Le codon initiateur de la traduction est :', options: ['UAA', 'AUG', 'UAG', 'UGA'], correctIndex: 1, explanation: 'AUG est le codon initiateur, codant la methionine. C\'est le premier codon traduit. UAA, UAG et UGA sont les codons stop. ASTUCE : les 3 stops contiennent tous U et A.' },
                    { question: 'La transcription se deroule dans :', options: ['Le cytoplasme', 'Le noyau', 'Les ribosomes', 'Les mitochondries uniquement'], correctIndex: 1, explanation: 'La transcription de l\'ADN en ARNm a lieu dans le noyau par l\'ARN polymerase. L\'ARNm migre ensuite dans le cytoplasme pour la traduction par les ribosomes.' },
                    { question: 'Une mutation faux-sens :', options: ['Introduit un codon stop premature', 'Remplace un acide amine par un autre', 'Ne modifie pas la proteine', 'Supprime un nucleotide'], correctIndex: 1, explanation: 'Une mutation faux-sens est une substitution qui modifie le codon et remplace un acide amine par un autre. Elle peut alterer la fonction de la proteine.' },
                    { question: 'La replication de l\'ADN est dite semi-conservative car :', options: ['Seule la moitie de l\'ADN est copiee', 'Chaque nouvelle molecule contient un brin ancien et un brin neuf', 'Les deux brins sont entierement nouveaux', 'Un seul brin est conserve dans la cellule'], correctIndex: 1, explanation: 'Chaque molecule fille contient un brin matrice de la molecule mere (conserve) et un brin nouvellement synthetise. Experience de Meselson et Stahl (1958).' },
                    { question: 'Le code genetique est dit degenere car :', options: ['Il se degrade avec le temps', 'Plusieurs codons codent pour un meme acide amine', 'Il est different selon les especes', 'Chaque codon code plusieurs acides amines'], correctIndex: 1, explanation: 'Il y a 64 codons pour seulement 20 acides amines : certains acides amines sont codes par 2, 3, 4 ou meme 6 codons differents. Cela protege contre certaines mutations (silencieuses).' },
                    { question: 'L\'ARN de transfert (ARNt) a pour role de :', options: ['Copier l\'ADN en ARNm', 'Transporter les acides amines vers le ribosome', 'Degrader les proteines defectueuses', 'Reparer les mutations de l\'ADN'], correctIndex: 1, explanation: 'L\'ARNt porte un anticodon (complementaire du codon) et l\'acide amine correspondant. Il sert de traducteur entre le langage des nucleotides et celui des acides amines.' },
                    { question: 'CRISPR-Cas9 est :', options: ['Un type de mutation naturelle', 'Un outil de modification ciblee de l\'ADN', 'Un enzyme de la replication', 'Un type d\'ARN messager'], correctIndex: 1, explanation: 'CRISPR-Cas9 est un systeme de "ciseaux moleculaires" decouvert en 2012. Un ARN guide dirige la proteine Cas9 vers une cible precise dans l\'ADN pour la couper et la modifier.' },
                    { question: 'L\'epissage de l\'ARN pre-messager consiste a :', options: ['Ajouter une coiffe 5\'', 'Retirer les introns et reunir les exons', 'Ajouter la queue poly-A', 'Traduire l\'ARNm en proteine'], correctIndex: 1, explanation: 'L\'epissage retire les introns (sequences non codantes) et reunit les exons (sequences codantes) pour former l\'ARNm mature. L\'epissage alternatif permet de produire plusieurs proteines a partir d\'un seul gene.' },
                    { question: 'Un individu heterozygote possede :', options: ['Deux alleles identiques', 'Deux alleles differents pour un gene donne', 'Un seul allele', 'Aucun allele dominant'], correctIndex: 1, explanation: 'Un heterozygote porte deux alleles differents d\'un meme gene, un sur chaque chromosome homologue. En cas de dominance complete, seul l\'allele dominant s\'exprime.' },
                    { question: 'La PCR permet de :', options: ['Sequencer l\'ADN complet', 'Amplifier un fragment specifique d\'ADN', 'Traduire l\'ARNm en proteine', 'Modifier un gene par transgenese'], correctIndex: 1, explanation: 'La PCR (Polymerase Chain Reaction) amplifie en millions de copies un fragment d\'ADN cible grace a des cycles de temperature et une polymerase thermoresistante (Taq).' },
                    { question: 'Un gene de predisposition :', options: ['Provoque systematiquement la maladie', 'Augmente le risque sans certitude', 'Protege contre toutes les maladies', 'N\'a aucun lien avec le phenotype'], correctIndex: 1, explanation: 'Un gene de predisposition (ex : BRCA1 pour le cancer du sein) augmente la probabilite mais ne determine pas la maladie. L\'environnement et le mode de vie jouent aussi.' },
                    { question: 'Les agents mutagenes incluent :', options: ['L\'eau et le glucose', 'Les UV, les radiations et certaines substances chimiques', 'Uniquement les virus', 'Les proteines de l\'alimentation'], correctIndex: 1, explanation: 'Les agents mutagenes augmentent la frequence des mutations : UV (dimeres de thymine), rayons X, benzene, goudrons du tabac, amiante. Ils peuvent causer des cancers.' },
                    { question: 'Dans l\'ARNm, quelle base remplace la thymine de l\'ADN ?', options: ['L\'adenine', 'La cytosine', 'La guanine', 'L\'uracile'], correctIndex: 3, explanation: 'Dans l\'ARN (messager, transfert, ribosomique), la base uracile (U) remplace la thymine (T) de l\'ADN. Ainsi A de l\'ADN s\'apparie avec U dans l\'ARN.' },
                    { question: 'Le promoteur d\'un gene sert a :', options: ['Coder directement la proteine', 'Permettre la fixation de l\'ARN polymerase et initier la transcription', 'Transporter l\'ARNm vers le ribosome', 'Proteger l\'ADN des mutations'], correctIndex: 1, explanation: 'Le promoteur est une sequence en amont du gene ou se fixe l\'ARN polymerase pour demarrer la transcription. Sans promoteur, le gene reste silencieux.' },
                    { question: 'La drepanocytose est causee par :', options: ['Une deletion de gene', 'Une substitution d\'un nucleotide dans le gene de la beta-globine', 'Un chromosome surnumeraire', 'Un virus'], correctIndex: 1, explanation: 'La mutation GAG→GTG dans le gene de la beta-globine remplace l\'acide glutamique par la valine (mutation faux-sens). L\'hemoglobine S deforme les globules rouges en faucille.' },
                    { question: 'Les introns sont :', options: ['Des sequences codantes conservees dans l\'ARNm', 'Des sequences non codantes eliminees lors de l\'epissage', 'Des proteines du ribosome', 'Des acides amines'], correctIndex: 1, explanation: 'Les introns (INtervening sequences) sont des sequences non codantes du gene pre-ARNm, eliminees par epissage. Seuls les exons (EXprimes) sont traduits en proteine.' },
                    { question: 'Une maladie genetique recessive s\'exprime :', options: ['Des qu\'un seul allele est mute', 'Uniquement quand les deux alleles sont mutes (homozygote)', 'Quel que soit le genotype', 'Seulement chez les garcons'], correctIndex: 1, explanation: 'Une maladie recessive necessite deux copies de l\'allele mute (homozygote). L\'heterozygote est porteur sain : il porte l\'allele mais n\'est pas malade. Ex : mucoviscidose, drepanocytose.' },
                    { question: 'Les purines de l\'ADN sont :', options: ['Thymine et Cytosine', 'Adenine et Guanine', 'Adenine et Thymine', 'Uracile et Guanine'], correctIndex: 1, explanation: 'Les purines (A et G) ont 2 cycles aromatiques (plus grosses). Les pyrimidines (T et C) ont 1 seul cycle (plus petites). Un appariement purine-pyrimidine assure un diametre constant de l\'helice.' },
                    { question: 'Le daltonisme est une maladie liee au chromosome :', options: ['Y', 'X', 'Chromosome 21', 'Chromosome 1'], correctIndex: 1, explanation: 'Le daltonisme est lie au chromosome X (recessif). Les hommes (XY) sont plus souvent atteints car ils n\'ont qu\'un X : un seul allele mute suffit. Les femmes doivent etre homozygotes (XX mutes).' },
                    { question: 'Un plasmide est :', options: ['Un organite de la cellule animale', 'Un petit ADN circulaire bacterien utilise comme vecteur en genie genetique', 'Un type de proteine membranaire', 'Un chromosome humain'], correctIndex: 1, explanation: 'Les plasmides sont de petites molecules d\'ADN circulaires des bacteries. Ils se repliquent independamment et portent souvent des genes de resistance. En biotechnologie, on les utilise comme vecteurs pour transporter des genes d\'interet.' },
                    { question: 'Le nombre total de codons possibles est :', options: ['20', '4', '64', '128'], correctIndex: 2, explanation: 'Avec 4 bases possibles a chaque position et 3 positions par codon : 4³ = 64 codons. Parmi eux, 61 codent des acides amines et 3 sont des codons stop (UAA, UAG, UGA).' },
                    { question: 'L\'ADN polymerase synthetise le nouveau brin dans le sens :', options: ['3\' vers 5\'', '5\' vers 3\'', 'Dans les deux sens', 'Du centre vers les extremites'], correctIndex: 1, explanation: 'L\'ADN polymerase synthetise TOUJOURS le nouveau brin dans le sens 5\'→3\' en lisant le brin matrice dans le sens 3\'→5\'. C\'est une regle universelle.' },
                    { question: 'Les enzymes de restriction :', options: ['Synthetisent de l\'ADN', 'Coupent l\'ADN a des sequences specifiques', 'Traduisent l\'ARNm en proteines', 'Repliquent les chromosomes'], correctIndex: 1, explanation: 'Les enzymes de restriction sont des "ciseaux moleculaires" bacteriens qui coupent l\'ADN double brin a des sites de restriction specifiques. Outil fondamental du genie genetique.' }
                ]
            },

            // ===== SECTION 2 : DIVISION CELLULAIRE =====
            {
                id: 'division-cellulaire',
                title: 'Division cellulaire',
                icon: '\uD83D\uDD2C',
                content: '<h3>Cycle cellulaire</h3>'
                    + '<ul>'
                    + '<li><strong>Interphase</strong> : G1 (croissance), S (replication de l\'ADN), G2 (preparation a la division). L\'ADN est sous forme de chromatine</li>'
                    + '<li><strong>Phase M</strong> : mitose (division du noyau) suivie de la cytocinese (division du cytoplasme)</li>'
                    + '</ul>'
                    + '<h3>Mitose</h3>'
                    + '<ul>'
                    + '<li><strong>Prophase</strong> : condensation de la chromatine en chromosomes, disparition de l\'enveloppe nucleaire, formation du fuseau mitotique</li>'
                    + '<li><strong>Metaphase</strong> : chromosomes alignes sur la plaque equatoriale, chaque chromosome est attache aux fibres du fuseau par son centromere</li>'
                    + '<li><strong>Anaphase</strong> : separation des chromatides soeurs qui migrent vers les poles opposes</li>'
                    + '<li><strong>Telophase</strong> : decondensation des chromosomes, reformation de l\'enveloppe nucleaire, cytocinese</li>'
                    + '</ul>'
                    + '<h3>Meiose</h3>'
                    + '<ul>'
                    + '<li><strong>Meiose I (reductionnelle)</strong> : separation des chromosomes homologues. Crossing-over en prophase I. Brassage interchromosomique en metaphase I</li>'
                    + '<li><strong>Meiose II (equationnelle)</strong> : separation des chromatides soeurs (comme une mitose). Produit 4 cellules haploides</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Quelles sont les phases du cycle cellulaire ?', answer: 'Le cycle cellulaire comprend l\'interphase (G1 : croissance, S : replication de l\'ADN, G2 : preparation) et la phase M (mitose + cytocinese). L\'interphase represente environ 90% du cycle. En G1, la cellule grandit et fonctionne normalement. 💡 ASTUCE MEMO : G1-S-G2-M = "Grandir, Synthetiser, se preparer a Grandir encore, et Mitose !" ' },
                    { question: 'Qu\'est-ce qui se passe pendant la phase S ?', answer: 'La phase S (Synthese) est la phase de replication de l\'ADN. Chaque molecule d\'ADN est integralement copiee (replication semi-conservative). A la fin de S, chaque chromosome est forme de 2 chromatides soeurs identiques liees par le centromere. La quantite d\'ADN double : on passe de 2n a 2n mais avec 2 fois plus d\'ADN (de 2C a 4C en quantite d\'ADN).' },
                    { question: 'Decrire les etapes de la mitose.', answer: '1) Prophase : chromatine se condense en chromosomes, l\'enveloppe nucleaire disparait, le fuseau mitotique se forme. 2) Metaphase : les chromosomes s\'alignent sur la plaque equatoriale. 3) Anaphase : les chromatides soeurs se separent et migrent vers les poles. 4) Telophase : les chromosomes se decondensent, l\'enveloppe nucleaire se reforme, la cytocinese divise le cytoplasme. 🧠 TRUC POUR RETENIR : PMAT — "Pour Mieux Apprendre Tout !" (Prophase, Metaphase, Anaphase, Telophase).' },
                    { question: 'Quelle est la difference entre mitose et meiose ?', answer: 'Mitose : 1 division, 2 cellules filles diploides (2n) identiques, but = croissance et reparation. Meiose : 2 divisions, 4 cellules filles haploides (n) differentes, but = formation des gametes. 🧠 TRUC POUR RETENIR : Mitose = division a l\'Identique (MI = Meme Information). Meiose = division qui Melange (ME = Melange). La mitose conserve, la meiose diversifie !' },
                    { question: 'Qu\'est-ce que le brassage interchromosomique ?', answer: 'Lors de la metaphase I de meiose, les paires de chromosomes homologues se repartissent ALEATOIREMENT de part et d\'autre du plan equatorial. Pour n paires de chromosomes, il y a 2^n combinaisons possibles. Chez l\'humain (n=23), cela donne environ 8 millions de combinaisons de gametes. 🤯 Le savais-tu ? C\'est pour ca qu\'aucun de tes freres et soeurs (sauf vrais jumeaux) ne te ressemble parfaitement !' },
                    { question: 'Qu\'est-ce qu\'un crossing-over ?', answer: 'Un crossing-over est un echange de segments de chromatides entre chromosomes homologues lors de la prophase I de meiose (quand les homologues sont apparies en bivalents). Il produit des chromatides recombinees portant de nouvelles combinaisons d\'alleles = brassage INTRAchromosomique. 💡 ASTUCE MEMO : crossing-over = CROISEMENT de segments — comme echanger des pieces de puzzle entre deux puzzles similaires.' },
                    { question: 'Pourquoi la meiose I est-elle dite reductionnelle ?', answer: 'La meiose I est dite reductionnelle car elle REDUIT de moitie le nombre de chromosomes : on passe de 2n (diploide) a n (haploide). C\'est la separation des chromosomes HOMOLOGUES (et non des chromatides soeurs). Chaque cellule fille recoit un seul chromosome de chaque paire. La meiose II, elle, est equationnelle (separe les chromatides comme une mitose).' },
                    { question: 'Qu\'est-ce que la fecondation et son role genetique ?', answer: 'La fecondation est la fusion de deux gametes haploides (n) — un spermatozoide et un ovule — pour former un zygote diploide (2n). Elle retablit la diploidie et constitue un TROISIEME niveau de brassage genetique : la rencontre aleatoire des gametes. Avec les brassages inter et intrachromosomiques, la fecondation cree une combinaison genetique unique. Chaque etre humain est une experience genetique inedite !' },
                    { question: 'Qu\'est-ce que la trisomie 21 ?', answer: 'La trisomie 21 (syndrome de Down) resulte de la presence de TROIS chromosomes 21 au lieu de deux (47 chromosomes au total). Elle est causee par une non-disjonction des chromosomes 21 lors de la meiose (le plus souvent chez la mere). Le risque augmente avec l\'age maternel. 💡 ASTUCE MEMO : TRIsomie = TROIS exemplaires d\'un chromosome au lieu de deux. MONosomie = un seul exemplaire.' },
                    { question: 'Qu\'est-ce que la non-disjonction chromosomique ?', answer: 'La non-disjonction est une erreur de la meiose ou les chromosomes homologues (en meiose I) ou les chromatides soeurs (en meiose II) ne se separent pas correctement. Un gamete recoit un chromosome en trop, l\'autre un en moins. A la fecondation, cela donne une trisomie (2n+1) ou une monosomie (2n-1). C\'est la cause des anomalies chromosomiques de nombre.' },
                    { question: 'Quel est le role du fuseau mitotique ?', answer: 'Le fuseau mitotique est constitue de microtubules (proteines tubulines) qui s\'attachent aux chromosomes par les centromeress/kinetochores. Il permet l\'alignement des chromosomes en metaphase et la separation des chromatides soeurs en anaphase en les "tirant" vers les poles opposes de la cellule. Sans fuseau fonctionnel, la division est impossible.' },
                    { question: 'Comment le cancer est-il lie au cycle cellulaire ?', answer: 'Le cancer resulte d\'un dereglement du cycle cellulaire : les cellules se divisent de facon incontrolee. Des genes normaux (proto-oncogenes et genes suppresseurs de tumeurs) controlent le cycle. Leur mutation conduit au cancer. Proto-oncogene mute = oncogene (accelere la division). Gene suppresseur (ex : p53) mute = perte de frein. Il faut PLUSIEURS mutations accumulees. ⚠️ PIEGE BAC : Le cancer n\'est pas cause par UNE seule mutation mais par une ACCUMULATION de mutations.' },
                    { question: 'Qu\'est-ce que l\'apoptose ?', answer: 'L\'apoptose est la mort cellulaire programmee — un "suicide" ordonne de la cellule. C\'est un processus normal et essentiel : elimination des cellules endommagees, sculpture des organes (disparition des membranes entre les doigts chez l\'embryon), renouvellement des cellules immunitaires. Un defaut d\'apoptose peut contribuer au cancer (les cellules anormales ne sont pas eliminees).' },
                    { question: 'Qu\'est-ce que p53, le "gardien du genome" ?', answer: 'p53 est une proteine codee par un gene suppresseur de tumeur. Elle est activee quand l\'ADN est endommage. Elle peut : 1) Arreter le cycle cellulaire pour permettre la reparation. 2) Declencher l\'apoptose si les dommages sont trop importants. p53 est mutee dans environ 50% des cancers humains. 🤯 Le savais-tu ? Les elephants ont 20 copies du gene p53, ce qui explique en partie pourquoi ils developpent rarement des cancers malgre leur grande taille !' },
                    { question: 'Comparer les brassages genetiques : interchromosomique vs intrachromosomique.', answer: 'Brassage INTERchromosomique : repartition aleatoire des chromosomes homologues entre les cellules filles en metaphase I. Cree 2^n combinaisons. Brassage INTRAchromosomique : crossing-over en prophase I, echange de segments entre chromatides homologues. Cree des combinaisons NOUVELLES d\'alleles sur un meme chromosome. 💡 ASTUCE MEMO : INTER = ENTRE les chromosomes (ils changent de cellule). INTRA = A L\'INTERIEUR des chromosomes (ils echangent des morceaux).' },
                    { question: 'Qu\'est-ce qu\'un bivalent (ou tetrade) ?', answer: 'Un bivalent est l\'association de deux chromosomes homologues apparies lors de la prophase I de meiose. Comme chaque chromosome est constitue de 2 chromatides soeurs (apres la phase S), le bivalent comporte 4 chromatides au total = tetrade. C\'est dans cette configuration que les crossing-over peuvent se produire entre chromatides non soeurs.' },
                    { question: 'Pourquoi la meiose est-elle indispensable a la reproduction sexuee ?', answer: 'Sans meiose, les gametes seraient diploides (2n). A chaque fecondation, le nombre de chromosomes doublerait (4n, 8n, 16n...). La meiose reduit le nombre de chromosomes de moitie (2n → n), ce qui garantit que la fecondation retablit le nombre normal (n + n = 2n). De plus, les brassages genetiques de la meiose assurent la diversite genetique indispensable a l\'adaptation des especes.' },
                    { question: 'Qu\'est-ce qu\'une cellule souche ?', answer: 'Une cellule souche est une cellule indifferenciee capable de : 1) Se diviser par mitose pour produire d\'autres cellules souches (auto-renouvellement). 2) Se differencier en cellules specialisees (neurone, globule rouge, cellule musculaire...). Types : cellules souches TOTIPOTENTES (zygote, peuvent tout donner), PLURIPOTENTES (embryon, presque tout), MULTIPOTENTES (adulte, lignees limitees). 🤯 Le savais-tu ? Les cellules iPS (prix Nobel 2012, Yamanaka) sont des cellules adultes reprogrammees en cellules souches — revolution medicale !' },
                    { question: 'Qu\'est-ce que la G0 dans le cycle cellulaire ?', answer: 'La phase G0 est un etat de "quiescence" : la cellule sort du cycle cellulaire et ne se divise plus. Beaucoup de cellules adultes sont en G0 (neurones, cellules musculaires). Certaines peuvent reintegrer le cycle si stimulees (hepatocytes apres une lesion du foie). Le passage de G1 a S est controle par le point de restriction : un "point de non-retour" apres lequel la cellule s\'engage irreversiblement dans la division.' },
                    { question: 'Qu\'est-ce que le centromere et le kinetochore ?', answer: 'Le CENTROMERE est la region de constriction du chromosome qui relie les deux chromatides soeurs. Le KINETOCHORE est un complexe proteique situe au niveau du centromere, sur lequel s\'attachent les microtubules du fuseau mitotique. C\'est grace au kinetochore que les chromosomes sont "tires" vers les poles lors de l\'anaphase. 💡 ASTUCE MEMO : Le centromere est le "milieu" du chromosome (centro = centre), le kinetochore est le "crochet" pour le fuseau (kineto = mouvement).' },
                    { question: 'Qu\'est-ce que la polyploidie ?', answer: 'La polyploidie est la presence de plus de 2 jeux complets de chromosomes dans une cellule (3n = triploide, 4n = tetraploide, etc.). Elle resulte souvent d\'une erreur de meiose ou de mitose (non-disjonction complete). Tres frequente chez les PLANTES (ble = hexaploide 6n !) et souvent a l\'origine de speciation rapide (speciation sympatrique). Chez les animaux, la polyploidie est generalement letale. 🤯 Le savais-tu ? Le ble que tu manges tous les jours a 42 chromosomes (6n = 6 × 7) — il est hexaploide !' },
                    { question: 'Comparer la mitose et la meiose en un tableau mental.', answer: 'MITOSE : 1 division, 2 cellules filles, diploides (2n), genetiquement IDENTIQUES, dans les cellules somatiques, pour la croissance/reparation. MEIOSE : 2 divisions, 4 cellules filles, haploides (n), genetiquement DIFFERENTES (brassages), dans les cellules germinales, pour la formation des gametes. ⚠️ PIEGE BAC : La meiose ne se produit QUE dans les cellules germinales (ovaires, testicules), JAMAIS dans les cellules somatiques !' },
                    { question: 'Qu\'est-ce que le syndrome de Turner ?', answer: 'Le syndrome de Turner est une monosomie : la personne ne possede qu\'un seul chromosome X (caryotype 45,X au lieu de 46,XX). C\'est la seule monosomie viable chez l\'humain. Consequences : femme de petite taille, ovaires non fonctionnels (infertilite), parfois anomalies cardiaques. Cause : non-disjonction des chromosomes sexuels lors de la meiose d\'un des parents.' },
                    { question: 'Comment les cellules cancereuses echappent-elles au controle du cycle cellulaire ?', answer: 'Les cellules cancereuses accumulent des mutations dans les genes de controle du cycle : 1) Activation d\'ONCOGENES (accelerateurs bloques = division permanente). 2) Inactivation de GENES SUPPRESSEURS (freins casses, ex : p53, Rb). 3) Activation de la TELOMERASE (evite le raccourcissement des telomeres = immortalite cellulaire). 4) Echappement a l\'APOPTOSE. 5) ANGIOGENESE (creation de vaisseaux pour nourrir la tumeur). Il faut en general 5-10 mutations accumulees pour qu\'un cancer se declare.' },
                    { question: 'Qu\'est-ce que les telomeres et leur role dans le vieillissement ?', answer: 'Les telomeres sont des sequences repetitives (TTAGGG chez l\'humain) aux EXTREMITES des chromosomes. A chaque division cellulaire, les telomeres raccourcissent (l\'ADN polymerase ne peut pas copier l\'extremite). Quand ils deviennent trop courts → la cellule entre en senescence (arrete de se diviser) ou meurt par apoptose. C\'est une horloge biologique du vieillissement. 🤯 Le savais-tu ? Les cellules cancereuses reactivent la telomerase pour rallonger leurs telomeres — elles deviennent ainsi "immortelles" !' },
                    { question: 'Qu\'est-ce que la differenciation cellulaire ?', answer: 'La differenciation cellulaire est le processus par lequel une cellule souche se specialise pour devenir un type cellulaire precis (neurone, globule rouge, cellule musculaire...). Toutes les cellules ont le MEME ADN, mais chacune n\'exprime qu\'une partie de ses genes (regulation epigenetique). La differenciation est generalement irreversible chez les cellules adultes (sauf reprogrammation en cellules iPS). 💡 ASTUCE MEMO : Meme ADN, programme different — comme des musiciens avec la meme partition mais qui jouent chacun un instrument different.' },
                    { question: 'Qu\'est-ce que les coheseines et leur role ?', answer: 'Les coheseines sont des proteines en forme d\'anneau qui maintiennent les chromatides soeurs liees ensemble apres la replication (phase S) et jusqu\'a leur separation. En MITOSE et MEIOSE II, les coheseines du centromere sont clivees par la separase en ANAPHASE, permettant la separation des chromatides soeurs. En MEIOSE I, seules les coheseines des bras sont clivees (les centromeres restent lies), permettant la separation des chromosomes homologues mais PAS des chromatides soeurs.' },
                    { question: 'Qu\'est-ce que l\'aneuploïdie ?', answer: 'L\'aneuploïdie est une anomalie du nombre de chromosomes ou l\'individu n\'a PAS un multiple exact de n. Exemples : monosomie (2n-1 = 45 chromosomes, ex : Turner 45,X), trisomie (2n+1 = 47 chromosomes, ex : trisomie 21). Elle resulte de non-disjonctions lors de la meiose. La plupart des aneuploidies sont letales — seules quelques-unes sont viables chez l\'humain. ⚠️ PIEGE BAC : Aneuploïdie ≠ polyploidie ! L\'aneuploïdie = un ou quelques chromosomes en trop ou en moins. La polyploidie = un JEU COMPLET en trop (3n, 4n...).' },
                    { question: 'Qu\'est-ce que la chimiotherapie et comment agit-elle ?', answer: 'La chimiotherapie utilise des molecules chimiques qui ciblent les cellules en division rapide. Mecanismes : bloquer la replication de l\'ADN, empecher la formation du fuseau mitotique (taxol, vincristine), ou declencher l\'apoptose. Probleme : les cellules NORMALES a division rapide sont aussi touchees (cheveux → alopecie, muqueuses → nausees, moelle osseuse → immunodepression). C\'est pourquoi la chimiotherapie a des effets secondaires importants — elle ne distingue pas les cellules cancereuses des cellules normales en division.' },
                    { question: 'Qu\'est-ce que la prophase I de meiose et pourquoi est-elle si longue ?', answer: 'La prophase I est la phase la plus LONGUE et la plus COMPLEXE de la meiose. Elle comprend : 1) LEPTOTENE : les chromosomes se condensent. 2) ZYGOTENE : appariement des homologues (synapsis). 3) PACHYTENE : crossing-over entre chromatides non soeurs. 4) DIPLOTENE : les homologues se separent sauf aux chiasmas (points de crossing-over). 5) DIACINESE : condensation maximale. La prophase I peut durer des JOURS (voire des ANNEES chez l\'ovocyte humain — bloque en prophase I de la vie foetale a l\'ovulation !).' },
                    { question: 'Qu\'est-ce que le clonage et ses types ?', answer: 'Le clonage est la creation d\'un organisme genetiquement identique a un autre. Clonage REPRODUCTIF : creation d\'un individu entier (Dolly la brebis, 1996 — transfert de noyau d\'une cellule somatique dans un ovocyte enuclée). Clonage THERAPEUTIQUE : creation de cellules souches embryonnaires pour la medecine regenerative (pas d\'individu complet). La multiplication vegetative chez les plantes (boutures, stolons) est une forme naturelle de clonage. Le clonage reproductif humain est interdit partout dans le monde.' },
                    { question: 'Qu\'est-ce que la quantite d\'ADN (C) au cours du cycle cellulaire ?', answer: 'La quantite d\'ADN varie au cours du cycle : En G1 : 2C (quantite normale). Pendant la phase S : 2C → 4C (replication en cours). En G2 et debut de mitose : 4C (ADN replique, chaque chromosome = 2 chromatides). Apres mitose : retour a 2C dans chaque cellule fille. En fin de meiose I : 2C → 1C (nombre reduit). En fin de meiose II : C (gamete haploide). 💡 ASTUCE MEMO : Le graphe de quantite d\'ADN forme un "escalier" en S puis une "chute" a la division. C\'est un CLASSIQUE au Bac !' },
                    { question: 'Qu\'est-ce que le fuseau achromatique et la tubuline ?', answer: 'Le fuseau achromatique (mitotique) est la structure formee de microtubules de TUBULINE qui organise la separation des chromosomes. Il se forme a partir des centrosomes (ou centrioles chez les animaux) qui migrent aux poles de la cellule. Les microtubules s\'attachent aux kinetochores des chromosomes. En metaphase, ils alignent les chromosomes. En anaphase, leur depolymerisation et des proteines motrices tirent les chromatides vers les poles.' },
                    { question: 'Qu\'est-ce que le caryotype spectral (SKY) ?', answer: 'Le caryotype spectral (SKY = Spectral Karyotyping) est une technique de cytogenetique qui colore chaque chromosome d\'une couleur differente grace a des sondes fluorescentes specifiques. Cela permet de visualiser l\'ensemble des chromosomes simultanement et de detecter facilement les anomalies : translocations (echange de segments entre chromosomes), deletions, inversions. C\'est un outil puissant pour diagnostiquer les cancers et les maladies genetiques.' },
                    { question: 'Qu\'est-ce que la metastase ?', answer: 'La metastase est la dissemination de cellules cancereuses depuis la tumeur primaire vers d\'autres organes, via le sang ou la lymphe. C\'est l\'etape la plus dangereuse du cancer — la majorite des deces par cancer sont dus aux metastases et non a la tumeur d\'origine. Les cellules metastatiques doivent : se detacher de la tumeur, penetrer un vaisseau, survivre dans le sang, sortir du vaisseau et coloniser un nouvel organe. Seule une infime fraction y parvient, mais c\'est suffisant. 🤯 Le savais-tu ? Un gramme de tumeur peut liberer des millions de cellules dans le sang chaque jour, mais moins de 0,01% formeront une metastase — c\'est un processus tres inefficace mais devastateur.' }
                ],
                quiz: [
                    { question: 'La meiose produit :', options: ['2 cellules diploides', '4 cellules diploides', '2 cellules haploides', '4 cellules haploides'], correctIndex: 3, explanation: 'La meiose comporte deux divisions successives (reductionnelle puis equationnelle) et produit 4 cellules haploides (gametes) a partir d\'une cellule diploide.' },
                    { question: 'Le brassage intrachromosomique se produit lors de :', options: ['La metaphase II', 'La prophase I', 'L\'anaphase II', 'La telophase I'], correctIndex: 1, explanation: 'Les crossing-over (echanges de segments entre chromatides homologues) se produisent en prophase I, quand les chromosomes homologues sont apparies (bivalents).' },
                    { question: 'Chez l\'humain (2n=46), le nombre de combinaisons par brassage interchromosomique est :', options: ['23', '46', '2^23 (environ 8 millions)', '2^46'], correctIndex: 2, explanation: 'Avec n=23 paires de chromosomes, la repartition aleatoire des homologues en metaphase I donne 2^23 = 8 388 608 combinaisons possibles pour les gametes.' },
                    { question: 'Les phases de la mitose dans l\'ordre sont :', options: ['Metaphase, Prophase, Telophase, Anaphase', 'Prophase, Metaphase, Anaphase, Telophase', 'Anaphase, Prophase, Telophase, Metaphase', 'Telophase, Anaphase, Metaphase, Prophase'], correctIndex: 1, explanation: 'PMAT : Prophase (condensation), Metaphase (alignement), Anaphase (separation), Telophase (decondensation). Moyen mnemotechnique : "Pour Mieux Apprendre Tout".' },
                    { question: 'La phase S du cycle cellulaire correspond a :', options: ['La separation des chromatides', 'La synthese (replication) de l\'ADN', 'La formation du fuseau mitotique', 'La cytocinese'], correctIndex: 1, explanation: 'S = Synthese de l\'ADN. C\'est pendant cette phase que l\'ADN est integralement replique. Chaque chromosome passe de 1 chromatide a 2 chromatides soeurs.' },
                    { question: 'La trisomie 21 est causee par :', options: ['Une mutation ponctuelle', 'Une non-disjonction du chromosome 21 lors de la meiose', 'Un crossing-over anormal', 'Une deletion chromosomique'], correctIndex: 1, explanation: 'La trisomie 21 resulte d\'une non-disjonction : les deux chromosomes 21 ne se separent pas lors de la meiose. Un gamete recoit 2 chromosomes 21, donnant 3 exemplaires apres fecondation.' },
                    { question: 'Le gene p53 est un :', options: ['Oncogene', 'Gene suppresseur de tumeur', 'Gene de structure des ribosomes', 'Gene codant l\'ADN polymerase'], correctIndex: 1, explanation: 'p53 est le "gardien du genome" : il arrete le cycle cellulaire en cas de dommages a l\'ADN ou declenche l\'apoptose. Sa mutation est trouvee dans ~50% des cancers.' },
                    { question: 'L\'apoptose est :', options: ['La division cellulaire incontrolee', 'La mort cellulaire programmee', 'La fusion de deux cellules', 'La migration des chromosomes'], correctIndex: 1, explanation: 'L\'apoptose est un suicide cellulaire ordonne, essentiel pour eliminer les cellules endommagees, inutiles ou potentiellement cancereuses. C\'est un processus normal et benefique.' },
                    { question: 'La meiose I est dite reductionnelle car :', options: ['Elle reduit la taille des chromosomes', 'Elle divise par deux le nombre de chromosomes', 'Elle reduit le nombre de mutations', 'Elle elimine les chromosomes defectueux'], correctIndex: 1, explanation: 'La meiose I separe les chromosomes homologues, faisant passer la cellule de l\'etat diploide (2n) a l\'etat haploide (n). D\'ou le terme reductionnel.' },
                    { question: 'Le crossing-over augmente la diversite genetique en :', options: ['Ajoutant de nouveaux genes', 'Creant de nouvelles combinaisons d\'alleles sur un chromosome', 'Augmentant le nombre de chromosomes', 'Provoquant des mutations'], correctIndex: 1, explanation: 'Le crossing-over echange des segments entre chromatides homologues, creant des chromosomes recombines portant des associations d\'alleles nouvelles. C\'est le brassage intrachromosomique.' },
                    { question: 'Un proto-oncogene mute devient un oncogene qui :', options: ['Repare l\'ADN endommage', 'Stimule excessivement la division cellulaire', 'Bloque la meiose', 'Provoque l\'apoptose'], correctIndex: 1, explanation: 'Un proto-oncogene normal controle la croissance cellulaire. Sa mutation en oncogene est comme un accelerateur bloque : la cellule se divise sans controle, contribuant au cancer.' },
                    { question: 'La cytocinese correspond a :', options: ['La replication de l\'ADN', 'La division du cytoplasme en deux cellules filles', 'L\'alignement des chromosomes', 'La condensation de la chromatine'], correctIndex: 1, explanation: 'La cytocinese est la derniere etape de la division cellulaire : le cytoplasme se divise pour former deux cellules filles distinctes. Chez les animaux, un anneau contractile de filaments d\'actine etrangle la cellule.' },
                    { question: 'Un bivalent est :', options: ['Un chromosome a deux chromatides', 'Une paire de chromosomes homologues apparies en prophase I', 'Un chromosome unique non replique', 'Deux cellules filles identiques'], correctIndex: 1, explanation: 'Un bivalent = 2 chromosomes homologues apparies (= 4 chromatides au total = tetrade). Cette configuration en prophase I permet les crossing-over.' },
                    { question: 'La polyploidie est :', options: ['La presence d\'un seul jeu de chromosomes', 'La presence de plus de 2 jeux complets de chromosomes', 'La perte d\'un chromosome', 'La fusion de deux cellules'], correctIndex: 1, explanation: 'La polyploidie = plus de 2n chromosomes (3n, 4n, 6n...). Frequente et viable chez les plantes (ble = 6n). Souvent letale chez les animaux. Peut causer une speciation rapide.' },
                    { question: 'Le point de restriction du cycle cellulaire se situe en :', options: ['Phase S', 'Fin de G1', 'Metaphase', 'Telophase'], correctIndex: 1, explanation: 'Le point de restriction en fin de G1 est le "point de non-retour" : avant, la cellule peut retourner en G0. Apres, elle s\'engage irreversiblement dans la division (phase S puis M).' },
                    { question: 'Les cellules souches pluripotentes peuvent :', options: ['Se differencier en n\'importe quel type cellulaire sauf les annexes embryonnaires', 'Produire uniquement des cellules sanguines', 'Se transformer en gametes uniquement', 'Ne se diviser qu\'une seule fois'], correctIndex: 0, explanation: 'Les cellules souches pluripotentes (embryonnaires) peuvent donner tous les types cellulaires de l\'organisme sauf les annexes embryonnaires (placenta). Les totipotentes (zygote) peuvent TOUT donner.' },
                    { question: 'La telomerase :', options: ['Detruit les telomeres', 'Rallonge les telomeres et est active dans les cellules cancereuses', 'Coupe l\'ADN en fragments', 'Separe les chromatides soeurs'], correctIndex: 1, explanation: 'Les telomeres raccourcissent a chaque division (horloge biologique). La telomerase les rallonge. Normalement inactive dans les cellules adultes, elle est reactivee dans ~90% des cancers, rendant les cellules "immortelles".' },
                    { question: 'Le syndrome de Turner correspond au caryotype :', options: ['47,XXY', '45,X', '47,XYY', '47,XXX'], correctIndex: 1, explanation: 'Turner = 45,X (une seule gonosome X). C\'est la seule monosomie viable. La personne est de sexe feminin, petite taille, ovaires non fonctionnels. Klinefelter = 47,XXY.' },
                    { question: 'En anaphase de mitose, ce qui se separe, c\'est :', options: ['Les chromosomes homologues', 'Les chromatides soeurs', 'Les bivalents', 'Les cellules filles'], correctIndex: 1, explanation: 'En anaphase de MITOSE, les chromatides soeurs se separent (coupure des coheseines au centromere). En anaphase I de MEIOSE, ce sont les chromosomes homologues qui se separent.' },
                    { question: 'Les telomeres :', options: ['Sont des enzymes de replication', 'Sont des sequences repetitives aux extremites des chromosomes qui raccourcissent a chaque division', 'Codent des proteines essentielles', 'Se trouvent au centre du chromosome'], correctIndex: 1, explanation: 'Les telomeres (TTAGGG repete) protegent les extremites des chromosomes. Ils raccourcissent a chaque division car l\'ADN polymerase ne peut pas copier l\'extremite. Quand trop courts → senescence cellulaire.' },
                    { question: 'La differenciation cellulaire signifie que :', options: ['Les cellules perdent de l\'ADN', 'Chaque cellule exprime un sous-ensemble specifique de ses genes', 'Les cellules changent de genome', 'Seules les cellules souches ont de l\'ADN'], correctIndex: 1, explanation: 'Toutes les cellules ont le MEME ADN, mais chaque type cellulaire n\'exprime qu\'une partie de ses genes (regulation epigenetique). C\'est ce qui fait qu\'un neurone est different d\'un globule rouge.' },
                    { question: 'La chimiotherapie cible principalement :', options: ['Les cellules qui ne se divisent pas', 'Les cellules en division rapide', 'Uniquement les cellules cancereuses', 'Les cellules osseuses'], correctIndex: 1, explanation: 'La chimiotherapie cible les cellules en division rapide, ce qui inclut les cellules cancereuses MAIS aussi les cellules normales a renouvellement rapide (cheveux, muqueuses, moelle osseuse). D\'ou les effets secondaires.' }
                ]
            },

            // ===== SECTION 3 : EVOLUTION & BIODIVERSITE =====
            {
                id: 'evolution',
                title: 'Evolution et biodiversite',
                icon: '\uD83E\uDD9E',
                content: '<h3>Mecanismes de l\'evolution</h3>'
                    + '<ul>'
                    + '<li><strong>Selection naturelle</strong> : les individus les mieux adaptes ont un avantage reproductif, favorisant la transmission de certains alleles (Darwin, 1859)</li>'
                    + '<li><strong>Derive genetique</strong> : variation aleatoire des frequences alleliques, surtout dans les petites populations (effet fondateur, goulet d\'etranglement)</li>'
                    + '<li><strong>Mutations</strong> : source ultime de la variabilite genetique, matiere premiere de l\'evolution</li>'
                    + '</ul>'
                    + '<h3>Preuves de l\'evolution</h3>'
                    + '<ul>'
                    + '<li><strong>Fossiles</strong> : temoins des formes de vie passees, montrent les formes de transition</li>'
                    + '<li><strong>Anatomie comparee</strong> : structures homologues (meme origine, fonctions differentes) vs analogues (origines differentes, meme fonction)</li>'
                    + '<li><strong>Biologie moleculaire</strong> : comparaison des sequences ADN/proteines, universalite du code genetique</li>'
                    + '</ul>'
                    + '<h3>Speciation et classification</h3>'
                    + '<ul>'
                    + '<li><strong>Speciation allopatrique</strong> : isolement geographique conduisant a la divergence genetique</li>'
                    + '<li><strong>Speciation sympatrique</strong> : formation d\'especes nouvelles sans isolement geographique (polyploidie chez les plantes)</li>'
                    + '<li><strong>Classification phylogenetique</strong> : regroupement des especes selon leurs liens de parente evolutive</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Qu\'est-ce que la selection naturelle selon Darwin ?', answer: 'La selection naturelle est le mecanisme par lequel les individus portant des caracteres avantageux dans un environnement donne survivent et se reproduisent mieux, transmettant ces caracteres a leur descendance. Au fil des generations, les alleles favorables deviennent plus frequents. Les 3 conditions : variation, heritabilite, avantage selectif (survie/reproduction). 🤯 Le savais-tu ? Darwin a mis 20 ans a publier sa theorie (1859), par peur du scandale !' },
                    { question: 'Qu\'est-ce que la derive genetique ?', answer: 'La derive genetique est la variation ALEATOIRE des frequences alleliques au cours des generations. Elle est d\'autant plus forte que la population est PETITE. Elle peut conduire a la fixation ou la disparition d\'alleles independamment de leur valeur selective. Cas particuliers : effet fondateur (petite population colonise un nouveau milieu) et goulet d\'etranglement (catastrophe reduit la population). 💡 ASTUCE MEMO : La derive genetique, c\'est comme tirer des billes au hasard dans un sac — moins il y a de billes, plus le hasard a d\'impact !' },
                    { question: 'Quelles sont les preuves de l\'evolution ?', answer: '1) Fossiles : formes de transition (Archaeopteryx, Tiktaalik). 2) Anatomie comparee : structures homologues (bras humain, aile de chauve-souris, nageoire de baleine = meme plan d\'organisation). 3) Biologie moleculaire : l\'ADN de tous les etres vivants est similaire, le code genetique est universel. 4) Biogeographie : repartition des especes sur les continents. 5) Organes vestigiaux (appendice, os du bassin chez les baleines).' },
                    { question: 'Quelle difference entre structures homologues et analogues ?', answer: 'Structures homologues : meme ORIGINE embryologique, fonctions differentes. Exemple : bras humain, aile de chauve-souris, nageoire de dauphin (meme plan = humerus-radius-ulna). Prouvent une parente commune. Structures analogues : origines DIFFERENTES, meme fonction. Exemple : aile d\'insecte et aile d\'oiseau. Resultent de la convergence evolutive. ⚠️ PIEGE BAC : Homologue ≠ identique ! L\'homologie prouve la parente, l\'analogie prouve l\'adaptation a un meme milieu.' },
                    { question: 'Qu\'est-ce que la speciation allopatrique ?', answer: 'La speciation allopatrique est la formation d\'une nouvelle espece par ISOLEMENT GEOGRAPHIQUE. Une population est separee en deux (montagne, fleuve, ocean). Sans flux de genes, les deux sous-populations evoluent independamment (mutations, selection, derive) et finissent par devenir intersteriles = deux especes distinctes. Exemple classique : les pinsons des Galapagos etudies par Darwin.' },
                    { question: 'Qu\'est-ce que la speciation sympatrique ?', answer: 'La speciation sympatrique est la formation d\'une nouvelle espece SANS isolement geographique, les populations vivant dans la meme aire. Mecanisme principal chez les plantes : polyploidie (doublement accidentel du nombre de chromosomes) rendant l\'hybride sterile avec les parents mais fertile avec d\'autres polyploides. Plus rare chez les animaux mais possible par specialisation ecologique ou comportementale.' },
                    { question: 'Comment lire un arbre phylogenetique ?', answer: 'Un arbre phylogenetique represente les relations de parente entre especes. Les noeuds representent les ancetres communs. Les especes actuelles sont aux extremites des branches. Plus deux especes partagent un noeud recent, plus elles sont apparentees. Les innovations evolutives (caracteres derives partages) sont placees sur les branches. ⚠️ PIEGE BAC : L\'arbre ne montre PAS que l\'homme descend du singe — il montre que nous partageons un ANCETRE COMMUN !' },
                    { question: 'Qu\'est-ce qu\'un caractere derive partage (synapomorphie) ?', answer: 'Un caractere derive partage est un caractere nouveau apparu chez un ancetre commun et transmis a tous ses descendants. Il sert a definir des groupes monophyletiques (clades). Exemples : les poils (mammiferes), les plumes (oiseaux/dinosaures theropodes), le squelette interne (vertebres). 💡 ASTUCE MEMO : "Derive PARTAGE = innovation COMMUNE" — c\'est la carte de membre du club familial !' },
                    { question: 'Retracer les grandes etapes de l\'evolution humaine.', answer: 'Les hominines se separent des panines (chimpanzes) il y a ~7 millions d\'annees. Etapes cles : 1) Bipedie (Toumai, ~7 Ma; Lucy/Australopithecus, ~3,2 Ma). 2) Augmentation du volume cranien (Homo habilis ~600 cm³, Homo erectus ~900 cm³). 3) Maitrise du feu (H. erectus, ~400 000 ans). 4) Art et langage complexe (H. sapiens, ~300 000 ans). 🤯 Le savais-tu ? Homo sapiens et Neandertal ont coexiste pendant ~5000 ans en Europe et se sont meme metisses — 2% de notre ADN est neandertalien !' },
                    { question: 'Qu\'est-ce qu\'un fossile et comment se forme-t-il ?', answer: 'Un fossile est un reste ou une trace d\'un organisme conserve dans les roches sedimentaires. Formation : un organisme meurt, est enfoui rapidement dans des sediments (sable, boue), les parties dures (os, coquille) sont peu a peu mineralisees (remplacement par des mineraux). La fossilisation est un evenement RARE qui necessite des conditions particulieres (enfouissement rapide, absence d\'oxygene).' },
                    { question: 'Qu\'est-ce que la selection sexuelle ?', answer: 'La selection sexuelle est un cas particulier de selection naturelle ou certains caracteres sont favorises car ils augmentent le succes reproducteur. Deux mecanismes : 1) Competition entre males (bois du cerf, combats). 2) Choix par les femelles (plumage du paon, chant des oiseaux). 🤯 Le savais-tu ? La queue du paon est un HANDICAP pour la survie (poids, visibilite par les predateurs) mais un avantage pour la reproduction — paradoxe de la selection sexuelle !' },
                    { question: 'Qu\'est-ce que la convergence evolutive ?', answer: 'La convergence evolutive est le phenomene par lequel des especes NON apparentees developpent des caracteres similaires en reponse aux memes pressions de selection. Exemples : forme hydrodynamique du dauphin (mammifere) et du requin (poisson), ailes de l\'insecte et de l\'oiseau, yeux du poulpe et de l\'humain. Ce sont des structures analogues, pas homologues. 💡 ASTUCE MEMO : La convergence, c\'est comme deux eleves qui trouvent la meme solution a un probleme sans avoir copie l\'un sur l\'autre !' },
                    { question: 'Qu\'est-ce que la biodiversite et quelles sont ses echelles ?', answer: 'La biodiversite est la diversite du vivant a trois echelles : 1) Genetique : diversite des alleles au sein d\'une espece. 2) Specifique : diversite des especes dans un ecosysteme (8-10 millions d\'especes estimees, 1,8 million decrites). 3) Ecosystemique : diversite des ecosystemes (forets, recifs, zones humides). Ces trois niveaux sont interdependants. La biodiversite n\'est pas fixe : elle evolue au cours du temps (crises et radiations).' },
                    { question: 'Qu\'est-ce qu\'une crise biologique (extinction de masse) ?', answer: 'Une crise biologique est une disparition massive et rapide d\'especes a l\'echelle planetaire. 5 grandes extinctions identifiees. La plus celebre : crise Cretace-Paleogene (-66 Ma, disparition des dinosaures non-aviens, meteorite + volcanisme). Nous vivons possiblement la 6eme extinction, d\'origine HUMAINE. 🤯 Le savais-tu ? Lors de la crise Permien-Trias (-252 Ma), 95% des especes marines ont disparu — c\'est la plus grande catastrophe de l\'histoire du vivant !' },
                    { question: 'Qu\'est-ce que l\'horloge moleculaire ?', answer: 'L\'horloge moleculaire est un outil qui estime la date de divergence entre deux especes en comparant les differences dans leurs sequences d\'ADN ou de proteines. Hypothese : les mutations s\'accumulent a un rythme relativement constant dans le temps. Plus deux especes ont de differences dans leur ADN, plus leur ancetre commun est ancien. Limites : le rythme varie selon les genes et les organismes.' },
                    { question: 'Qu\'est-ce que l\'equilibre ponctue (Gould & Eldredge) ?', answer: 'La theorie de l\'equilibre ponctue propose que l\'evolution ne se fait pas de facon graduelle et constante, mais par de longues periodes de stabilite (stase) ponctuees de breves periodes de changement rapide (speciation). Cela explique pourquoi on trouve souvent des "trous" dans les archives fossiles — les transitions sont rapides et locales. C\'est un complement (pas une contradiction) du darwinisme.' },
                    { question: 'Qu\'est-ce que la radiation adaptative ?', answer: 'La radiation adaptative est la diversification rapide d\'une espece ancestrale en de nombreuses especes occupant des niches ecologiques variees. Elle survient souvent apres une extinction de masse (niches liberees) ou la colonisation d\'un nouveau milieu. Exemples celebres : les pinsons des Galapagos (13 especes a partir d\'un ancetre), les mammiferes apres la disparition des dinosaures.' },
                    { question: 'Qu\'est-ce que l\'effet fondateur ?', answer: 'L\'effet fondateur est un cas particulier de derive genetique : un petit groupe d\'individus colonise un nouveau territoire. Ce groupe ne represente qu\'un echantillon de la diversite genetique de la population d\'origine. Certains alleles rares peuvent etre surrepresentes, d\'autres absents. Exemple : forte frequence de la polydactylie chez les Amish (fondee par un petit groupe portant cet allele).' },
                    { question: 'Expliquer la difference entre micro-evolution et macro-evolution.', answer: 'Micro-evolution : changements a l\'echelle de la population (changement des frequences alleliques au fil des generations) — observable directement (resistance aux antibiotiques, phalenes du bouleau). Macro-evolution : changements a grande echelle sur de longues periodes (apparition de nouveaux groupes, extinctions massives, radiation adaptative). La macro-evolution resulte de l\'accumulation de phenomenes micro-evolutifs.' },
                    { question: 'Qu\'est-ce que le goulet d\'etranglement ?', answer: 'Le goulet d\'etranglement (bottleneck) est une reduction drastique et brutale de la taille d\'une population suite a une catastrophe (epidemie, famine, cataclysme). La population survivante ne represente qu\'un echantillon reduit de la diversite genetique d\'origine. La derive genetique est alors tres forte. Exemple : les guepards ont subi un goulet il y a ~10 000 ans — ils sont si peu diversifies genetiquement qu\'on peut faire des greffes de peau entre individus non apparentes !' },
                    { question: 'Qu\'est-ce que la co-evolution ?', answer: 'La co-evolution est l\'evolution reciproque de deux especes en interaction etroite. Chaque changement chez l\'une exerce une pression selective sur l\'autre, et vice versa. Exemples : fleurs et pollinisateurs (orchidee de Madagascar et papillon avec trompe de 30 cm, predit par Darwin !), predateur-proie (course aux armements entre guepard rapide et gazelle rapide), parasite-hote. 💡 ASTUCE MEMO : La co-evolution, c\'est une danse a deux ou chaque partenaire s\'adapte aux pas de l\'autre.' },
                    { question: 'Qu\'est-ce que la theorie endosymbiotique ?', answer: 'La theorie endosymbiotique (Lynn Margulis, 1967) propose que les mitochondries et les chloroplastes etaient a l\'origine des BACTERIES libres qui ont ete englobees par une cellule ancestrale. Preuves : ils possedent leur propre ADN circulaire, une double membrane, des ribosomes de type bacterien, et se divisent par scissiparite. 🤯 Le savais-tu ? Tes mitochondries sont des anciennes bacteries ! Tu es litteralement le produit d\'une association vieille de 2 milliards d\'annees.' },
                    { question: 'Qu\'est-ce qu\'un organe vestigial ?', answer: 'Un organe vestigial est un organe reduit, atrophie et sans fonction apparente, mais qui temoigne d\'une fonction chez un ancetre. C\'est une preuve de l\'evolution. Exemples : l\'appendice chez l\'humain (vestige du caecum des herbivores), les os du bassin chez les baleines (vestige des pattes posterieures de leurs ancetres terrestres), les yeux des poissons cavernicoles aveugles. 💡 ASTUCE MEMO : Un vestige est une "ruine" evolutive — comme un chateau en ruine temoigne d\'une epoque revolue.' },
                    { question: 'Qu\'est-ce que la phalene du bouleau et que prouve-t-elle ?', answer: 'La phalene du bouleau (Biston betularia) est un papillon de nuit qui existe sous deux formes : claire (typica) et sombre (carbonaria). Avant l\'industrialisation, la forme claire dominait (camouflage sur les bouleaux clairs). Pendant la revolution industrielle, la pollution a noirci les troncs : la forme sombre a ete selectionee (mieux camouflee). Apres depollution, la forme claire est revenue. C\'est un exemple OBSERVABLE de selection naturelle en action !' },
                    { question: 'Qu\'est-ce que la resistance aux antibiotiques et son lien avec l\'evolution ?', answer: 'Certaines bacteries possedent naturellement des alleles de resistance aux antibiotiques. Quand on utilise un antibiotique, il tue les bacteries sensibles mais les RESISTANTES survivent et se reproduisent = selection naturelle. La surpopulation de resistantes rend l\'antibiotique inefficace. C\'est l\'evolution en temps reel ! L\'OMS considere l\'antibioresistance comme l\'une des plus grandes menaces pour la sante mondiale. 🤯 Le savais-tu ? En 2019, l\'antibioresistance a directement cause 1,27 million de deces dans le monde.' },
                    { question: 'Qu\'est-ce que la selection stabilisante vs directionnelle vs diversifiante ?', answer: 'Selection STABILISANTE : les phenotypes intermediaires sont favorises, les extremes elimines. Exemple : poids des bebes a la naissance (trop petit ou trop gros = defavorable). Selection DIRECTIONNELLE : un phenotype extreme est favorise, la moyenne se deplace. Exemple : phalene du bouleau. Selection DIVERSIFIANTE : les deux extremes sont favorises au detriment du phenotype moyen. Exemple : becs des pinsons (tres gros ou tres fin).' },
                    { question: 'Qu\'est-ce que l\'equilibre de Hardy-Weinberg ?', answer: 'L\'equilibre de Hardy-Weinberg est un modele mathematique predisant que les frequences alleliques d\'une population restent CONSTANTES de generation en generation SI : 1) Population infinie. 2) Panmixie (croisements aleatoires). 3) Pas de mutations. 4) Pas de selection. 5) Pas de migration. En realite, ces conditions ne sont jamais reunies — l\'evolution est INEVITABLE. L\'equation : p² + 2pq + q² = 1 (p = freq allele dominant, q = freq allele recessif). C\'est le "modele zero" de l\'evolution : s\'il est viole, il y a evolution !' },
                    { question: 'Qu\'est-ce que la fitness en evolution ?', answer: 'La fitness (valeur selective ou aptitude phenotypique) mesure le succes reproducteur relatif d\'un individu par rapport aux autres dans une population. Un individu avec une fitness elevee survit mieux ET/OU se reproduit plus, transmettant davantage ses alleles. La fitness n\'est pas une valeur absolue — elle depend de l\'ENVIRONNEMENT. Un allele "avantageux" dans un milieu peut etre "desavantageux" dans un autre. 💡 ASTUCE MEMO : La fitness, ce n\'est pas etre le plus fort — c\'est laisser le plus de descendants viables !' },
                    { question: 'Qu\'est-ce qu\'un clade (groupe monophyletique) ?', answer: 'Un clade est un groupe evolutif comprenant un ancetre et TOUS ses descendants. Il est defini par au moins un caractere derive partage (synapomorphie). Exemples : les mammiferes (partageant les poils + les glandes mammaires), les tetrapodes (partageant les 4 membres). Un arbre phylogenetique represente les relations entre clades. ⚠️ PIEGE BAC : Les "reptiles" au sens traditionnel ne forment PAS un clade car ils excluent les oiseaux — qui descendent des dinosaures theropodes !' },
                    { question: 'Qu\'est-ce que la bipedie et pourquoi est-elle cle dans l\'evolution humaine ?', answer: 'La bipedie (marche sur deux pieds) est le PREMIER caractere derive des hominines, apparu il y a ~7 millions d\'annees (Toumai, Orrorin). Adaptations anatomiques : trou occipital centre sous le crane (et non a l\'arriere), bassin large et court, lordose lombaire, pied non prehensile avec voute plantaire. La bipedie a libere les mains (outils, transport), permis de voir plus loin dans la savane et de parcourir de longues distances. 🤯 Le savais-tu ? Lucy (Australopithecus afarensis, -3,2 Ma) avait un cerveau de la taille d\'un pamplemousse mais marchait parfaitement debout !' },
                    { question: 'Qu\'est-ce que le transfert horizontal de genes ?', answer: 'Le transfert horizontal de genes (THG) est le transfert d\'ADN entre organismes qui ne sont PAS parent-enfant (contrairement a la transmission verticale classique). Il est tres frequent chez les BACTERIES (par conjugaison, transduction ou transformation). C\'est le principal mecanisme de propagation de la resistance aux antibiotiques entre bacteries. Le THG complique la construction des arbres phylogenetiques chez les procaryotes.' },
                    { question: 'Qu\'est-ce que l\'avantage de l\'heterozygote ?', answer: 'L\'avantage de l\'heterozygote est un cas ou l\'individu heterozygote (Aa) a une fitness SUPERIEURE aux deux homozygotes (AA et aa). Exemple classique : le gene de la drepanocytose. L\'homozygote HbS/HbS a la drepanocytose (grave). L\'homozygote HbA/HbA est sensible au paludisme. L\'heterozygote HbA/HbS n\'a ni drepanocytose severe NI paludisme = avantage. C\'est pourquoi l\'allele HbS est maintenu dans les populations ou le paludisme est present.' },
                    { question: 'Qu\'est-ce que la speciation par polyploidie ?', answer: 'Chez les plantes, la polyploidie (multiplication du nombre de chromosomes : 3n, 4n, 6n...) peut creer instantanement une nouvelle espece. Mecanisme : un hybride entre deux especes proches est normalement sterile (chromosomes non homologues = meiose impossible). Si un doublement chromosomique survient, les chromosomes retrouvent un homologue et la meiose devient possible. C\'est de la speciation INSTANTANEE et SYMPATRIQUE. 🤯 Le savais-tu ? Le ble moderne (6n = 42 chromosomes) est un polyploide issu de croisements entre trois especes ancestrales !' },
                    { question: 'Comment le volume cranien a-t-il evolue chez les hominines ?', answer: 'L\'augmentation du volume cranien est un trait majeur de l\'evolution humaine (mais pas le premier — la bipedie est antérieure). Toumai (~7 Ma) : ~350 cm³. Australopithecus (~3 Ma) : ~400-500 cm³. Homo habilis (~2,5 Ma) : ~600-700 cm³. Homo erectus (~1,5 Ma) : ~900-1100 cm³. Homo neandertalensis : ~1500 cm³. Homo sapiens : ~1400 cm³. L\'augmentation du volume cranien est correlee avec le developpement des outils, du langage et de la vie sociale. Attention : un cerveau plus gros ne signifie pas forcement plus intelligent — Neandertal avait un cerveau plus grand que le notre !' },
                    { question: 'Qu\'est-ce que l\'ADN mitochondrial et son utilite en evolution ?', answer: 'L\'ADN mitochondrial (ADNmt) est un petit genome circulaire (~16 500 pb chez l\'humain) present dans les MITOCHONDRIES. Particularites : 1) Transmission MATERNELLE uniquement (les mitochondries du spermatozoïde sont eliminees). 2) Pas de recombinaison. 3) Taux de mutation plus eleve que l\'ADN nucleaire. Ces proprietes en font un outil ideal pour tracer les lignees maternelles en evolution. L\'"Eve mitochondriale" est l\'ancetre maternelle commune de tous les humains actuels, estimee a ~200 000 ans, en Afrique.' },
                    { question: 'Qu\'est-ce que la selection artificielle ?', answer: 'La selection artificielle est la selection operee par l\'HOMME sur les especes domestiques pour favoriser des caracteres souhaites. C\'est le meme principe que la selection naturelle, mais le critere de "fitness" est choisi par l\'eleveur/agriculteur. Exemples : toutes les races de chiens descendent du loup (domestication il y a ~15 000 ans), le mais moderne vient de la teosinte (plante sauvage), le chou, le brocoli, le chou-fleur et les choux de Bruxelles viennent tous de la MEME espece sauvage (Brassica oleracea). 🤯 Le savais-tu ? Darwin a commence "L\'Origine des especes" par un chapitre sur les pigeons domestiques — la selection artificielle etait sa preuve par analogie de la selection naturelle !' },
                    { question: 'Qu\'est-ce que l\'Out of Africa et ses preuves ?', answer: 'La theorie "Out of Africa" (ou origine africaine recente) propose que tous les Homo sapiens actuels descendent d\'une population AFRICAINE qui a emigre vers le reste du monde il y a ~70 000-100 000 ans, remplacant les populations archaiques locales (avec un peu de metissage). Preuves : 1) La diversite genetique est MAXIMALE en Afrique et DIMINUE en s\'eloignant (effet fondateur a chaque etape). 2) Les plus anciens fossiles de H. sapiens sont africains (~300 000 ans, Jebel Irhoud, Maroc). 3) L\'ADN ancien confirme le metissage avec Neandertal hors d\'Afrique (~2%).' },
                    { question: 'Qu\'est-ce qu\'un taxon et comment construit-on un arbre phylogenetique ?', answer: 'Un taxon est un groupe d\'organismes defini dans une classification (espece, genre, famille, ordre, classe...). Pour construire un arbre phylogenetique : 1) Choisir des caracteres (morphologiques ou moleculaires). 2) Distinguer les caracteres primitifs (ancestraux = plesiomorphies) des derives (nouveaux = apomorphies). 3) Regrouper les especes partageant les memes caracteres DERIVES (synapomorphies). 4) Appliquer le principe de PARCIMONIE (l\'arbre le plus simple est le plus probable). 💡 ASTUCE MEMO : Un arbre phylogenetique n\'est pas un arbre genealogique ! Il montre les RELATIONS DE PARENTE, pas la descendance directe.' },
                    { question: 'Qu\'est-ce que la selection dependante de la frequence ?', answer: 'La selection dependante de la frequence est un type de selection ou la fitness d\'un phenotype depend de sa FREQUENCE dans la population. Selection NEGATIVE dependante de la frequence : le phenotype RARE est avantage (ex : les predateurs apprennent a reconnaitre la proie commune et ignorent la rare → avantage pour les rares). Selection POSITIVE : le phenotype commun est avantage (ex : mimetisme chez les papillons toxiques — plus ils sont nombreux, plus les predateurs les evitent). Ce mecanisme MAINTIENT le polymorphisme dans les populations.' },
                    { question: 'Qu\'est-ce que LUCA (Last Universal Common Ancestor) ?', answer: 'LUCA (Last Universal Common Ancestor) est le dernier ancetre commun universel de tous les etres vivants actuels. Il n\'est pas le premier etre vivant mais le dernier a partir duquel toutes les lignees actuelles ont diverge. On estime qu\'il vivait il y a ~3,5-4 milliards d\'annees. Ses caracteristiques deduites : cellule procaryote, ADN comme support genetique, code genetique universel, ribosomes, membranes lipidiques. 🤯 Le savais-tu ? Toi, un champignon, un sequoia et une bacterie — vous descendez tous du MEME ancetre. C\'est peut-etre la decouverte la plus stupéfiante de la biologie !' },
                    { question: 'Qu\'est-ce que la genetique des populations ?', answer: 'La genetique des populations etudie comment les frequences alleliques changent au cours des generations dans une population. Forces evolutives : 1) MUTATION (cree de nouveaux alleles). 2) SELECTION NATURELLE (favorise/elimine des alleles). 3) DERIVE GENETIQUE (fluctuations aleatoires, surtout petites populations). 4) MIGRATION/flux de genes (apport d\'alleles d\'une autre population). L\'equilibre de Hardy-Weinberg predit la stabilite des frequences en ABSENCE de ces forces — c\'est le modele de reference pour detecter l\'evolution.' }
                ],
                quiz: [
                    { question: 'La derive genetique est plus importante dans :', options: ['Les grandes populations', 'Les petites populations', 'Les populations soumises a selection', 'Les populations a forte mutation'], correctIndex: 1, explanation: 'La derive genetique est un phenomene stochastique inversement proportionnel a la taille de la population. Plus la population est petite, plus les fluctuations aleatoires sont marquees.' },
                    { question: 'Les structures homologues prouvent :', options: ['La convergence evolutive', 'Une parente commune entre especes', 'L\'adaptation au meme milieu', 'L\'absence d\'evolution'], correctIndex: 1, explanation: 'Les structures homologues (meme plan d\'organisation, meme origine embryologique) sont la preuve d\'un ancetre commun. Exemple : bras humain, aile de chauve-souris, nageoire de baleine.' },
                    { question: 'La speciation allopatrique necessite :', options: ['Une mutation unique majeure', 'Un isolement geographique', 'La polyploidie', 'La selection sexuelle uniquement'], correctIndex: 1, explanation: 'La speciation allopatrique repose sur l\'isolement geographique qui empeche le flux de genes entre deux populations. Elles evoluent independamment jusqu\'a devenir intersteriles.' },
                    { question: 'L\'Archaeopteryx est un fossile important car :', options: ['C\'est le plus vieux fossile connu', 'C\'est une forme de transition entre dinosaures et oiseaux', 'Il prouve que les mammiferes descendent des reptiles', 'Il date de -4 milliards d\'annees'], correctIndex: 1, explanation: 'L\'Archaeopteryx (~150 Ma) possede des caracteres de dinosaure (dents, griffes, queue osseuse) ET d\'oiseau (plumes, furcula). C\'est une forme de transition cle dans l\'evolution des oiseaux.' },
                    { question: 'Un caractere derive partage permet de :', options: ['Dater un fossile', 'Definir un groupe monophyletique dans un arbre phylogenetique', 'Mesurer la taille d\'une population', 'Calculer le taux de mutation'], correctIndex: 1, explanation: 'Un caractere derive partage (synapomorphie) est une innovation apparue chez un ancetre commun et heritee par tous ses descendants. Il definit un clade (groupe monophyletique).' },
                    { question: 'La 6eme extinction de masse est principalement causee par :', options: ['Une meteorite', 'Le volcanisme', 'Les activites humaines', 'Les glaciations'], correctIndex: 2, explanation: 'La 6eme extinction est d\'origine anthropique : destruction des habitats, surexploitation, pollution, especes invasives et changement climatique accelerent la disparition des especes.' },
                    { question: 'La selection sexuelle favorise des caracteres qui :', options: ['Augmentent toujours la survie', 'Augmentent le succes reproducteur', 'Sont toujours utiles pour fuir les predateurs', 'Reduisent la taille de la population'], correctIndex: 1, explanation: 'La selection sexuelle favorise les caracteres augmentant le succes reproducteur, meme s\'ils sont couteux pour la survie (queue du paon, bois du cerf).' },
                    { question: 'L\'horloge moleculaire suppose que :', options: ['Les mutations sont toujours nefastes', 'Les mutations neutres s\'accumulent a rythme constant', 'L\'ADN ne change jamais', 'Les fossiles sont inutiles'], correctIndex: 1, explanation: 'L\'horloge moleculaire repose sur l\'hypothese que les mutations neutres s\'accumulent a un rythme relativement constant. Plus les sequences divergent entre deux especes, plus leur separation est ancienne.' },
                    { question: 'La convergence evolutive produit des structures :', options: ['Homologues', 'Analogues', 'Vestigiales', 'Identiques genetiquement'], correctIndex: 1, explanation: 'La convergence evolutive produit des structures analogues : meme fonction mais origines differentes (aile d\'insecte vs aile d\'oiseau). Elles ne prouvent PAS une parente commune.' },
                    { question: 'L\'effet fondateur se produit quand :', options: ['Une grande population migre en masse', 'Un petit groupe colonise un nouveau territoire', 'Une mutation benefique apparait', 'Deux especes se croisent'], correctIndex: 1, explanation: 'L\'effet fondateur : un petit nombre d\'individus colonise un nouveau milieu. Ce petit echantillon ne represente pas toute la diversite genetique d\'origine, ce qui peut fixer des alleles rares.' },
                    { question: 'Les pinsons des Galapagos illustrent :', options: ['La derive des continents', 'La radiation adaptative', 'L\'extinction de masse', 'La symbiose'], correctIndex: 1, explanation: 'Les 13 especes de pinsons des Galapagos descendent d\'un seul ancetre et se sont diversifiees en occupant differentes niches ecologiques (insectivores, granivores, cactophages) = radiation adaptative.' },
                    { question: 'Homo sapiens et Neandertal :', options: ['N\'ont jamais coexiste', 'Se sont metisses, nous portons ~2% d\'ADN neandertalien', 'Sont la meme espece', 'Ont diverge il y a 100 000 ans'], correctIndex: 1, explanation: 'Les etudes d\'ADN ancien montrent que Homo sapiens et Neandertal se sont croises. Les non-Africains portent environ 2% d\'ADN neandertalien, preuve d\'hybridation en Europe/Asie.' },
                    { question: 'La source ultime de la variabilite genetique est :', options: ['La selection naturelle', 'La derive genetique', 'Les mutations', 'La fecondation'], correctIndex: 2, explanation: 'Les mutations sont la seule source de NOUVEAUX alleles. La selection naturelle, la derive genetique et la fecondation ne font que redistribuer la variabilite deja existante.' },
                    { question: 'La theorie endosymbiotique explique l\'origine :', options: ['Du noyau cellulaire', 'Des mitochondries et chloroplastes', 'Des ribosomes', 'De la membrane plasmique'], correctIndex: 1, explanation: 'Selon la theorie endosymbiotique (Margulis), les mitochondries et chloroplastes etaient des bacteries libres englobees par une cellule ancestrale. Preuves : ADN propre circulaire, double membrane, ribosomes de type bacterien.' },
                    { question: 'Le goulet d\'etranglement :', options: ['Augmente la diversite genetique', 'Reduit brutalement la taille et la diversite d\'une population', 'Est un type de selection naturelle', 'Favorise les individus les plus forts'], correctIndex: 1, explanation: 'Un goulet d\'etranglement reduit drastiquement la population. Les survivants ne sont qu\'un echantillon de la diversite initiale. La derive genetique est ensuite tres forte.' },
                    { question: 'La phalene du bouleau illustre :', options: ['La derive genetique', 'La selection naturelle observable en temps reel', 'La speciation sympatrique', 'La mutation dirigee'], correctIndex: 1, explanation: 'Le changement de frequence des formes claire et sombre selon la pollution est un exemple classique de selection naturelle directionnelle observable sur quelques generations.' },
                    { question: 'L\'antibioresistance est un exemple de :', options: ['Mutation dirigee', 'Selection naturelle chez les bacteries', 'Derive genetique', 'Co-evolution'], correctIndex: 1, explanation: 'L\'antibiotique agit comme pression de selection : les bacteries resistantes survivent et se reproduisent. C\'est de la selection naturelle en temps reel, avec des consequences graves pour la sante publique.' },
                    { question: 'Un organe vestigial :', options: ['Est un organe nouvellement apparu', 'Est un organe atrophie temoignant d\'une fonction ancestrale', 'Fonctionne mieux que l\'organe original', 'N\'existe que chez les humains'], correctIndex: 1, explanation: 'Un organe vestigial est reduit et sans fonction apparente mais temoigne d\'un ancetre chez qui il etait fonctionnel. Exemples : appendice (humain), os du bassin (baleines).' },
                    { question: 'La co-evolution implique :', options: ['L\'evolution d\'une seule espece', 'L\'evolution reciproque de deux especes en interaction', 'L\'extinction simultanee de deux especes', 'La fusion de deux especes en une'], correctIndex: 1, explanation: 'La co-evolution est l\'evolution reciproque de deux especes en interaction (predateur-proie, parasite-hote, fleur-pollinisateur). Chaque changement chez l\'une influence l\'autre.' },
                    { question: 'La selection stabilisante favorise :', options: ['Les phenotypes extremes', 'Les phenotypes intermediaires', 'La disparition de l\'espece', 'Les mutations letales'], correctIndex: 1, explanation: 'La selection stabilisante elimine les phenotypes extremes et favorise la moyenne. Exemple classique : le poids optimal des bebes a la naissance (ni trop petit ni trop gros).' },
                    { question: 'L\'equilibre de Hardy-Weinberg est viole quand :', options: ['La population est tres grande', 'Il y a selection, derive, mutation ou migration', 'Les croisements sont aleatoires', 'Il n\'y a aucune mutation'], correctIndex: 1, explanation: 'L\'equilibre de Hardy-Weinberg suppose une population infinie, panmixie, pas de mutation, pas de selection, pas de migration. Toute violation = les frequences alleliques changent = il y a EVOLUTION.' },
                    { question: 'L\'avantage de l\'heterozygote pour la drepanocytose signifie :', options: ['Tous les heterozygotes sont malades', 'L\'heterozygote est protege du paludisme sans etre malade', 'La drepanocytose est benefique', 'Seuls les homozygotes survivent'], correctIndex: 1, explanation: 'L\'heterozygote HbA/HbS n\'a ni drepanocytose grave ni paludisme = fitness superieure. C\'est pourquoi l\'allele HbS est maintenu dans les zones impaludees malgre ses effets nefastes a l\'etat homozygote.' },
                    { question: 'Le transfert horizontal de genes est frequent chez :', options: ['Les mammiferes', 'Les plantes', 'Les bacteries', 'Les insectes uniquement'], correctIndex: 2, explanation: 'Les bacteries echangent des genes par conjugaison, transduction et transformation. C\'est le mecanisme principal de propagation de la resistance aux antibiotiques.' },
                    { question: 'La bipedie est apparue chez les hominines il y a environ :', options: ['100 000 ans', '1 million d\'annees', '7 millions d\'annees', '65 millions d\'annees'], correctIndex: 2, explanation: 'La bipedie est le PREMIER caractere derive des hominines, apparue il y a ~7 Ma (Toumai, Orrorin). Bien avant l\'augmentation du volume cranien ou l\'utilisation d\'outils.' }
                ]
            },

            // ===== SECTION 4 : SYSTEME IMMUNITAIRE =====
            {
                id: 'immunologie',
                title: 'Le systeme immunitaire',
                icon: '\uD83E\uDDA0',
                content: '<h3>Immunite innee</h3>'
                    + '<ul>'
                    + '<li><strong>Barrieres</strong> : physiques (peau, muqueuses), chimiques (lysozyme, acidite gastrique), microbiologiques (microbiote)</li>'
                    + '<li><strong>Reaction inflammatoire</strong> : rougeur, chaleur, gonflement, douleur. Cellules sentinelles, mediateurs chimiques</li>'
                    + '<li><strong>Phagocytose</strong> : ingestion et destruction des pathogenes par macrophages et granulocytes neutrophiles</li>'
                    + '</ul>'
                    + '<h3>Immunite adaptative</h3>'
                    + '<ul>'
                    + '<li><strong>Lymphocytes T CD8+</strong> : detruisent les cellules infectees (perforine, granzymes). Reponse cellulaire</li>'
                    + '<li><strong>Lymphocytes T CD4+</strong> : activent les autres lymphocytes via interleukines. Chefs d\'orchestre</li>'
                    + '<li><strong>Lymphocytes B → plasmocytes</strong> : secretent les anticorps. Reponse humorale</li>'
                    + '</ul>'
                    + '<h3>Memoire immunitaire et vaccination</h3>'
                    + '<ul>'
                    + '<li><strong>Cellules memoire</strong> : persistent apres l\'infection, permettent une reponse secondaire rapide</li>'
                    + '<li><strong>Vaccination</strong> : antigene attenue/inactive/ARNm pour generer des cellules memoire</li>'
                    + '<li><strong>VIH et SIDA</strong> : le VIH detruit les LT CD4+, effondrant la reponse immunitaire adaptative</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Quelles sont les barrieres de l\'immunite innee ?', answer: 'L\'immunite innee possede trois types de barrieres : 1) Physiques : peau (epiderme keratinise), muqueuses, cils des voies respiratoires. 2) Chimiques : lysozyme (larmes, salive), acidite gastrique (pH 2), defensines. 3) Microbiologiques : le microbiote (flore intestinale) empeche la colonisation par les pathogenes par competition. 💡 ASTUCE MEMO : PCM — Physique, Chimique, Microbiologique = les 3 murs de la forteresse immunitaire !' },
                    { question: 'Quelles sont les etapes de la reaction inflammatoire ?', answer: 'La lesion libere des mediateurs chimiques (histamine, prostaglandines par les mastocytes). Il y a vasodilatation (rougeur, chaleur), augmentation de la permeabilite vasculaire (oedeme, gonflement), afflux de phagocytes par diapedese, puis phagocytose des pathogenes. La douleur resulte de la stimulation des nocicepteurs. 🧠 TRUC POUR RETENIR : RCGD — Rougeur, Chaleur, Gonflement, Douleur = les 4 signes cardinaux de l\'inflammation, decrits par Celse il y a 2000 ans !' },
                    { question: 'Decrire les etapes de la phagocytose.', answer: '1) Adhesion : le phagocyte reconnait et se fixe au pathogene (recepteurs PRR reconnaissent les PAMP). 2) Ingestion : le pathogene est englobe dans une vesicule (phagosome). 3) Digestion : fusion du phagosome avec un lysosome (phagolysosome), les enzymes detruisent le pathogene. 4) Rejet : les debris sont expulses par exocytose. 5) Presentation : les fragments antigeniques sont presentes sur le CMH (lien avec l\'immunite adaptative).' },
                    { question: 'Quelle est la difference entre immunite innee et adaptative ?', answer: 'Immunite innee : IMMEDIATE (minutes), NON specifique (agit contre tout pathogene), SANS memoire. Immunite adaptative : LENTE (5-7 jours pour la reponse primaire), SPECIFIQUE d\'un antigene, avec MEMOIRE (reponse secondaire rapide). 💡 ASTUCE MEMO : L\'immunite innee = les pompiers (interviennent immediatement, memes outils pour tout feu). L\'immunite adaptative = les experts (plus lents mais avec des outils specialises, et ils se souviennent).' },
                    { question: 'Quel est le role des lymphocytes T CD4+ ?', answer: 'Les lymphocytes T CD4+ (auxiliaires/helper) sont les CHEFS D\'ORCHESTRE de l\'immunite adaptative. Apres reconnaissance de l\'antigene presente par une CPA (cellule presentatrice d\'antigene) via le CMH II, ils secretent des interleukines qui : 1) Activent les lymphocytes B (reponse humorale). 2) Activent les lymphocytes T CD8+ (reponse cellulaire). 3) Stimulent les macrophages. Sans eux, pas de reponse adaptative efficace — c\'est pourquoi le VIH est si devastateur !' },
                    { question: 'Comment agissent les lymphocytes T CD8+ ?', answer: 'Les lymphocytes T CD8+ (cytotoxiques) reconnaissent les cellules infectees qui presentent des peptides viraux via le CMH de classe I (toute cellule nucleee). Ils detruisent ces cellules par contact direct en liberant : 1) Perforine (perfore la membrane = trous). 2) Granzymes (entrent par les trous et declenchent l\'apoptose). 🧠 TRUC POUR RETENIR : CD8+ = "Cellular Destruction 8" — ils detruisent les cellules ! Perforine = PERfore comme un PERceur.' },
                    { question: 'Qu\'est-ce qu\'un anticorps et comment agit-il ?', answer: 'Un anticorps (immunoglobuline) est une proteine en forme de Y, produite par les plasmocytes. Il possede 2 sites de fixation specifiques d\'un antigene (parties variables). Modes d\'action : 1) Neutralisation (bloque le pathogene). 2) Opsonisation (facilite la phagocytose). 3) Activation du complement (cascade de proteines qui perfore les pathogenes). 💡 ASTUCE MEMO : L\'anticorps en Y a 2 bras pour "attraper" l\'antigene, comme une pince !' },
                    { question: 'Qu\'est-ce que la selection clonale ?', answer: 'La selection clonale est le mecanisme par lequel SEULS les lymphocytes portant un recepteur specifique de l\'antigene rencontre sont actives. Ces lymphocytes proliferent (expansion clonale) et se differencient en cellules effectrices (plasmocytes ou T cytotoxiques) ET en cellules memoire. Notre corps possede des milliards de lymphocytes differents, chacun avec un recepteur unique — seuls ceux qui "matchent" l\'antigene sont selectionnes. 🤯 Le savais-tu ? Tu possedes environ 10 milliards de lymphocytes differents, chacun capable de reconnaitre un antigene specifique !' },
                    { question: 'Quel est le principe de la vaccination ?', answer: 'La vaccination introduit un antigene SANS provoquer la maladie pour generer des cellules memoire. Types : attenue (ROR), inactive (grippe), sous-unitaire (hepatite B), ARNm (COVID). La reponse primaire cree des cellules memoire. Si le "vrai" pathogene arrive plus tard, la reponse secondaire est plus rapide, plus intense et plus durable. C\'est le principe de la memoire immunitaire exploitee artificiellement.' },
                    { question: 'Pourquoi la reponse secondaire est-elle plus rapide ?', answer: 'Lors de la reponse primaire, il faut selectionner, activer et amplifier les lymphocytes specifiques (5-7 jours). Lors de la reponse secondaire, les cellules memoire sont deja presentes et rapidement reactivees (1-2 jours). Elles sont plus nombreuses, reagissent plus vite et produisent des anticorps de meilleure affinite (maturation d\'affinite). ⚠️ PIEGE BAC : La reponse secondaire n\'est pas seulement plus rapide — les anticorps sont aussi plus AFFINS (ils se fixent mieux a l\'antigene).' },
                    { question: 'Comment le VIH cause-t-il le SIDA ?', answer: 'Le VIH (retrovirus) infecte specifiquement les lymphocytes T CD4+ grace a sa fixation sur le recepteur CD4 et le corecepteur CCR5. Il integre son ADN (apres transcription inverse) dans le genome de la cellule hote. La destruction progressive des LT CD4+ (sur plusieurs annees) effondre la reponse immunitaire adaptative. Le SIDA est le stade final ou les infections opportunistes (normalement benignes) deviennent mortelles car il n\'y a plus assez de CD4+ pour orchestrer la defense.' },
                    { question: 'Qu\'est-ce que le CMH et son role ?', answer: 'Le Complexe Majeur d\'Histocompatibilite (CMH) = glycoproteines membranaires qui presentent des peptides antigeniques aux lymphocytes T. CMH I : present sur TOUTES les cellules nucleees, presente aux T CD8+ (montre ce qui se passe "a l\'interieur"). CMH II : present uniquement sur les CPA (macrophages, cellules dendritiques, lymphocytes B), presente aux T CD4+. 💡 ASTUCE MEMO : CMH I = vitrine de TOUTE cellule (si un virus y apparait = destruction). CMH II = rapport des CPA au "chef" (T CD4+).' },
                    { question: 'Qu\'est-ce que les groupes sanguins ABO ?', answer: 'Le systeme ABO depend des antigenes presents sur les globules rouges. Groupe A : antigene A (anticorps anti-B). Groupe B : antigene B (anticorps anti-A). Groupe AB : antigenes A et B (aucun anticorps = receveur universel). Groupe O : aucun antigene (anticorps anti-A et anti-B = donneur universel). 🧠 TRUC POUR RETENIR : Tu as les ANTIGENES de ton groupe et les ANTICORPS contre les AUTRES groupes !' },
                    { question: 'Qu\'est-ce qu\'une allergie ?', answer: 'L\'allergie est une reaction immunitaire EXCESSIVE et INAPPROPRIEE contre un antigene normalement inoffensif (allergene : pollen, acariens, arachides). Lors du premier contact, des IgE sont produites et se fixent sur les mastocytes. Au second contact, les allergenes pontent les IgE, les mastocytes degranulement (liberation massive d\'histamine) = vasodilatation, bronchospasme, urticaire. Cas extreme : choc anaphylactique (potentiellement mortel).' },
                    { question: 'Qu\'est-ce qu\'une maladie auto-immune ?', answer: 'Une maladie auto-immune survient quand le systeme immunitaire attaque les PROPRES cellules de l\'organisme (perte de la tolerance au soi). Le systeme immunitaire ne distingue plus le soi du non-soi. Exemples : diabete de type 1 (destruction des cellules beta du pancreas), sclerose en plaques (destruction de la myeline), lupus (anticorps anti-ADN). 🤯 Le savais-tu ? 5 a 8% de la population mondiale souffre d\'une maladie auto-immune, et les femmes sont 2 a 3 fois plus touchees que les hommes.' },
                    { question: 'Qu\'est-ce que l\'immunite collective ?', answer: 'L\'immunite collective (ou de groupe) est atteinte quand une proportion suffisante de la population est immunisee (par vaccination ou infection), freinant la circulation du pathogene et protegeant indirectement les personnes non vaccinees (nourrissons, immunodeprimes). Le seuil depend de la contagiosite (R0) : rougeole = 95% necessaire, grippe = ~70%. C\'est un enjeu de sante publique majeur.' },
                    { question: 'Qu\'est-ce que l\'immunotherapie anti-cancer ?', answer: 'L\'immunotherapie anti-cancer consiste a stimuler le systeme immunitaire du patient pour qu\'il detruise les cellules tumorales. Strategies : 1) Inhibiteurs de checkpoints (anti-PD1, anti-CTLA4) — levent les freins sur les lymphocytes T. 2) Cellules CAR-T (LT modifies genetiquement pour cibler la tumeur). 3) Vaccins anti-cancer. Prix Nobel 2018 (Allison & Honjo). Revolution en oncologie ! 🤯 Le savais-tu ? Le president Jimmy Carter a ete gueri d\'un melanome metastatique grace a l\'immunotherapie en 2015 !' },
                    { question: 'Comment un vaccin a ARNm fonctionne-t-il ?', answer: 'Un vaccin a ARNm (ex : Pfizer/Moderna contre le COVID) injecte un ARNm synthetique codant une proteine du virus (proteine Spike). Nos cellules traduisent cet ARNm en proteine Spike, qui est presentee au systeme immunitaire. Les lymphocytes T et B specifiques sont actives et des cellules memoire sont creees. L\'ARNm est degrade en quelques jours — il NE s\'integre PAS dans notre ADN. ⚠️ PIEGE BAC : L\'ARNm du vaccin est TEMPORAIRE, il est rapidement degrade par les ribonucleases de la cellule.' },
                    { question: 'Qu\'est-ce que les IST (Infections Sexuellement Transmissibles) ?', answer: 'Les IST se transmettent lors de rapports sexuels (contacts muqueux). Exemples : VIH/SIDA (virus, retrovirus), chlamydia (bacterie, souvent asymptomatique), herpes genital (virus HSV), HPV (papillomavirus, risque de cancer du col de l\'uterus), syphilis (bacterie Treponema). Prevention : preservatif (seule protection contre le VIH), depistage regulier, vaccination (HPV). L\'information et le depistage sont essentiels.' },
                    { question: 'Qu\'est-ce que le systeme du complement ?', answer: 'Le complement est un ensemble d\'une trentaine de proteines plasmatiques circulant sous forme inactive. Quand activees (par anticorps ou pathogenes), elles declenchent une cascade : 1) Complexe d\'attaque membranaire (MAC) qui PERFORE les pathogenes. 2) Opsonisation (facilite la phagocytose). 3) Chimiotactisme (attraction des phagocytes). Le complement fait le pont entre immunite innee et adaptative.' },
                    { question: 'Qu\'est-ce que la tolerance immunitaire et la selection negative ?', answer: 'La tolerance immunitaire est la capacite a NE PAS attaquer le soi. Elle s\'etablit pendant le developpement des lymphocytes : dans le THYMUS (LT) et la MOELLE OSSEUSE (LB), les lymphocytes auto-reactifs sont elimines = SELECTION NEGATIVE. Seuls les lymphocytes qui reconnaissent le non-soi survivent. Si cette tolerance est rompue → maladie auto-immune. 💡 ASTUCE MEMO : Le thymus est l\'ecole des LT — ceux qui "attaquent les copains" (le soi) sont exclus !' },
                    { question: 'Qu\'est-ce qu\'une CPA et son role ?', answer: 'Les CPA (Cellules Presentatrices d\'Antigene) sont des cellules qui "montrent" les fragments de pathogene aux lymphocytes T via le CMH II. Principales CPA : cellules dendritiques (les plus efficaces), macrophages et lymphocytes B. Elles phagocytent le pathogene, le degradent et presentent ses peptides aux LT CD4+ dans les ganglions lymphatiques. C\'est le LIEN entre immunite innee et adaptative.' },
                    { question: 'Qu\'est-ce que le microbiote et son role immunitaire ?', answer: 'Le microbiote = ensemble des micro-organismes vivant sur et dans notre corps (100 000 milliards de bacteries intestinales !). Roles immunitaires : 1) Barriere contre les pathogenes (competition). 2) Education du systeme immunitaire. 3) Production de substances antimicrobiennes. Un desequilibre (dysbiose) est associe a allergies, obesite, maladies auto-immunes. 🤯 Le savais-tu ? Tu as autant de bacteries que de cellules humaines — tu es autant "bacterien" qu\'humain !' },
                    { question: 'Qu\'est-ce que la serotherapie et en quoi differe-t-elle de la vaccination ?', answer: 'La serotherapie injecte des anticorps DEJA FORMES pour un traitement d\'urgence. C\'est une immunite PASSIVE, IMMEDIATE mais TEMPORAIRE (anticorps degrades en semaines). La vaccination declenche une immunite ACTIVE : le corps fabrique SES PROPRES anticorps et des cellules memoire (protection durable). Exemples de serotherapie : serum antivenimeux (morsure serpent), serum antitetanique. ⚠️ PIEGE BAC : Vaccination = ACTIF (le corps travaille). Serotherapie = PASSIF (anticorps fournis tout faits).' },
                    { question: 'Comment le VIH echappe-t-il au systeme immunitaire ?', answer: 'Le VIH utilise plusieurs strategies : 1) Mutation RAPIDE (la transcriptase inverse fait des erreurs, creant des variantes). 2) Destruction des LT CD4+ (cible le chef d\'orchestre). 3) Integration dans le genome (provirus LATENT, invisible). 4) Faible expression du CMH sur les cellules infectees. C\'est pourquoi il n\'existe toujours pas de vaccin efficace malgre 40 ans de recherche.' },
                    { question: 'Qu\'est-ce que les cytokines et leur role ?', answer: 'Les cytokines sont des molecules de communication secretees par les cellules immunitaires. Types principaux : 1) INTERLEUKINES : communication entre leucocytes (IL-2 active les LT, IL-4 active les LB). 2) INTERFERONS : defense antivirale (empechent la replication virale dans les cellules voisines). 3) TNF (Tumor Necrosis Factor) : inflammation et destruction des tumeurs. 4) CHIMIOKINES : attraction des cellules immunitaires vers le site d\'infection. Les cytokines coordonnent toute la reponse immunitaire. 🧠 TRUC POUR RETENIR : Les cytokines sont les "SMS" du systeme immunitaire — elles permettent aux cellules de communiquer a distance.' },
                    { question: 'Qu\'est-ce que le systeme ABO et le facteur Rhesus ?', answer: 'Le systeme ABO depend des antigenes sur les globules rouges (A, B, AB, O) et des anticorps naturels anti-A et anti-B. Le facteur RHESUS (Rh) est un autre systeme : Rh+ (possede l\'antigene D) ou Rh- (ne le possede pas). Importance : en transfusion, il faut respecter la compatibilite pour eviter l\'agglutination (destruction des globules rouges par les anticorps du receveur). En grossesse, une mere Rh- portant un foetus Rh+ peut developper des anticorps anti-Rh dangereux pour les grossesses suivantes (maladie hemolytique du nouveau-ne). ⚠️ PIEGE BAC : Le groupe O n\'est pas "sans antigene" — il possede l\'antigene H. Mais il est considere donneur universel car il n\'a ni A ni B.' },
                    { question: 'Qu\'est-ce que la fievre et son role immunitaire ?', answer: 'La fievre est une AUGMENTATION controlee de la temperature corporelle, declenchee par les pyrogenes (cytokines comme IL-1 et IL-6 qui agissent sur l\'hypothalamus). La fievre n\'est PAS une maladie mais une DEFENSE : 1) Elle accelere les reactions immunitaires (phagocytose, proliferation des lymphocytes). 2) Elle ralentit la multiplication de nombreux pathogenes (bacteries et virus se reproduisent moins bien a 39°C). 3) Elle augmente la production d\'interferons. La fievre est donc un ALLIE de l\'immunite (sauf si elle depasse 40°C).' },
                    { question: 'Qu\'est-ce que la tritherapie anti-VIH ?', answer: 'La tritherapie (ou traitement antiretroviral = ARV) combine TROIS medicaments ciblant differentes etapes du cycle du VIH : 1) Inhibiteurs de la transcriptase inverse (empechent la copie de l\'ARN viral en ADN). 2) Inhibiteurs de protease (empechent la maturation des proteines virales). 3) Inhibiteurs d\'integrase (empechent l\'integration de l\'ADN viral dans le genome). Resultat : charge virale INDETECTABLE, le patient ne transmet plus le virus (I=I : Indetectable = Intransmissible). Ce n\'est pas une guerison mais un controle efficace.' },
                    { question: 'Qu\'est-ce que les PAMP et les PRR ?', answer: 'Les PAMP (Pathogen-Associated Molecular Patterns) sont des motifs moleculaires CONSERVES chez les pathogenes (LPS des bacteries gram-, flagelline, ADN viral double brin, etc.). Ils sont reconnus par les PRR (Pattern Recognition Receptors) des cellules de l\'immunite innee (macrophages, cellules dendritiques). Les plus connus sont les TLR (Toll-Like Receptors). C\'est un systeme de reconnaissance RAPIDE et NON SPECIFIQUE — les PRR reconnaissent des "signatures" generales de pathogenes, pas des antigenes specifiques. 💡 ASTUCE MEMO : PAMP = la "carte d\'identite" des microbes. PRR = le "lecteur de carte" des cellules sentinelles.' },
                    { question: 'Qu\'est-ce que le thymus et pourquoi est-il essentiel ?', answer: 'Le thymus est un organe lymphoide situe derriere le sternum. C\'est l\'ecole de maturation des lymphocytes T (T = Thymus !). Les lymphocytes T immatures y subissent deux selections : 1) SELECTION POSITIVE : seuls les LT qui reconnaissent le CMH du soi survivent. 2) SELECTION NEGATIVE : les LT auto-reactifs (qui attaquent le soi) sont elimines (apoptose). Resultat : seuls les LT competents et tolerants sont liberes dans le sang. Le thymus est tres actif chez l\'enfant et s\'atrophie avec l\'age (involution thymique).' },
                    { question: 'Qu\'est-ce que l\'inflammation chronique et ses consequences ?', answer: 'Contrairement a l\'inflammation aigue (reponse normale et temporaire), l\'inflammation CHRONIQUE est une inflammation persistante qui endommage les tissus. Causes : infection persistante, maladie auto-immune, exposition continue a un irritant (tabac), obesite (tissu adipeux secrete des cytokines inflammatoires). Consequences : fibrose, destruction tissulaire, et surtout AUGMENTATION du risque de cancer, maladies cardiovasculaires et neurodegeneratives. L\'inflammation chronique est surnommee le "tueur silencieux".' },
                    { question: 'Qu\'est-ce que le rejet de greffe et comment le prevenir ?', answer: 'Le rejet de greffe est la reaction du systeme immunitaire du receveur contre les cellules du greffon, reconnues comme "etrangeres" (CMH different). Les LT CD8+ attaquent les cellules du greffon. Prevention : 1) TYPAGE HLA (choisir un donneur le plus compatible possible — les jumeaux identiques sont les meilleurs donneurs). 2) Traitement IMMUNOSUPPRESSEUR a vie (cyclosporine, tacrolimus) pour empecher le rejet. Inconvenient : augmente la vulnerabilite aux infections et aux cancers.' },
                    { question: 'Qu\'est-ce que la maturation d\'affinite des anticorps ?', answer: 'Lors de la reponse immunitaire, les lymphocytes B subissent des HYPERMUTATIONS SOMATIQUES dans les centres germinatifs des ganglions (mutations aleatoires des genes des anticorps). Les LB dont les anticorps se lient MIEUX a l\'antigene sont selectionnes (selection positive). Au fil des divisions, la qualite (affinite) des anticorps AUGMENTE. C\'est pourquoi la reponse secondaire produit des anticorps de MEILLEURE AFFINITE que la reponse primaire. C\'est un mini-processus d\'evolution par selection !' },
                    { question: 'Qu\'est-ce que l\'immunodeficience et ses types ?', answer: 'L\'immunodeficience est un deficit du systeme immunitaire. Types : 1) PRIMAIRE (genetique, congenitale) : DICS (enfants-bulles — absence de LT et LB), deficit en IgA, agammaglobulinemie de Bruton. 2) ACQUISE : VIH/SIDA (destruction des LT CD4+), traitements immunosuppresseurs (greffes, auto-immunite), malnutrition, stress chronique. L\'immunodeprime est vulnerabie aux infections OPPORTUNISTES (normalement benignes). 💡 ASTUCE MEMO : Primaire = defaut de NAISSANCE (gene defectueux). Acquise = defaut APPRIS (virus, medicament, mode de vie).' },
                    { question: 'Qu\'est-ce que les anticorps monoclonaux ?', answer: 'Les anticorps monoclonaux sont des anticorps identiques produits par un SEUL clone de lymphocyte B. Ils ciblent un SEUL epitope specifique. Fabrication : technique des hybridomes (fusion LB + cellule myelomateuse immortelle). Applications medicales revolutionnaires : traitement de cancers (trastuzumab/Herceptin contre le cancer du sein HER2+), maladies auto-immunes (adalimumab anti-TNF), diagnostic (tests rapides). Leur nom finit toujours par "-mab" (Monoclonal AntiBodies).' },
                    { question: 'Qu\'est-ce que le choc anaphylactique ?', answer: 'Le choc anaphylactique est la forme la plus grave et la plus rapide de reaction allergique. C\'est une URGENCE VITALE. Mecanisme : degranulation MASSIVE et GENERALISEE des mastocytes → liberation d\'histamine dans tout le corps → vasodilatation generalisee (chute de tension), bronchospasme severe (difficulte a respirer), oedeme (gonflement des voies aeriennes). Peut etre fatal en minutes. Traitement : injection d\'ADRENALINE (stylo auto-injecteur type EpiPen) + appel au 15/SAMU.' }
                ],
                quiz: [
                    { question: 'La phagocytose est realisee par :', options: ['Les lymphocytes B', 'Les macrophages et granulocytes neutrophiles', 'Les lymphocytes T CD8+', 'Les plasmocytes'], correctIndex: 1, explanation: 'La phagocytose est assuree par les phagocytes : macrophages, granulocytes neutrophiles et cellules dendritiques. Ils ingèrent et digerent les pathogenes.' },
                    { question: 'Les anticorps sont produits par :', options: ['Les lymphocytes T CD4+', 'Les macrophages', 'Les plasmocytes (lymphocytes B differencies)', 'Les cellules dendritiques'], correctIndex: 2, explanation: 'Les anticorps sont secretes par les plasmocytes, qui sont des lymphocytes B ayant subi une selection clonale et une differenciation apres contact avec l\'antigene.' },
                    { question: 'La reaction inflammatoire est une composante de :', options: ['L\'immunite adaptative', 'L\'immunite innee', 'La reponse humorale', 'La reponse cellulaire cytotoxique'], correctIndex: 1, explanation: 'La reaction inflammatoire est une reponse rapide et non specifique, caracteristique de l\'immunite innee. Elle fait intervenir les cellules sentinelles et les mediateurs chimiques.' },
                    { question: 'Les lymphocytes T CD8+ detruisent les cellules cibles en liberant :', options: ['Des anticorps', 'Des histamines', 'De la perforine et des granzymes', 'Des interleukines uniquement'], correctIndex: 2, explanation: 'Les T CD8+ liberent de la perforine (cree des pores dans la membrane) et des granzymes (declenchent l\'apoptose). Ils tuent par contact direct = reponse cellulaire.' },
                    { question: 'Le VIH infecte principalement :', options: ['Les globules rouges', 'Les lymphocytes T CD4+', 'Les neurones', 'Les cellules musculaires'], correctIndex: 1, explanation: 'Le VIH se fixe sur le recepteur CD4 des lymphocytes T CD4+ (et le corecepteur CCR5/CXCR4). La destruction progressive des CD4+ effondre l\'immunite adaptative, menant au SIDA.' },
                    { question: 'L\'immunite collective est atteinte quand :', options: ['Tous les individus sont vaccines', 'Un seul individu est immunise', 'Une proportion suffisante de la population est immunisee', 'Les anticorps sont presents dans l\'environnement'], correctIndex: 2, explanation: 'Quand suffisamment d\'individus sont immunises (seuil dependant du R0), la propagation du pathogene est reduite, protegeant indirectement les personnes non vaccinees.' },
                    { question: 'La selection clonale concerne :', options: ['Tous les lymphocytes sans distinction', 'Uniquement les lymphocytes specifiques de l\'antigene', 'Les phagocytes uniquement', 'Les globules rouges'], correctIndex: 1, explanation: 'Seuls les lymphocytes dont les recepteurs reconnaissent l\'antigene sont selectionnes, actives et proliferent pour combattre specifiquement ce pathogene.' },
                    { question: 'Un vaccin a ARNm :', options: ['Modifie l\'ADN du patient', 'Injecte le virus vivant entier', 'Fait produire une proteine virale par nos cellules', 'Contient des anticorps prets a l\'emploi'], correctIndex: 2, explanation: 'Le vaccin ARNm fournit le "plan" (ARNm) pour que nos propres cellules fabriquent la proteine virale (ex : Spike), declenchant une reponse immunitaire. L\'ARNm est ensuite degrade.' },
                    { question: 'Une maladie auto-immune est causee par :', options: ['Un virus tres virulent', 'Le systeme immunitaire qui attaque les propres cellules du corps', 'Un deficit en globules rouges', 'L\'absence de microbiote'], correctIndex: 1, explanation: 'Les maladies auto-immunes resultent d\'une perte de tolerance au soi : le systeme immunitaire attaque les tissus de l\'organisme (ex : diabete de type 1, sclerose en plaques).' },
                    { question: 'L\'histamine provoque :', options: ['La vasoconstriction', 'La vasodilatation et l\'augmentation de la permeabilite vasculaire', 'La production d\'anticorps', 'La destruction des cellules infectees'], correctIndex: 1, explanation: 'L\'histamine, liberee par les mastocytes, provoque la vasodilatation et l\'augmentation de la permeabilite vasculaire, favorisant l\'arrivee des cellules immunitaires au site de l\'infection.' },
                    { question: 'Le CMH de classe I est present sur :', options: ['Uniquement les cellules immunitaires', 'Toutes les cellules nucleees de l\'organisme', 'Uniquement les globules rouges', 'Uniquement les neurones'], correctIndex: 1, explanation: 'Le CMH I est exprime par toutes les cellules nucleees. Il presente des peptides intracellulaires aux LT CD8+. Si une cellule est infectee, les peptides viraux sont presentes et la cellule est detruite.' },
                    { question: 'Le groupe sanguin O est dit donneur universel car :', options: ['Il possede les antigenes A et B', 'Il ne possede ni antigene A ni antigene B sur les globules rouges', 'Il n\'a pas d\'anticorps', 'Ses globules rouges sont plus petits'], correctIndex: 1, explanation: 'Les globules rouges du groupe O n\'ont ni antigene A ni B a leur surface, donc ils ne sont pas reconnus et detruits par les anticorps anti-A ou anti-B du receveur.' },
                    { question: 'L\'immunotherapie anti-cancer par inhibiteurs de checkpoints :', options: ['Detruit directement les cellules tumorales', 'Leve les freins qui empechent les lymphocytes T d\'attaquer la tumeur', 'Injecte des virus dans la tumeur', 'Bloque la division des cellules normales'], correctIndex: 1, explanation: 'Les inhibiteurs de checkpoints (anti-PD1, anti-CTLA4) levent les mecanismes de freinage que les tumeurs exploitent pour echapper aux lymphocytes T, permettant une attaque immunitaire efficace.' },
                    { question: 'Lors d\'une allergie, la degranulation des mastocytes est declenchee par :', options: ['Les lymphocytes T CD8+', 'Le pontage des IgE fixees par l\'allergene', 'La phagocytose', 'Le complement seul'], correctIndex: 1, explanation: 'Les IgE specifiques se fixent sur les mastocytes. Au contact de l\'allergene, celui-ci ponte les IgE, ce qui declenche la degranulation massive (histamine) = reaction allergique.' },
                    { question: 'La reponse immunitaire secondaire est :', options: ['Plus lente que la primaire', 'Identique a la primaire', 'Plus rapide, plus intense et plus durable', 'Independante de la memoire immunitaire'], correctIndex: 2, explanation: 'Grace aux cellules memoire, la reponse secondaire est declenchee en 1-2 jours (vs 5-7), produit plus d\'anticorps et de meilleure affinite. C\'est le principe de la vaccination.' },
                    { question: 'La serotherapie confere une immunite :', options: ['Active et durable', 'Passive et temporaire', 'Active et temporaire', 'Passive et permanente'], correctIndex: 1, explanation: 'La serotherapie injecte des anticorps tout faits = immunite PASSIVE (le corps ne produit rien) et TEMPORAIRE (anticorps degrades en semaines). Contrairement a la vaccination = active et durable.' },
                    { question: 'Le complement est :', options: ['Un type de lymphocyte', 'Un ensemble de proteines plasmatiques formant une cascade de defense', 'Un organe lymphoide', 'Un type d\'anticorps'], correctIndex: 1, explanation: 'Le complement est une trentaine de proteines circulantes. Une fois activees en cascade, elles perforent les pathogenes (MAC), facilitent la phagocytose (opsonisation) et attirent les cellules immunitaires.' },
                    { question: 'Les cellules dendritiques sont particulierement efficaces pour :', options: ['Produire des anticorps', 'Presenter les antigenes aux lymphocytes T', 'Secreter de l\'histamine', 'Detruire les cellules cancereuses directement'], correctIndex: 1, explanation: 'Les cellules dendritiques sont les meilleures CPA (Cellules Presentatrices d\'Antigene). Elles capturent les pathogenes, migrent vers les ganglions et activent les LT CD4+ via le CMH II. Pont cle entre immunite innee et adaptative.' },
                    { question: 'Le microbiote intestinal :', options: ['N\'a aucun role immunitaire', 'Participe a l\'education du systeme immunitaire et protege contre les pathogenes', 'Est compose uniquement de virus', 'Disparait a l\'age adulte'], correctIndex: 1, explanation: 'Le microbiote (100 000 milliards de bacteries) eduque le systeme immunitaire, empeche la colonisation par les pathogenes et produit des substances antimicrobiennes. Sa perturbation est liee a de nombreuses maladies.' },
                    { question: 'Le VIH est un retrovirus car :', options: ['Il se transmet par voie aerienne', 'Son genome est en ARN et il utilise la transcriptase inverse pour fabriquer de l\'ADN', 'Il n\'a pas de genome', 'Il ne peut infecter que les animaux'], correctIndex: 1, explanation: 'Le VIH possede un genome a ARN. Apres infection, sa transcriptase inverse convertit l\'ARN viral en ADN, qui s\'integre dans le genome de la cellule hote (provirus). C\'est la definition d\'un retrovirus (retro = en arriere).' },
                    { question: 'Les cytokines sont :', options: ['Des anticorps', 'Des molecules de communication secretees par les cellules immunitaires', 'Des antigenes', 'Des globules rouges'], correctIndex: 1, explanation: 'Les cytokines (interleukines, interferons, TNF, chimiokines) sont des molecules de signalisation qui coordonnent la reponse immunitaire entre les cellules. Elles sont les "SMS" du systeme immunitaire.' },
                    { question: 'La fievre est :', options: ['Toujours dangereuse et a combattre', 'Un mecanisme de defense qui accelere les reactions immunitaires', 'Causee par les antibiotiques', 'Un signe que le systeme immunitaire ne fonctionne pas'], correctIndex: 1, explanation: 'La fievre est une DEFENSE : elle accelere la phagocytose, la proliferation des lymphocytes et ralentit la multiplication des pathogenes. Elle n\'est dangereuse qu\'au-dessus de 40°C.' },
                    { question: 'Le thymus est le lieu de maturation :', options: ['Des lymphocytes B', 'Des lymphocytes T', 'Des macrophages', 'Des globules rouges'], correctIndex: 1, explanation: 'Le thymus est l\'organe ou les lymphocytes T immatures subissent leur selection (positive puis negative). T = Thymus ! Il est actif surtout chez l\'enfant et s\'atrophie avec l\'age.' },
                    { question: 'Les PAMP sont reconnus par les PRR de l\'immunite :', options: ['Adaptative', 'Innee', 'Humorale uniquement', 'Passive'], correctIndex: 1, explanation: 'Les PAMP (motifs moleculaires des pathogenes) sont reconnus par les PRR (recepteurs de l\'immunite innee, comme les TLR) des macrophages et cellules dendritiques. C\'est une reconnaissance rapide et non specifique.' }
                ]
            },

            // ===== SECTION 5 : ECOLOGIE & ENVIRONNEMENT =====
            {
                id: 'ecologie',
                title: 'Ecologie et environnement',
                icon: '\uD83C\uDF3F',
                content: '<h3>Ecosystemes et biodiversite</h3>'
                    + '<ul>'
                    + '<li><strong>Ecosysteme</strong> = biocenose (etres vivants) + biotope (milieu physico-chimique)</li>'
                    + '<li><strong>Biodiversite</strong> : genetique, specifique, ecosystemique</li>'
                    + '<li><strong>Espece</strong> : ensemble d\'individus interfeconds avec descendance fertile (Mayr)</li>'
                    + '</ul>'
                    + '<h3>Relations trophiques et cycles</h3>'
                    + '<ul>'
                    + '<li><strong>Producteurs</strong> → <strong>Consommateurs</strong> → <strong>Decomposeurs</strong></li>'
                    + '<li><strong>Rendement ecologique</strong> : ~10% entre niveaux trophiques</li>'
                    + '<li><strong>Cycles biogeochimiques</strong> : carbone, azote, eau</li>'
                    + '</ul>'
                    + '<h3>Changement climatique et impact humain</h3>'
                    + '<ul>'
                    + '<li><strong>Effet de serre renforce</strong> par les emissions anthropiques (CO2, CH4, N2O)</li>'
                    + '<li><strong>6eme extinction</strong> : destruction des habitats, surexploitation, pollution, especes invasives</li>'
                    + '<li><strong>Solutions</strong> : developpement durable, energies renouvelables, economie circulaire</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Qu\'est-ce qu\'un ecosysteme ?', answer: 'Un ecosysteme est l\'ensemble forme par une BIOCENOSE (communaute d\'etres vivants : animaux, vegetaux, micro-organismes) et un BIOTOPE (milieu physico-chimique : sol, eau, climat, lumiere) en interaction. Les etres vivants interagissent entre eux (predation, competition, symbiose) et avec leur milieu. 💡 ASTUCE MEMO : ECOSYSTEME = BIO + TOPE. BIOcenose = le VIVANT (bio=vie). BIOtope = le LIEU (topos=lieu en grec).' },
                    { question: 'Quelles sont les trois echelles de la biodiversite ?', answer: 'La biodiversite genetique (diversite des alleles au sein d\'une espece — ex : differentes couleurs de cheveux), la biodiversite specifique (diversite des especes dans un ecosysteme — ex : 8-10 millions d\'especes estimees, 1,8 million decrites) et la biodiversite ecosystemique (diversite des ecosystemes — forets, oceans, deserts). 🤯 Le savais-tu ? On decouvre encore environ 18 000 nouvelles especes par an, surtout des insectes et dans les forets tropicales !' },
                    { question: 'Qu\'est-ce qu\'un reseau trophique ?', answer: 'Un reseau trophique est l\'ensemble des relations alimentaires interconnectees dans un ecosysteme. Il relie les producteurs primaires (autotrophes : plantes, phytoplancton), les consommateurs (herbivores C1, carnivores C2-C3) et les decomposeurs. Contrairement a une chaine alimentaire simple et lineaire, un reseau trophique montre la COMPLEXITE des interactions (un organisme peut etre mange par plusieurs predateurs).' },
                    { question: 'Pourquoi la biomasse diminue-t-elle a chaque niveau trophique ?', answer: 'A chaque niveau trophique, environ 90% de l\'energie est perdue sous forme de chaleur (respiration cellulaire), de dechets et de matiere non assimilee. Seuls ~10% sont transferes au niveau suivant. C\'est pourquoi les chaines alimentaires comptent rarement plus de 4-5 niveaux. 💡 ASTUCE MEMO : Imaginer un escalier ou tu perds 90% de ton energie a chaque marche — au bout de 4-5 marches, il ne reste presque plus rien !' },
                    { question: 'Qu\'est-ce que l\'effet de serre et pourquoi est-il problematique ?', answer: 'L\'effet de serre NATUREL est vital : les gaz (CO2, H2O, CH4) absorbent le rayonnement infrarouge reemis par la Terre, rechauffant l\'atmosphere (15°C au lieu de -18°C). Le PROBLEME : les activites humaines (combustion fossile, deforestation, elevage) augmentent ces gaz, renforcant l\'effet de serre = rechauffement climatique. Depuis 1850, la temperature moyenne a augmente de ~1,2°C. 🤯 Le savais-tu ? La derniere fois que le CO2 atmospherique etait aussi eleve qu\'aujourd\'hui (420 ppm), c\'etait il y a 3 millions d\'annees — le niveau des mers etait 15 a 25 metres plus haut !' },
                    { question: 'Decrire les grandes etapes du cycle du carbone.', answer: 'Photosynthese : les vegetaux fixent le CO2 en matiere organique. Respiration : les etres vivants liberent du CO2. Decomposition : les decomposeurs mineralisent la matiere organique. Combustion des fossiles : libere le carbone stocke depuis des millions d\'annees. Sedimentation : piege le carbone dans les roches calcaires. Dissolution oceanique : les oceans absorbent ~25% du CO2 emis. ⚠️ PIEGE BAC : L\'ocean est le plus grand RESERVOIR de carbone apres la lithosphere, pas l\'atmosphere !' },
                    { question: 'Quelles sont les causes de l\'erosion de la biodiversite ?', answer: '5 causes majeures (memorise-les avec DSPEI) : 1) Destruction des habitats (deforestation, urbanisation — cause n°1). 2) Surexploitation (surpeche, braconnage). 3) Pollution (pesticides, plastiques, perturbateurs endocriniens). 4) Especes invasives (competition, predation). 5) Changement climatique (modification des aires de repartition). 💡 ASTUCE MEMO : DSPEI = "Destruction, Surexploitation, Pollution, Especes invasives, (changement clImatique)".' },
                    { question: 'Qu\'est-ce qu\'un service ecosystemique ?', answer: 'Un service ecosystemique est un benefice que les societes humaines tirent GRATUITEMENT du fonctionnement des ecosystemes. 4 categories : 1) Approvisionnement (nourriture, eau douce, bois, medicaments). 2) Regulation (pollinisation, epuration de l\'eau, regulation du climat). 3) Culturels (loisirs, esthetique, spiritualite). 4) Support (formation des sols, photosynthese, cycle des nutriments). 🤯 Le savais-tu ? La valeur des services ecosystemiques mondiaux est estimee a 125 000 milliards de dollars par an — soit plus que le PIB mondial !' },
                    { question: 'Decrire le cycle de l\'azote.', answer: 'L\'azote atmospherique (N2, 78% de l\'air) est INERTE — les plantes ne peuvent pas l\'utiliser directement. 1) Fixation : bacteries fixatrices (Rhizobium, cyanobacteries) transforment N2 en NH4+ (ammonium). 2) Nitrification : bacteries transforment NH4+ en NO3- (nitrates) assimilables par les plantes. 3) Assimilation : les plantes absorbent les NO3-. 4) Decomposition : retour de l\'azote organique au sol. 5) Denitrification : bacteries retransforment NO3- en N2. 💡 ASTUCE MEMO : L\'azote fait un CYCLE complet : air → sol → plante → animal → decomposition → sol → air.' },
                    { question: 'Qu\'est-ce que l\'empreinte ecologique ?', answer: 'L\'empreinte ecologique mesure la surface de terre et d\'eau biologiquement productives necessaires pour produire les ressources qu\'une personne consomme et absorber ses dechets. Elle s\'exprime en hectares globaux (gha). Si tout le monde vivait comme un Francais, il faudrait 2,9 planetes. Comme un Americain : 5 planetes. Le "Jour du depassement" (Earth Overshoot Day) marque la date ou l\'humanite a consomme toutes les ressources que la Terre peut regenerer en un an (en 2025 : debut aout).' },
                    { question: 'Qu\'est-ce que le developpement durable ?', answer: 'Le developpement durable est un developpement qui repond aux besoins du present sans compromettre la capacite des generations futures a repondre aux leurs (rapport Brundtland, 1987). Il repose sur 3 piliers : economique (croissance viable), social (equite, acces aux droits) et environnemental (preservation des ecosystemes). En 2015, l\'ONU a adopte 17 Objectifs de Developpement Durable (ODD) pour 2030.' },
                    { question: 'Qu\'est-ce que le cycle de l\'eau ?', answer: 'Le cycle de l\'eau comprend : evaporation (oceans, lacs → vapeur d\'eau), transpiration des plantes (evapotranspiration), condensation (formation de nuages), precipitations (pluie, neige), ruissellement (vers les cours d\'eau), infiltration (vers les nappes souterraines). L\'eau douce ne represente que 2,5% de l\'eau totale, et seulement 0,7% est accessible. Le cycle de l\'eau est le moteur fondamental de la vie sur Terre.' },
                    { question: 'Qu\'est-ce qu\'une espece invasive et pourquoi est-ce un probleme ?', answer: 'Une espece invasive est une espece introduite (volontairement ou non) dans un milieu dont elle n\'est pas originaire, qui se propage et cause des dommages ecologiques. Elle entre en competition avec les especes locales, peut transmettre des maladies et modifier l\'ecosysteme. Exemples : ecrevisse de Louisiane, jussie, frelon asiatique (menace les abeilles), renouee du Japon. 🤯 Le savais-tu ? Les especes invasives sont la 2eme cause d\'extinction mondiale, juste apres la destruction des habitats !' },
                    { question: 'Qu\'est-ce que la photosynthese et pourquoi est-elle fondamentale ?', answer: 'La photosynthese (6 CO2 + 6 H2O → C6H12O6 + 6 O2) convertit l\'energie lumineuse en matiere organique. Elle est FONDAMENTALE car : 1) Elle est a la base de presque toutes les chaines alimentaires (producteurs primaires). 2) Elle produit l\'O2 atmospherique (respiration des etres vivants). 3) Elle fixe le CO2 (regulation du climat). Sans photosynthese, pas de vie complexe sur Terre !' },
                    { question: 'Qu\'est-ce que l\'acidification des oceans ?', answer: 'L\'acidification des oceans est la diminution du pH des eaux marines due a l\'absorption du CO2 atmospherique excedentaire. Le CO2 dissous dans l\'eau forme de l\'acide carbonique (H2CO3). Consequences : les coraux et coquillages ne peuvent plus fabriquer leur squelette calcaire (dissolution du CaCO3), perturbation des ecosystemes marins. Le pH a deja diminue de 0,1 unite depuis 1850 (soit +26% d\'acidite). C\'est l\'autre crise du CO2, moins connue que le rechauffement.' },
                    { question: 'Qu\'est-ce qu\'une boucle de retroaction positive dans le changement climatique ?', answer: 'Une boucle de retroaction positive AMPLIFIE le changement initial. Exemples : 1) Fonte des glaces → moins de reflexion (albedo) → plus d\'absorption de chaleur → plus de fonte. 2) Degel du permafrost → liberation de methane (CH4) → plus d\'effet de serre → plus de degel. 3) Incendies de foret → liberation de CO2 → plus de rechauffement → plus de secheresse → plus d\'incendies. Ces boucles risquent de creer un "emballement" climatique.' },
                    { question: 'Qu\'est-ce que l\'economie circulaire ?', answer: 'L\'economie circulaire s\'oppose a l\'economie lineaire (extraire-produire-jeter). Elle vise a minimiser les dechets et maximiser la reutilisation des ressources. Principes : reduire la consommation, reutiliser les produits, recycler les materiaux, reparer au lieu de jeter, ecoconception (produits durables et reparables). C\'est un pilier du developpement durable qui s\'inspire du fonctionnement des ecosystemes (ou il n\'y a pas de dechet — tout est recycle par les decomposeurs).' },
                    { question: 'Qu\'est-ce que l\'albedo et pourquoi est-il important ?', answer: 'L\'albedo est le pouvoir reflechissant d\'une surface (0 = absorbe tout, 1 = reflechit tout). Les surfaces claires (glace, neige) ont un albedo eleve (~0,8), les surfaces sombres (ocean, foret) un albedo faible (~0,1). Quand les glaces fondent, l\'albedo diminue → plus d\'absorption de chaleur → plus de fonte = boucle de retroaction positive. C\'est un amplificateur majeur du rechauffement climatique en Arctique.' },
                    { question: 'Qu\'est-ce que la biomagnification (bioaccumulation) ?', answer: 'La biomagnification est la concentration croissante d\'un polluant persistant a chaque niveau trophique de la chaine alimentaire. Exemple classique : le DDT (pesticide). Le phytoplancton absorbe de faibles doses, les petits poissons en accumulent plus, les gros poissons encore plus, et les rapaces en haut de la chaine en accumulent des doses toxiques. 🤯 Le savais-tu ? La biomagnification du DDT a failli causer l\'extinction du pygargue a tete blanche (aigle americain) dans les annees 1960 — coquilles d\'oeufs trop fines !' },
                    { question: 'Qu\'est-ce que la deforestation et ses consequences ?', answer: 'La deforestation est la destruction des forets pour l\'agriculture, l\'elevage, l\'exploitation du bois ou l\'urbanisation. Consequences : 1) Liberation massive de CO2 (le carbone stocke dans les arbres). 2) Perte de biodiversite (les forets tropicales abritent 80% des especes terrestres). 3) Erosion des sols. 4) Perturbation du cycle de l\'eau. 5) Disparition de peuples autochtones. Chaque minute, l\'equivalent de 40 terrains de football de foret disparait.' },
                    { question: 'Qu\'est-ce qu\'un biome ?', answer: 'Un biome est un grand ensemble d\'ecosystemes partageant les memes conditions climatiques et une vegetation similaire. Principaux biomes terrestres : toundra, taiga (foret boreale), foret temperee, prairie/steppe, desert, foret tropicale humide, savane. La repartition des biomes depend de la temperature et des precipitations. 💡 ASTUCE MEMO : Un biome = un "super-ecosysteme" defini par le climat. La foret tropicale = chaud + humide. Le desert = chaud + sec. La toundra = froid + sec.' },
                    { question: 'Qu\'est-ce que l\'eutrophisation ?', answer: 'L\'eutrophisation est l\'enrichissement excessif d\'un milieu aquatique en nutriments (nitrates, phosphates) — souvent d\'origine agricole (engrais). Consequences en chaine : 1) Proliferation d\'algues (bloom). 2) Quand les algues meurent, les decomposeurs consomment tout l\'O2. 3) Le milieu devient anoxique (sans oxygene). 4) Mort des poissons et organismes aquatiques. C\'est la cause des "marees vertes" en Bretagne. Un exemple concret de l\'impact de l\'agriculture sur les ecosystemes.' },
                    { question: 'Qu\'est-ce que les energies renouvelables et pourquoi sont-elles importantes ?', answer: 'Les energies renouvelables sont des sources d\'energie qui se renouvellent naturellement a l\'echelle humaine. Types : solaire (photovoltaique, thermique), eolien, hydraulique, biomasse, geothermie. Contrairement aux energies fossiles (petrole, charbon, gaz — reserves limitees + CO2), elles emettent peu de gaz a effet de serre. 🤯 Le savais-tu ? L\'energie solaire recue par la Terre en 1 heure suffirait a couvrir la consommation energetique mondiale pendant 1 an ! Le defi est de la capter efficacement.' },
                    { question: 'Qu\'est-ce que le plastique et son impact ecologique ?', answer: 'Le plastique est un polymere synthetique derive du petrole. Probleme : il met 100-1000 ans a se degrader et s\'accumule dans les ecosystemes. 8 millions de tonnes de plastique finissent dans les oceans chaque annee. Il se fragmente en microplastiques (<5 mm) ingeres par les organismes marins. Le "7eme continent" est une zone d\'accumulation de plastique dans le Pacifique (1,6 million de km²). Solutions : reduire, reutiliser, recycler, developper des bioplastiques.' },
                    { question: 'Qu\'est-ce que le bilan carbone et la neutralite carbone ?', answer: 'Le bilan carbone mesure la quantite totale de gaz a effet de serre emise par une activite, un produit ou un pays (exprime en tonnes equivalent CO2). La neutralite carbone signifie EQUILIBRER les emissions avec l\'absorption (forets, oceans, captage technologique). La France vise la neutralite carbone en 2050. En moyenne, un Francais emet ~10 tonnes de CO2eq/an. Pour limiter le rechauffement a 1,5°C, il faudrait reduire a 2 tonnes/an/personne.' },
                    { question: 'Qu\'est-ce qu\'une espece cle de voute (keystone species) ?', answer: 'Une espece cle de voute est une espece qui a un impact DISPROPORTIONNE sur son ecosysteme par rapport a son abondance. Sa disparition entrainerait des changements en cascade dans tout l\'ecosysteme. Exemple celebre : la loutre de mer du Pacifique — elle mange les oursins qui mangent les kelps (algues geantes). Sans loutres → explosion d\'oursins → disparition des forets de kelp → effondrement de tout l\'ecosysteme. 🤯 Le savais-tu ? Quand les loups ont ete reintroduits a Yellowstone en 1995, meme le cours des RIVIERES a change — les cerfs ne broutaient plus les berges !' },
                    { question: 'Qu\'est-ce que la photosynthese et la respiration en termes de flux de carbone ?', answer: 'La photosynthese et la respiration sont les deux processus opposes du cycle du carbone. PHOTOSYNTHESE (6CO2 + 6H2O → C6H12O6 + 6O2) : fixe le CO2 atmospherique en matiere organique = PUITS de carbone. RESPIRATION (C6H12O6 + 6O2 → 6CO2 + 6H2O) : libere le CO2 = SOURCE de carbone. A l\'echelle globale, ces deux flux sont naturellement a peu pres equilibres. Le probleme : les emissions fossiles AJOUTENT du CO2 supplementaire que la photosynthese ne peut pas absorber entierement.' },
                    { question: 'Qu\'est-ce que les perturbateurs endocriniens ?', answer: 'Les perturbateurs endocriniens sont des substances chimiques (naturelles ou synthetiques) qui interfèrent avec le systeme hormonal. Ils miment, bloquent ou modifient l\'action des hormones. Exemples : bisphenol A (plastiques), phtalates (cosmetiques), pesticides (DDT, atrazine), parabenes. Effets : infertilite, puberte precoce, cancers hormono-dependants, malformations. Ils agissent a TRES FAIBLES doses et sont particulierement dangereux pour les foetus et les enfants. 🤯 Le savais-tu ? Des traces de perturbateurs endocriniens ont ete retrouvees chez des ours polaires arctiques — preuve de leur ubiquite mondiale !' },
                    { question: 'Qu\'est-ce que l\'agroecologie ?', answer: 'L\'agroecologie est une approche agricole qui s\'inspire des ecosystemes naturels pour produire de la nourriture de facon durable. Principes : diversite des cultures (polyculture vs monoculture), association de plantes (legumineuses fixatrices d\'azote), rotation des cultures, agriculture biologique (sans pesticides chimiques), agroforesterie (arbres + cultures), maintien de la biodiversite du sol. C\'est une alternative a l\'agriculture intensive qui epuise les sols, pollue l\'eau et reduit la biodiversite.' },
                    { question: 'Qu\'est-ce que la fragmentation des habitats ?', answer: 'La fragmentation des habitats est le morcellement d\'un milieu naturel continu en petits ilots isoles (routes, urbanisation, agriculture). Consequences : 1) Reduction de la surface habitable. 2) Isolement des populations (plus de flux de genes = derive genetique, consanguinite). 3) Effet de lisiere (les bordures sont differentes de l\'interieur). 4) Certaines especes ne peuvent plus circuler entre les fragments. Solutions : corridors ecologiques (trame verte et bleue en France) qui reconnectent les fragments.' },
                    { question: 'Qu\'est-ce que le GIEC et quel est son role ?', answer: 'Le GIEC (Groupe d\'experts Intergouvernemental sur l\'Evolution du Climat) = IPCC en anglais. Cree en 1988 par l\'ONU, il reunit des milliers de scientifiques qui evaluent les publications scientifiques sur le changement climatique. Il ne fait PAS de recherche lui-meme mais synthetise l\'etat des connaissances. Ses rapports (environ tous les 6-7 ans) sont la reference mondiale. 6eme rapport (2021-2023) : le rechauffement est "sans equivoque" d\'origine humaine et chaque dixieme de degre compte.' },
                    { question: 'Qu\'est-ce que la niche ecologique ?', answer: 'La niche ecologique est l\'ensemble des conditions environnementales et des ressources qu\'une espece utilise pour vivre et se reproduire. Elle inclut l\'habitat (ou elle vit), le regime alimentaire (ce qu\'elle mange), les interactions avec d\'autres especes, les conditions physico-chimiques tolerees. Deux especes ne peuvent pas occuper EXACTEMENT la meme niche (principe d\'exclusion competitive de Gause). Si leurs niches se chevauchent, la competition est intense et l\'une finit par exclure l\'autre ou par se specialiser.' },
                    { question: 'Qu\'est-ce que la resilience d\'un ecosysteme ?', answer: 'La resilience est la capacite d\'un ecosysteme a retrouver son etat d\'equilibre apres une perturbation (incendie, tempete, pollution). Un ecosysteme tres biodivers est generalement plus resilient (redondance fonctionnelle : si une espece disparait, une autre peut prendre le relais). La perte de biodiversite REDUIT la resilience. 💡 ASTUCE MEMO : La resilience, c\'est comme un filet de securite — plus il y a de mailles (especes), plus il est solide. Enlever des mailles (extinctions) le fragilise.' },
                    { question: 'Qu\'est-ce que la productivite primaire nette d\'un ecosysteme ?', answer: 'La productivite primaire nette (PPN) est la quantite de matiere organique FIXEE par les producteurs primaires (photosynthese) MOINS la quantite CONSOMMEE par leur propre respiration. PPN = photosynthese brute - respiration. Elle s\'exprime en g de carbone/m²/an. Les ecosystemes les plus productifs : forets tropicales humides et recifs coralliens. Les moins productifs : deserts et oceans profonds. La PPN globale terrestre : ~120 GtC/an.' },
                    { question: 'Qu\'est-ce que la symbiose mycorhizienne et son importance ecologique ?', answer: 'La mycorhize est une symbiose mutualiste entre les racines d\'une plante et un champignon. Le champignon fournit eau et mineraux (surtout phosphore) a la plante. La plante fournit des glucides au champignon. MAIS en plus, les mycorhizes connectent les plantes entre elles par un reseau souterrain (le "Wood Wide Web") qui permet le transfert de nutriments et meme de signaux chimiques d\'alerte entre arbres ! 🤯 Le savais-tu ? Les arbres-meres peuvent nourrir leurs jeunes plants via le reseau mycorhizien — c\'est de l\'entraide vegetale !' },
                    { question: 'Qu\'est-ce que le methane (CH4) et pourquoi est-il preoccupant ?', answer: 'Le methane est un gaz a effet de serre 80 fois plus puissant que le CO2 sur 20 ans (28 fois sur 100 ans). Sources : elevage bovin (fermentation enterique et fumier = 1ere source anthropique), rizieres, dechets organiques, exploitation du gaz naturel et du petrole, degel du permafrost. Sa concentration a plus que double depuis 1750. 🤯 Le savais-tu ? Une vache produit environ 100 kg de methane par an — soit l\'equivalent CO2 de rouler 18 000 km en voiture !' }
                ],
                quiz: [
                    { question: 'Un ecosysteme comprend :', options: ['Uniquement les etres vivants', 'Uniquement le milieu physique', 'Les etres vivants (biocenose) et le milieu physique (biotope)', 'Seulement les producteurs et consommateurs'], correctIndex: 2, explanation: 'Un ecosysteme = biocenose (communaute d\'etres vivants) + biotope (milieu physico-chimique). Les interactions entre les deux le definissent.' },
                    { question: 'Les producteurs primaires sont des organismes :', options: ['Heterotrophes', 'Autotrophes', 'Decomposeurs', 'Parasites'], correctIndex: 1, explanation: 'Les producteurs primaires sont autotrophes : ils synthetisent leur matiere organique a partir de matiere minerale (CO2, eau) grace a la photosynthese.' },
                    { question: 'Le rendement ecologique entre deux niveaux trophiques est d\'environ :', options: ['50%', '90%', '10%', '1%'], correctIndex: 2, explanation: 'Environ 10% de l\'energie est transferee au niveau suivant. Les 90% restants sont dissipes en chaleur (respiration) et dechets non assimiles.' },
                    { question: 'Le CO2 est un gaz a effet de serre qui :', options: ['Reflechit la lumiere visible', 'Absorbe le rayonnement infrarouge', 'Absorbe les UV', 'N\'a aucun effet sur le climat'], correctIndex: 1, explanation: 'Le CO2 absorbe le rayonnement infrarouge emis par la Terre et le reemet, contribuant au rechauffement de l\'atmosphere.' },
                    { question: 'La fixation biologique de l\'azote est realisee par :', options: ['Les plantes directement', 'Les champignons', 'Des bacteries specifiques', 'Les animaux herbivores'], correctIndex: 2, explanation: 'Des bacteries fixatrices (Rhizobium, cyanobacteries) transforment N2 en NH4+ grace a l\'enzyme nitrogenase. Les plantes ne peuvent pas fixer N2 directement.' },
                    { question: 'Le principal reservoir de carbone sur Terre est :', options: ['L\'atmosphere', 'Les oceans', 'Les roches carbonatees (lithosphere)', 'La biomasse vegetale'], correctIndex: 2, explanation: 'Les roches carbonatees stockent ~60 millions de GtC, les oceans ~38 000 GtC, l\'atmosphere ~830 GtC et la biomasse ~550 GtC.' },
                    { question: 'L\'empreinte ecologique mesure :', options: ['La taille du pied humain', 'La surface necessaire pour subvenir aux besoins d\'une personne et absorber ses dechets', 'Le nombre d\'especes dans un ecosysteme', 'La quantite de CO2 emise uniquement'], correctIndex: 1, explanation: 'L\'empreinte ecologique mesure la surface bio-productive necessaire pour produire les ressources consommees et absorber les dechets generes.' },
                    { question: 'Les decomposeurs transforment :', options: ['La matiere minerale en matiere organique', 'La matiere organique en matiere minerale', 'Le CO2 en glucose', 'L\'azote en proteines'], correctIndex: 1, explanation: 'Les decomposeurs (bacteries, champignons, vers) mineralisent la matiere organique morte, liberant CO2, H2O et sels mineraux pour boucler les cycles.' },
                    { question: 'Le critere biologique de l\'espece (Mayr) est base sur :', options: ['La ressemblance morphologique', 'L\'interfecondite et la fertilite de la descendance', 'Le milieu de vie commun', 'Le regime alimentaire identique'], correctIndex: 1, explanation: 'Selon Mayr, une espece = individus effectivement ou potentiellement interfeconds produisant une descendance fertile, reproductlvement isoles des autres groupes.' },
                    { question: 'L\'acidification des oceans est causee par :', options: ['Les marees noires', 'L\'absorption de CO2 par l\'eau de mer', 'Le rechauffement seul', 'Les dechets plastiques'], correctIndex: 1, explanation: 'Le CO2 dissous forme de l\'acide carbonique (H2CO3), abaissant le pH oceanique. Cela menace les organismes a squelette calcaire (coraux, mollusques).' },
                    { question: 'Les 3 piliers du developpement durable sont :', options: ['Air, eau, terre', 'Economique, social, environnemental', 'Animaux, vegetaux, humains', 'Passé, present, futur'], correctIndex: 1, explanation: 'Le developpement durable repose sur trois piliers : economique (croissance viable), social (equite) et environnemental (preservation des ecosystemes).' },
                    { question: 'La pollinisation est un exemple de :', options: ['Service d\'approvisionnement', 'Service de regulation', 'Service culturel', 'Service de soutien uniquement'], correctIndex: 1, explanation: 'La pollinisation est un service de regulation ecosystemique assure par les pollinisateurs (abeilles, papillons). 75% des cultures mondiales dependent des pollinisateurs.' },
                    { question: 'Une boucle de retroaction positive dans le climat :', options: ['Stabilise le systeme', 'Amplifie le changement initial', 'Refroidit la Terre', 'N\'a aucun effet'], correctIndex: 1, explanation: 'Une retroaction positive AMPLIFIE le changement : plus de rechauffement → fonte des glaces → moins de reflexion → encore plus de rechauffement. Risque d\'emballement.' },
                    { question: 'Le "Jour du depassement" marque :', options: ['Le jour le plus chaud de l\'annee', 'Le jour ou l\'humanite a consomme les ressources regenerables en un an', 'Le premier jour de l\'ete', 'Le jour ou les stocks de petrole s\'epuisent'], correctIndex: 1, explanation: 'L\'Earth Overshoot Day marque la date ou l\'humanite a consomme toutes les ressources que la Terre peut regenerer en un an. En 2025 : debut aout. On vit "a credit" le reste de l\'annee.' },
                    { question: 'L\'eau douce accessible (lacs, rivieres, nappes) represente :', options: ['50% de l\'eau totale', '25% de l\'eau totale', 'Moins de 1% de l\'eau totale', '10% de l\'eau totale'], correctIndex: 2, explanation: 'L\'eau douce ne represente que 2,5% de l\'eau totale, et la plupart est piegee dans les glaciers. L\'eau douce accessible (lacs, nappes, rivieres) = seulement 0,7% du total.' },
                    { question: 'L\'eutrophisation est causee par :', options: ['Un manque de nutriments', 'Un exces de nitrates et phosphates dans l\'eau', 'La salinisation des sols', 'L\'augmentation de l\'oxygene dissous'], correctIndex: 1, explanation: 'L\'eutrophisation = enrichissement excessif en nutriments (engrais agricoles → nitrates/phosphates → proliferation d\'algues → decomposition → anoxie → mort des poissons). Cause des marees vertes.' },
                    { question: 'La biomagnification signifie que :', options: ['Les polluants se diluent dans la chaine alimentaire', 'La concentration de polluants augmente a chaque niveau trophique', 'Les organismes produisent plus de biomasse', 'Les predateurs sont immunises contre les polluants'], correctIndex: 1, explanation: 'Les polluants persistants (DDT, mercure) s\'accumulent a chaque niveau trophique. Un rapace en haut de chaine peut avoir une concentration 10 000 fois superieure a celle de l\'eau.' },
                    { question: 'Les energies renouvelables se distinguent des fossiles car :', options: ['Elles sont toujours moins cheres', 'Elles se renouvellent a l\'echelle humaine et emettent peu de CO2', 'Elles ne necessitent aucune technologie', 'Elles sont disponibles uniquement en ete'], correctIndex: 1, explanation: 'Les energies renouvelables (solaire, eolien, hydraulique, biomasse, geothermie) se renouvellent naturellement et emettent peu de gaz a effet de serre, contrairement aux fossiles (petrole, charbon, gaz).' },
                    { question: 'L\'albedo est :', options: ['Un type de gaz a effet de serre', 'Le pouvoir reflechissant d\'une surface', 'Un indicateur de biodiversite', 'La vitesse de fonte des glaciers'], correctIndex: 1, explanation: 'L\'albedo mesure la fraction de lumiere reflechie par une surface. Neige/glace = albedo eleve (~0,8). Ocean sombre = albedo faible (~0,1). La fonte des glaces reduit l\'albedo et amplifie le rechauffement.' },
                    { question: 'Un biome est defini par :', options: ['Une seule espece dominante', 'Les conditions climatiques et la vegetation dominante', 'La presence d\'un fleuve', 'Le type de sol uniquement'], correctIndex: 1, explanation: 'Un biome = grand ensemble d\'ecosystemes defini par le climat (temperature, precipitations) et la vegetation dominante. Exemples : foret tropicale, desert, taiga, toundra, savane.' }
                ]
            },

            // ===== SECTION 6 : GEOLOGIE & TECTONIQUE =====
            {
                id: 'geologie',
                title: 'Geologie et tectonique',
                icon: '\uD83C\uDF0B',
                content: '<h3>Structure interne de la Terre</h3>'
                    + '<ul>'
                    + '<li><strong>Croute</strong> : continentale (30-70 km, granitique) et oceanique (7-10 km, basaltique)</li>'
                    + '<li><strong>Manteau</strong> : superieur et inferieur (peridotite, jusqu\'a 2900 km)</li>'
                    + '<li><strong>Noyau</strong> : externe (liquide, fer-nickel) et interne/graine (solide)</li>'
                    + '<li><strong>Lithosphere</strong> (rigide) vs <strong>Asthenosphere</strong> (ductile)</li>'
                    + '</ul>'
                    + '<h3>Tectonique des plaques</h3>'
                    + '<ul>'
                    + '<li><strong>Divergence</strong> : dorsales oceaniques (accretion)</li>'
                    + '<li><strong>Convergence</strong> : subduction et collision</li>'
                    + '<li><strong>Transformantes</strong> : failles coulissantes (San Andreas)</li>'
                    + '<li><strong>Moteur</strong> : convection mantellique, slab pull, ridge push</li>'
                    + '</ul>'
                    + '<h3>Roches et datation</h3>'
                    + '<ul>'
                    + '<li><strong>Magmatiques</strong> (granite, basalte), <strong>sedimentaires</strong> (calcaire, gres), <strong>metamorphiques</strong> (gneiss, marbre)</li>'
                    + '<li><strong>Datation relative</strong> (superposition, recoupement) et <strong>absolue</strong> (radiochronologie, C14)</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Quelles sont les couches internes de la Terre ?', answer: 'De l\'exterieur vers l\'interieur : 1) Croute (continentale 30-70 km granitique, oceanique 7-10 km basaltique). 2) Manteau superieur (jusqu\'a 670 km). 3) Manteau inferieur (670-2900 km). 4) Noyau externe LIQUIDE (2900-5100 km, fer-nickel). 5) Graine/noyau interne SOLIDE (5100-6370 km). 💡 ASTUCE MEMO : "CMMNG" = Croute, Manteau superieur, Manteau inferieur, Noyau externe, Graine = "Ce Matin Maman N\'a pas Gronde".' },
                    { question: 'Quelle difference entre lithosphere et asthenosphere ?', answer: 'La LITHOSPHERE (0-100 km) comprend la croute + sommet du manteau superieur. Elle est RIGIDE et fragmentee en plaques. L\'ASTHENOSPHERE (100-670 km) est la couche ductile du manteau sur laquelle "glissent" les plaques lithospheriques. Elle est solide mais se deforme lentement (comme du miel tres epais). 🧠 TRUC POUR RETENIR : Litho = pierre (rigide comme la pierre). Astheno = sans force (molle, deformable).' },
                    { question: 'Qu\'est-ce qu\'une dorsale oceanique ?', answer: 'Une dorsale est une chaine de montagnes sous-marines a une limite de plaques DIVERGENTES. C\'est un lieu d\'ACCRETION oceanique : du magma basaltique remonte, se refroidit et forme de nouvelle lithosphere oceanique. La dorsale medio-atlantique fait 65 000 km de long — la plus longue chaine de montagnes du monde ! 🤯 Le savais-tu ? L\'Islande est l\'un des rares endroits ou la dorsale emerge au-dessus de l\'ocean — tu peux litteralement marcher ENTRE les plaques americaine et eurasienne !' },
                    { question: 'Decrire le mecanisme de la subduction.', answer: 'La subduction est le plongement d\'une plaque oceanique (plus dense) sous une autre plaque (continentale ou oceanique). Elle cree : 1) Une fosse oceanique (la ou la plaque plonge). 2) Un prisme d\'accretion (sediments accumules). 3) Un arc volcanique (volcanisme explosif par deshydratation de la plaque plongeante qui fait fondre le manteau). 4) Des seismes (friction entre les plaques). Exemple : fosse des Mariannes (11 034 m de profondeur).' },
                    { question: 'Comment la collision forme-t-elle des montagnes ?', answer: 'Quand deux plaques CONTINENTALES convergent (apres fermeture d\'un ocean par subduction), aucune ne peut plonger sous l\'autre (densites similaires ~2,7). Les roches se plissent, se fracturent et s\'epaississent, formant une chaine de collision. Exemple : l\'Himalaya (collision Inde-Eurasie, encore en cours — l\'Everest grandit de quelques mm/an !). Les Alpes (collision Afrique-Europe). 🤯 Le savais-tu ? On trouve des fossiles marins au sommet de l\'Everest — preuve que ces roches etaient au fond de l\'ocean avant la collision !' },
                    { question: 'Quelles sont les differences entre volcanisme effusif et explosif ?', answer: 'Effusif : magma basaltique FLUIDE (pauvre en silice), eruptions calmes avec coulees de lave. Exemples : Piton de la Fournaise, Hawaii. Explosif : magma andesitique/rhyolitique VISQUEUX (riche en silice), les gaz ne s\'echappent pas → explosions violentes, nuees ardentes, projections. Exemples : Montagne Pelee, Vesuve. 💡 ASTUCE MEMO : Fluide = coule doucement (Effusif). Visqueux = Pression qui monte = boum ! (Explosif). La silice, c\'est le bouchon de la bouteille de champagne.' },
                    { question: 'Quels sont les trois types de roches ?', answer: 'MAGMATIQUES : cristallisation d\'un magma. Plutoniques (refroidissement LENT en profondeur = gros cristaux : granite) et volcaniques (refroidissement RAPIDE en surface = microcristaux : basalte). SEDIMENTAIRES : depot et compaction de sediments (calcaire, gres, argile — contiennent les fossiles). METAMORPHIQUES : transformation par pression/temperature (argile → schiste → gneiss, calcaire → marbre). 🧠 TRUC POUR RETENIR : MaSMe = MAgmatique, Sedimentaire, MEtamorphique.' },
                    { question: 'Comment les ondes sismiques ont-elles revele la structure de la Terre ?', answer: 'Les ondes P (compression) traversent solides ET liquides. Les ondes S (cisaillement) NE traversent PAS les liquides. Les ondes S s\'arretent a 2900 km de profondeur → decouverte que le noyau externe est LIQUIDE (Gutenberg, 1914). Les changements de vitesse des ondes P revelent les discontinuites (Moho : croute/manteau a ~30 km, Gutenberg : manteau/noyau a 2900 km, Lehmann : noyau externe/graine a 5100 km).' },
                    { question: 'Qu\'est-ce que le principe de superposition en datation relative ?', answer: 'Le principe de superposition stipule que dans une serie sedimentaire NON DEFORMEE, une couche est plus RECENTE que celle qu\'elle recouvre. La couche la plus ancienne est en bas, la plus recente en haut. C\'est le principe fondamental de la datation relative. ⚠️ PIEGE BAC : Ce principe ne marche que si les couches n\'ont PAS ete retournees par des mouvements tectoniques — il faut toujours verifier !' },
                    { question: 'Expliquer le principe de la datation au carbone 14.', answer: 'Le 14C est un isotope radioactif du carbone (demi-vie = 5 730 ans). Les organismes VIVANTS incorporent du 14C (en equilibre avec l\'atmosphere). A la MORT, le 14C se desintegre sans etre renouvele. En mesurant le rapport 14C/12C restant, on calcule l\'age. Limite : ~50 000 ans (apres, trop peu de 14C). 💡 ASTUCE MEMO : Le 14C est un sablier qui se retourne a la mort de l\'organisme — plus il y a de sable en bas, plus l\'organisme est vieux.' },
                    { question: 'Qu\'est-ce que la radiochronologie et le couple Rb/Sr ?', answer: 'La radiochronologie utilise la desintegration d\'isotopes radioactifs pour dater les roches. Le rubidium 87 se desintegre en strontium 87 avec une demi-vie de 48,8 milliards d\'annees — parfait pour dater les roches ANCIENNES (millions/milliards d\'annees). On mesure le rapport 87Rb/87Sr dans differents mineraux d\'une roche et on construit une isochrone dont la pente donne l\'age. Autres couples : K/Ar (1,25 Ga), U/Pb (4,47 Ga).' },
                    { question: 'Quel est le moteur de la tectonique des plaques ?', answer: 'Le moteur principal est la CONVECTION MANTELLIQUE : la matiere chaude du manteau profond monte (moins dense), se refroidit en surface et redescend (plus dense). S\'y ajoutent : 1) Le "slab pull" (traction par la plaque plongeante — force PRINCIPALE). 2) Le "ridge push" (poussee a la dorsale). L\'energie provient de la chaleur interne de la Terre (desintegration radioactive + chaleur residuelle de formation).' },
                    { question: 'Qu\'est-ce qu\'un point chaud ?', answer: 'Un point chaud est une remontee de matiere anormalement chaude depuis le manteau profond (panache mantellique), fixe par rapport aux plaques. La plaque se deplace au-dessus, creant un alignement de volcans d\'age croissant. Exemple : l\'archipel d\'Hawaii (le volcan actif est au-dessus du point chaud, les iles plus anciennes sont plus loin). 🤯 Le savais-tu ? Le point chaud de la Reunion a cree il y a 66 Ma les immenses coulees de basalte du Deccan en Inde, qui ont contribue a l\'extinction des dinosaures !' },
                    { question: 'Qu\'est-ce que le Moho ?', answer: 'Le Moho (discontinuite de Mohorovicic, 1909) est la limite entre la croute et le manteau. Il se situe a ~7 km sous les oceans et ~30-70 km sous les continents. Il a ete decouvert grace a un brusque changement de vitesse des ondes sismiques P (de ~6,5 km/s dans la croute a ~8 km/s dans le manteau), signe d\'un changement de composition (granites/basaltes → peridotite).' },
                    { question: 'Qu\'est-ce que le cycle des roches ?', answer: 'Le cycle des roches decrit les transformations entre les 3 types de roches : 1) Magmatiques → erosion/transport/depot → Sedimentaires. 2) Sedimentaires → enfouissement + pression/temperature → Metamorphiques. 3) Metamorphiques → fusion partielle → Magma → Magmatiques. Tout type peut devenir n\'importe quel autre. Ce cycle, alimente par la tectonique et le climat, fonctionne depuis 4 milliards d\'annees.' },
                    { question: 'Qu\'est-ce qu\'une faille transformante ?', answer: 'Une faille transformante est une limite de plaques ou celles-ci COULISSENT horizontalement l\'une contre l\'autre (pas de creation ni destruction de lithosphere). Le mouvement est lateral. Exemple celebre : la faille de San Andreas en Californie (plaque pacifique glisse vers le nord-ouest par rapport a la plaque nord-americaine). Les failles transformantes generent des seismes puissants mais pas de volcanisme.' },
                    { question: 'Comment dater relativement des evenements geologiques ?', answer: '4 principes : 1) Superposition : la couche du dessous est la plus ancienne. 2) Recoupement : une structure qui en recoupe une autre est plus recente. 3) Inclusion : un fragment inclus dans une roche est plus ancien qu\'elle. 4) Identite paleontologique : deux couches contenant les memes fossiles stratigraphiques sont contemporaines. 💡 ASTUCE MEMO : SRII — Superposition, Recoupement, Inclusion, Identite paleontologique = "S\'il te plait, Retiens Immediatement l\'Idee".' },
                    { question: 'Qu\'est-ce que le metamorphisme et quels sont ses facteurs ?', answer: 'Le metamorphisme est la transformation d\'une roche preexistante sous l\'effet de la PRESSION et/ou de la TEMPERATURE, a l\'etat solide (sans fusion). Types : metamorphisme de contact (proximite d\'un magma → temperature), metamorphisme regional (enfouissement dans une zone de subduction/collision → pression + temperature). Exemples : argile → schiste → gneiss, calcaire → marbre. 💡 ASTUCE MEMO : Le metamorphisme, c\'est comme la cuisson en cocotte-minute — pression + chaleur transforment les ingredients (roches) !' },
                    { question: 'Qu\'est-ce qu\'un fossile stratigraphique ?', answer: 'Un fossile stratigraphique (ou fossile de facies ou fossile index) est un fossile qui permet de dater les couches sedimentaires. Criteres : 1) Grande extension geographique (repandu mondialement). 2) Courte duree d\'existence (permet une datation precise). 3) Abondant et facile a identifier. Exemples : ammonites, trilobites, foraminiferes. Le principe d\'identite paleontologique dit que deux couches contenant les memes fossiles stratigraphiques sont contemporaines.' },
                    { question: 'Qu\'est-ce que l\'isostasie ?', answer: 'L\'isostasie est l\'equilibre gravitaire entre la lithosphere (rigide, moins dense) et l\'asthenosphere (ductile, plus dense). La lithosphere "flotte" sur l\'asthenosphere comme un iceberg sur l\'eau. Plus la croute est epaisse (montagnes), plus elle s\'enfonce en profondeur (racine crustale). Quand la masse change (fonte des glaciers, erosion), la lithosphere se reajuste lentement = rebond isostatique. 🤯 Le savais-tu ? La Scandinavie remonte encore de ~1 cm/an depuis la fonte des glaciers il y a 10 000 ans !' },
                    { question: 'Qu\'est-ce qu\'une ophiolite et que prouve-t-elle ?', answer: 'Une ophiolite est un fragment de lithosphere oceanique (basalte + gabbro + peridotite) retrouve SUR un continent. Elle prouve qu\'un OCEAN EXISTAIT autrefois a cet endroit et qu\'il s\'est referme par subduction puis collision. C\'est une preuve majeure de la tectonique des plaques. Exemples : ophiolites du Chenaillet (Alpes francaises), ophiolites d\'Oman. 💡 ASTUCE MEMO : Une ophiolite, c\'est le "cadavre" d\'un ancien ocean piege dans une montagne !' },
                    { question: 'Qu\'est-ce que la demi-vie d\'un isotope radioactif ?', answer: 'La demi-vie (ou periode radioactive) est le temps necessaire pour que la MOITIE des atomes radioactifs d\'un echantillon se desintegrent. C\'est une constante propre a chaque isotope. Exemples : 14C = 5 730 ans (ideal pour dater les restes organiques recents), 40K = 1,25 milliard d\'annees, 87Rb = 48,8 milliards d\'annees (ideal pour les roches anciennes). Apres 1 demi-vie = 50% restant, 2 demi-vies = 25%, 3 demi-vies = 12,5%, etc.' },
                    { question: 'Qu\'est-ce que la Pangee ?', answer: 'La Pangee etait le dernier supercontinent, reuni il y a environ 250 millions d\'annees (Permien). Il reunissait tous les continents actuels en un seul bloc entoure d\'un unique ocean (Panthalassa). Sa fragmentation a commence au Jurassique (~200 Ma), separant d\'abord la Laurasia (nord) et le Gondwana (sud). Alfred Wegener a propose la derive des continents en 1912, mais n\'a ete accepte qu\'apres la decouverte de la tectonique des plaques dans les annees 1960.' },
                    { question: 'Comment les mineraux des roches magmatiques refletent-ils les conditions de cristallisation ?', answer: 'La TEXTURE des roches magmatiques reflete les conditions de refroidissement. Refroidissement LENT en profondeur = roches plutoniques, cristaux GROS et visibles (texture grenue : granite). Refroidissement RAPIDE en surface = roches volcaniques, cristaux MICROSCOPIQUES + pate vitreuse (texture microlitique : basalte). Plus le refroidissement est lent, plus les cristaux ont le temps de grossir. ⚠️ PIEGE BAC : Le granite et le basalte peuvent avoir la meme composition chimique, mais des textures differentes a cause des conditions de cristallisation !' },
                    { question: 'Qu\'est-ce qu\'un rift continental ?', answer: 'Un rift continental est une zone d\'extension ou la lithosphere continentale s\'amincit et se fracture, formant une vallee d\'effondrement (graben) bordee de failles normales. C\'est le DEBUT de la fracturation d\'un continent, qui peut eventuellement mener a l\'ouverture d\'un nouvel ocean. Exemple actuel : le Rift est-africain (de l\'Ethiopie au Mozambique). Exemple ancien : la separation de l\'Amerique du Sud et de l\'Afrique (ouverture de l\'ocean Atlantique au Jurassique). 🤯 Le savais-tu ? Le Rift est-africain est en train de couper l\'Afrique en deux — dans quelques millions d\'annees, la Corne de l\'Afrique sera une ile !' },
                    { question: 'Qu\'est-ce que la sismicite et comment mesure-t-on un seisme ?', answer: 'La sismicite est la frequence et l\'intensite des seismes dans une region. On mesure un seisme par : 1) La MAGNITUDE (echelle de Richter/moment : energie liberee, mesure instrumentale, logarithmique — chaque unite = ×32 en energie). 2) L\'INTENSITE (echelle de Mercalli/EMS : degats ressentis, varie selon la distance a l\'epicentre). Le foyer (hypocentre) est le point de rupture en profondeur. L\'epicentre est le point en surface a la verticale du foyer. 💡 ASTUCE MEMO : Magnitude = mesure par les Machines (sismographes). Intensite = mesure par les gens (Impact ressenti).' },
                    { question: 'Qu\'est-ce que la Ceinture de Feu du Pacifique ?', answer: 'La Ceinture de Feu du Pacifique est un alignement de volcans et de zones sismiques bordant l\'ocean Pacifique, sur environ 40 000 km. Elle concentre 75% des volcans actifs et 90% des seismes mondiaux. Elle correspond aux zones de SUBDUCTION qui entourent la plaque Pacifique (sous les plaques nord-americaine, philippine, eurasienne). Pays concernes : Japon, Indonesie, Philippines, Chili, ouest des Etats-Unis. C\'est la zone tectoniquement la plus active de la planete.' },
                    { question: 'Qu\'est-ce qu\'un tsunami et comment se forme-t-il ?', answer: 'Un tsunami est une serie de vagues oceaniques gigantesques causees par un deplacement brutal du fond marin (seisme sous-marin, eruption volcanique sous-marine, glissement de terrain). En pleine mer, la vague est basse (~1 m) mais tres rapide (~800 km/h). En approchant des cotes, elle ralentit mais sa hauteur augmente enormement (jusqu\'a 30+ metres). Le tsunami de 2004 dans l\'ocean Indien a cause ~230 000 morts. Systemes d\'alerte et education des populations sont essentiels.' },
                    { question: 'Qu\'est-ce que le paleomagnetisme et comment prouve-t-il la tectonique des plaques ?', answer: 'Le paleomagnetisme est l\'etude du champ magnetique terrestre enregistre dans les roches. Les mineraux magnetiques (magnetite) s\'orientent selon le champ magnetique au moment de leur cristallisation. Decouvertes cles : 1) Les INVERSIONS magnetiques (le pole nord et sud s\'inversent periodiquement). 2) Les ANOMALIES magnetiques symetriques de part et d\'autre des dorsales = preuve de l\'expansion oceanique. 3) Les derives des continents enregistrees dans les roches. 💡 ASTUCE MEMO : Les roches sont comme des boussoles figees — elles indiquent la direction du pole au moment de leur formation !' },
                    { question: 'Qu\'est-ce que la peridotite et ou la trouve-t-on ?', answer: 'La peridotite est la roche principale du MANTEAU terrestre. C\'est une roche magmatique plutonique riche en olivine et pyroxenes, de densite ~3,3. Elle n\'affleure que rarement en surface (ophiolites, kimberlites). Sa fusion partielle produit un magma BASALTIQUE (pauvre en silice = fluide = volcanisme effusif). Les donnees sur la peridotite viennent principalement de l\'etude des xenolithes (fragments de manteau remontes par les volcans) et des ondes sismiques.' },
                    { question: 'Qu\'est-ce que la geodesie spatiale et que mesure-t-elle ?', answer: 'La geodesie spatiale utilise les satellites (GPS, VLBI, InSAR) pour mesurer avec PRECISION les mouvements des plaques tectoniques en temps reel. Elle confirme les vitesses calculees par le paleomagnetisme : l\'Atlantique s\'ouvre de ~2,5 cm/an, la plaque Pacifique se deplace de ~7-10 cm/an. La geodesie peut aussi mesurer la deformation du sol autour des volcans (gonflement avant eruption) et les mouvements lies aux seismes. 🤯 Le savais-tu ? Paris et New York s\'eloignent de 2,5 cm par an — dans 200 millions d\'annees, l\'Atlantique aura double de largeur !' },
                    { question: 'Qu\'est-ce que le magmatisme d\'arc et comment se forme le magma en subduction ?', answer: 'En zone de subduction, la plaque plongeante se deshydrate (les mineraux hydrates liberent leur eau sous l\'effet de la pression). Cette eau remonte et abaisse le point de fusion du manteau sus-jacent → fusion PARTIELLE → formation de magma andesitique/rhyolitique (riche en silice = visqueux = volcanisme EXPLOSIF). C\'est ce qui cree les arcs volcaniques (Andes, Japon, Indonesie). 💡 ASTUCE MEMO : L\'eau de la plaque plongeante est comme un solvant — elle fait "fondre" le manteau au-dessus. L\'eau descend → le magma monte.' },
                    { question: 'Qu\'est-ce que les ressources geologiques et leur enjeu ?', answer: 'Les ressources geologiques comprennent : 1) Energies FOSSILES (petrole, gaz, charbon — formees en millions d\'annees, non renouvelables). 2) Mineraux et metaux (fer, cuivre, lithium, terres rares — essentiels pour la technologie). 3) Materiaux de construction (sable, gravier, calcaire). 4) Eau souterraine (nappes phreatiques). Enjeux : epuisement des reserves, impact environnemental de l\'extraction (mines, forages), conflits geopolitiques (petrole, terres rares). La transition energetique necessite paradoxalement d\'enormes quantites de mineraux (batteries au lithium, eoliennes au neodyme).' },
                    { question: 'Qu\'est-ce que l\'erosion et comment faconne-t-elle les paysages ?', answer: 'L\'erosion est l\'usure et le transport des roches par les agents d\'erosion : eau (rivières, pluie, glaciers), vent, gel/degel (gelifraction), organismes vivants (racines). L\'alteration peut etre MECANIQUE (fragmentation) ou CHIMIQUE (dissolution du calcaire par l\'eau acide = karst). Les sediments sont transportes et deposes dans les bassins sedimentaires (lacs, mers). L\'erosion nivelle les montagnes et comble les bassins — elle est le "sculpteur" des paysages. 🧠 TRUC POUR RETENIR : Les montagnes se construisent par la tectonique et se detruisent par l\'erosion — c\'est une course eternelle !' }
                ],
                quiz: [
                    { question: 'La lithosphere est composee de :', options: ['La croute uniquement', 'La croute et le manteau superieur rigide', 'Le manteau entier', 'La croute et le noyau'], correctIndex: 1, explanation: 'La lithosphere = croute + sommet rigide du manteau superieur. Elle repose sur l\'asthenosphere ductile.' },
                    { question: 'Une dorsale oceanique est une limite de plaques :', options: ['Convergente', 'Divergente', 'Transformante', 'Inactive'], correctIndex: 1, explanation: 'Aux dorsales, les plaques s\'ecartent (divergence). Du magma remonte et forme de nouvelle croute oceanique = accretion.' },
                    { question: 'Les ondes S ne traversent pas :', options: ['Les solides', 'Les liquides', 'Les gaz uniquement', 'L\'asthenosphere'], correctIndex: 1, explanation: 'Les ondes S (cisaillement) ne se propagent pas dans les liquides. Leur arret a 2900 km a prouve la nature liquide du noyau externe.' },
                    { question: 'Le volcanisme explosif est lie a un magma :', options: ['Basaltique et fluide', 'Riche en silice et visqueux', 'Pauvre en gaz', 'D\'origine mantellique directe'], correctIndex: 1, explanation: 'Un magma riche en silice est tres visqueux. Les gaz s\'y accumulent sous pression et provoquent des eruptions explosives violentes.' },
                    { question: 'Le granite est une roche :', options: ['Sedimentaire', 'Metamorphique', 'Magmatique plutonique', 'Magmatique volcanique'], correctIndex: 2, explanation: 'Le granite est magmatique plutonique : forme par refroidissement LENT en profondeur. Ses cristaux sont visibles a l\'oeil nu (texture grenue).' },
                    { question: 'La datation au carbone 14 est applicable sur environ :', options: ['1000 ans', '50 000 ans', '1 million d\'annees', '4,5 milliards d\'annees'], correctIndex: 1, explanation: 'La demi-vie du 14C = 5730 ans. Au-dela de ~50 000 ans (~8-9 demi-vies), la quantite restante est trop faible pour etre mesuree.' },
                    { question: 'La subduction genere :', options: ['Des dorsales oceaniques', 'Des fosses oceaniques et un arc volcanique', 'Des rifts continentaux uniquement', 'Des failles transformantes'], correctIndex: 1, explanation: 'La subduction cree une fosse oceanique, un prisme d\'accretion et un arc volcanique (par fusion partielle liee a la deshydratation de la plaque plongeante).' },
                    { question: 'Le principe de recoupement indique que :', options: ['Les couches se deposent horizontalement', 'Une structure qui en recoupe une autre est plus recente', 'Les fossiles permettent de dater les couches', 'Les couches les plus anciennes sont en bas'], correctIndex: 1, explanation: 'Le recoupement : une faille, un filon ou une intrusion qui recoupe une structure est POSTERIEURE a celle qu\'elle recoupe.' },
                    { question: 'L\'asthenosphere est :', options: ['Solide et rigide', 'Liquide', 'Ductile (solide mais deformable)', 'Gazeuse'], correctIndex: 2, explanation: 'L\'asthenosphere est solide mais se deforme lentement (ductile). C\'est sur elle que "flottent" les plaques lithospheriques.' },
                    { question: 'Les Alpes resultent de :', options: ['Une subduction active', 'Une collision entre deux plaques continentales', 'Un point chaud', 'Un rift continental'], correctIndex: 1, explanation: 'Les Alpes = collision Afrique (Apulie) / Eurasie, apres fermeture de l\'ocean alpin (Tethys).' },
                    { question: 'Un point chaud se caracterise par :', options: ['Un mouvement horizontal des plaques', 'Une remontee de matiere chaude fixe sous une plaque en mouvement', 'La subduction d\'une plaque', 'La collision de deux continents'], correctIndex: 1, explanation: 'Un point chaud = panache mantellique fixe. La plaque se deplace au-dessus, creant un alignement de volcans d\'age croissant (ex : Hawaii).' },
                    { question: 'Le Moho est la discontinuite entre :', options: ['Le manteau et le noyau', 'La croute et le manteau', 'Le noyau externe et la graine', 'La lithosphere et l\'atmosphere'], correctIndex: 1, explanation: 'Le Moho (discontinuite de Mohorovicic) separe la croute du manteau. La vitesse des ondes P y augmente brusquement (changement de composition).' },
                    { question: 'La force principale qui entraine les plaques est :', options: ['Le ridge push (poussee a la dorsale)', 'Le slab pull (traction de la plaque plongeante)', 'La rotation de la Terre', 'L\'attraction de la Lune'], correctIndex: 1, explanation: 'Le slab pull (traction par le poids de la plaque plongeante en subduction, plus dense que le manteau environnant) est considere comme le moteur principal de la tectonique.' },
                    { question: 'La faille de San Andreas est une limite :', options: ['Divergente', 'Convergente', 'Transformante', 'Inactive'], correctIndex: 2, explanation: 'San Andreas = faille transformante : les plaques pacifique et nord-americaine coulissent horizontalement l\'une contre l\'autre. Pas de volcanisme mais des seismes majeurs.' },
                    { question: 'Le metamorphisme transforme les roches par :', options: ['Fusion puis solidification', 'Erosion et transport', 'Pression et/ou temperature a l\'etat solide', 'Dissolution dans l\'eau'], correctIndex: 2, explanation: 'Le metamorphisme = transformation a l\'etat SOLIDE sous l\'effet de la pression et/ou de la temperature. Pas de fusion (sinon c\'est du magmatisme). Ex : argile → schiste → gneiss.' },
                    { question: 'Une ophiolite prouve :', options: ['L\'existence passee d\'un ocean a l\'emplacement d\'une montagne', 'Que les volcans crachent du granite', 'Que la Terre est plate', 'Que le noyau est solide'], correctIndex: 0, explanation: 'Une ophiolite est un fragment de lithosphere oceanique (basalte, gabbro, peridotite) retrouve sur un continent. C\'est la preuve qu\'un ocean existait avant la collision.' },
                    { question: 'L\'isostasie explique que :', options: ['Les continents flottent sur l\'eau', 'La lithosphere est en equilibre gravitaire sur l\'asthenosphere', 'La Terre est parfaitement spherique', 'Les ondes sismiques ne traversent pas les continents'], correctIndex: 1, explanation: 'L\'isostasie = equilibre de flottabilite de la lithosphere sur l\'asthenosphere. Plus la croute est epaisse, plus elle s\'enfonce. Quand la masse change (erosion, fonte), la lithosphere se reajuste.' },
                    { question: 'La Pangee etait :', options: ['Le premier ocean de la Terre', 'Le supercontinent reunissant toutes les terres il y a ~250 Ma', 'Un type de roche metamorphique', 'Le nom de la premiere cellule vivante'], correctIndex: 1, explanation: 'La Pangee etait le supercontinent (~250 Ma, Permien). Sa fragmentation a commence au Jurassique. Wegener a propose la derive des continents en 1912.' },
                    { question: 'La demi-vie du carbone 14 est de :', options: ['57 ans', '573 ans', '5 730 ans', '57 300 ans'], correctIndex: 2, explanation: 'La demi-vie du 14C = 5 730 ans. Apres 5 730 ans, il reste 50% du 14C initial. Apres 11 460 ans (2 demi-vies), il en reste 25%. Limite de la methode : ~50 000 ans.' },
                    { question: 'Un fossile stratigraphique doit etre :', options: ['Rare et localise dans une petite region', 'Repandu geographiquement, abondant et de courte duree d\'existence', 'Present uniquement dans les roches magmatiques', 'Le plus grand possible'], correctIndex: 1, explanation: 'Un bon fossile stratigraphique = grande repartition geographique + courte duree d\'existence (precision) + abondant + facile a identifier. Ex : ammonites, trilobites.' }
                ]
            },

            // ===== SECTION 7 : PROCREATION & SEXUALITE =====
            {
                id: 'procreation',
                title: 'Procreation et sexualite',
                icon: '\uD83E\uDDEC',
                content: '<h3>Appareils reproducteurs</h3>'
                    + '<ul>'
                    + '<li><strong>Masculin</strong> : testicules (spermatozoïdes + testosterone), epididyme, canaux deferents, prostate, vesicules seminales</li>'
                    + '<li><strong>Feminin</strong> : ovaires (ovocytes + oestrogenes/progesterone), trompes de Fallope, uterus, vagin</li>'
                    + '</ul>'
                    + '<h3>Gametogenese et hormones</h3>'
                    + '<ul>'
                    + '<li><strong>Spermatogenese</strong> : continue de la puberte a la mort, dans les tubes seminiferes. ~200 millions de spermatozoïdes/jour</li>'
                    + '<li><strong>Ovogenese</strong> : cyclique, un ovocyte par cycle. Stock d\'ovocytes fixe a la naissance (~1 million)</li>'
                    + '<li><strong>Axe hypothalamo-hypophysaire</strong> : GnRH → FSH + LH → hormones gonadiques → retrocontrole</li>'
                    + '</ul>'
                    + '<h3>Contraception et PMA</h3>'
                    + '<ul>'
                    + '<li><strong>Contraception hormonale</strong> : pilule, implant, patch — bloquent l\'ovulation par retrocontrole negatif</li>'
                    + '<li><strong>PMA</strong> : insemination artificielle, FIV, ICSI — aide a la procreation pour les couples infertiles</li>'
                    + '<li><strong>IST</strong> : VIH, chlamydia, HPV, herpes — prevention par le preservatif et le depistage</li>'
                    + '</ul>',
                flashcards: [
                    { question: 'Decrire l\'appareil reproducteur masculin.', answer: 'L\'appareil reproducteur masculin comprend : les TESTICULES (production des spermatozoïdes dans les tubes seminiferes + testosterone par les cellules de Leydig), l\'epididyme (maturation et stockage), les canaux deferents (transport), la PROSTATE et les vesicules seminales (secretion du liquide seminal). Le sperme = spermatozoïdes + liquide seminal. 🤯 Le savais-tu ? Un homme produit environ 200 millions de spermatozoïdes PAR JOUR, soit environ 500 milliards dans sa vie !' },
                    { question: 'Decrire l\'appareil reproducteur feminin.', answer: 'L\'appareil reproducteur feminin comprend : les OVAIRES (production des ovocytes + oestrogenes/progesterone), les TROMPES DE FALLOPE (lieu de la fecondation), l\'UTERUS (nidation et developpement de l\'embryon — l\'endometre s\'epaissit chaque cycle), le COL DE L\'UTERUS (secrete la glaire cervicale), le VAGIN. Le cycle menstruel dure en moyenne 28 jours.' },
                    { question: 'Qu\'est-ce que la spermatogenese ?', answer: 'La spermatogenese est la production de spermatozoïdes dans les TUBES SEMINIFERES des testicules, de la puberte jusqu\'a la fin de la vie. Etapes : spermatogonie (2n) → spermatocyte I (2n) → meiose I → spermatocyte II (n) → meiose II → spermatides (n) → spermiogenese → spermatozoïdes. Duree : environ 74 jours. Chaque spermatogonie produit 4 spermatozoïdes. 💡 ASTUCE MEMO : La spermatogenese est CONTINUE et ABONDANTE — comme une usine qui tourne 24h/24 sans arret.' },
                    { question: 'Qu\'est-ce que l\'ovogenese ?', answer: 'L\'ovogenese est la production d\'ovocytes dans les OVAIRES. Particularites : 1) Le stock est fixe a la NAISSANCE (~1 million d\'ovocytes I, bloques en prophase I). 2) A la puberte, a chaque cycle, UN ovocyte reprend la meiose (achevee en meiose I juste avant l\'ovulation, et en meiose II seulement si fecondation). 3) Une ovogonie produit 1 seul ovocyte + 3 globules polaires. 💡 ASTUCE MEMO : L\'ovogenese est CYCLIQUE et ECONOME — comme un distributeur qui donne UNE piece a la fois.' },
                    { question: 'Decrire le cycle menstruel.', answer: 'Le cycle menstruel (28 jours en moyenne) comprend : 1) Phase FOLLICULAIRE (J1-J14) : les regles (J1-5), un follicule murit sous l\'action de la FSH, il secrete des oestrogenes. 2) OVULATION (J14) : pic de LH declenche la liberation de l\'ovocyte. 3) Phase LUTEALE (J14-J28) : le corps jaune secrete de la progesterone + oestrogenes, l\'endometre s\'epaissit. Si pas de fecondation : chute hormonale → regles. 🧠 TRUC POUR RETENIR : "FOLL" (J1-14) = le FOLLicule murit. "LUT" (J14-28) = le corps jaune (LUTeum en latin) prend le relais.' },
                    { question: 'Qu\'est-ce que l\'axe hypothalamo-hypophysaire gonadique ?', answer: 'L\'HYPOTHALAMUS secrete la GnRH (de facon pulsatile). La GnRH stimule l\'HYPOPHYSE qui secrete FSH et LH. FSH et LH agissent sur les GONADES : FSH → maturation des follicules/spermatogenese. LH → ovulation/production de testosterone. Les hormones gonadiques exercent un RETROCONTROLE (negatif en general, positif juste avant l\'ovulation). 💡 ASTUCE MEMO : C\'est une cascade — Hypothalamus → Hypophyse → Gonades → retrocontrole. Comme un thermostat qui regule la temperature !' },
                    { question: 'Quel est le role des oestrogenes et de la progesterone ?', answer: 'OESTROGENES (secretes par les follicules/corps jaune) : developpement des caracteres sexuels secondaires, proliferation de l\'endometre, retrocontrole sur l\'axe HHG (negatif a faible dose, POSITIF a forte dose → declenchement du pic de LH → ovulation). PROGESTERONE (secretee par le corps jaune) : maintien de l\'endometre, preparation a la nidation, augmentation de la temperature corporelle, retrocontrole NEGATIF. ⚠️ PIEGE BAC : Les oestrogenes exercent un retrocontrole POSITIF uniquement a forte dose, juste avant l\'ovulation !' },
                    { question: 'Comment la testosterone agit-elle ?', answer: 'La TESTOSTERONE est l\'hormone sexuelle masculine principale, produite par les cellules de Leydig des testicules sous l\'action de la LH. Roles : 1) Spermatogenese (indispensable). 2) Developpement des caracteres sexuels secondaires (pilosite, mue de la voix, masse musculaire). 3) Libido. 4) Retrocontrole NEGATIF sur l\'axe hypothalamo-hypophysaire (stabilise la production). Production continue mais pulsatile.' },
                    { question: 'Decrire les etapes de la fecondation.', answer: '1) Les spermatozoïdes remontent les voies genitales feminines jusqu\'a la trompe de Fallope (sur ~300 millions, seuls quelques centaines atteignent l\'ovocyte). 2) Reaction acrosomique : le spermatozoïde libere des enzymes qui degradent la zone pellucide de l\'ovocyte. 3) Fusion des membranes (un seul spermatozoïde entre). 4) Reaction corticale (empeche la polyspermie). 5) Fusion des noyaux → zygote (2n). 🤯 Le savais-tu ? Sur 300 millions de spermatozoïdes, UN SEUL feconde l\'ovocyte — la competition la plus feroce de la nature !' },
                    { question: 'Qu\'est-ce que la nidation ?', answer: 'La nidation est l\'implantation de l\'embryon (au stade blastocyste, ~7 jours apres la fecondation) dans l\'endometre (muqueuse uterine preparee par la progesterone). Le trophoblaste du blastocyste s\'enfonce dans l\'endometre. Apres la nidation, le trophoblaste secrete l\'HCG (hormone detectee par les tests de grossesse), qui maintient le corps jaune actif et empeche les regles.' },
                    { question: 'Comment fonctionne la pilule contraceptive ?', answer: 'La pilule contraceptive contient des oestrogenes et/ou de la progesterone synthetiques qui exercent un RETROCONTROLE NEGATIF permanent sur l\'axe hypothalamo-hypophysaire. Consequences : 1) Pas de pic de LH → PAS d\'ovulation. 2) Glaire cervicale epaisse (empeche le passage des spermatozoïdes). 3) Endometre non receptif. La "semaine d\'arret" de la pilule provoque des regles de privation (pas de vraies regles). 💡 ASTUCE MEMO : La pilule fait croire au cerveau que la femme est "deja enceinte" hormonalement parlant.' },
                    { question: 'Quels sont les differents moyens de contraception ?', answer: 'HORMONAUX : pilule, implant, patch, anneau vaginal, injection (bloquent l\'ovulation). MECANIQUES : preservatif masculin/feminin (seule protection contre les IST !), DIU (sterilet au cuivre = empeche la nidation et est toxique pour les spermatozoïdes). D\'URGENCE : pilule du lendemain (levonorgestrel, efficace jusqu\'a 72h). DEFINITIFS : vasectomie, ligature des trompes. Le choix depend de la situation et doit etre discute avec un professionnel de sante.' },
                    { question: 'Qu\'est-ce que la FIV (Fecondation In Vitro) ?', answer: 'La FIV est une technique de PMA (Procreation Medicalement Assistee). Etapes : 1) Stimulation ovarienne (hormones FSH/LH pour obtenir plusieurs ovocytes). 2) Ponction des ovocytes. 3) Fecondation en laboratoire (in vitro = "dans le verre"). 4) Culture de l\'embryon pendant 2-5 jours. 5) Transfert d\'1-2 embryons dans l\'uterus. Taux de succes : environ 25-30% par tentative. Variante ICSI : injection directe d\'un spermatozoide dans l\'ovocyte.' },
                    { question: 'Quelles sont les principales IST et leur prevention ?', answer: 'IST majeures : VIH/SIDA (virus, retrovirus), chlamydia (bacterie, souvent asymptomatique — 1ere IST bacterienne en France), HPV (papillomavirus — risque de cancer du col), herpes genital (virus HSV), syphilis (bacterie), gonorrhee (bacterie). Prevention : PRESERVATIF (seule protection contre le VIH !), depistage regulier (beaucoup d\'IST sont asymptomatiques), vaccination HPV (garcons ET filles). Le depistage precoce permet un traitement efficace.' },
                    { question: 'Qu\'est-ce que la PMA et quelles sont les techniques ?', answer: 'La PMA (Procreation Medicalement Assistee) regroupe les techniques medicales aidant a concevoir : 1) INSEMINATION ARTIFICIELLE : depot de spermatozoïdes dans l\'uterus (infertilite masculine legere). 2) FIV : fecondation en laboratoire puis transfert d\'embryon. 3) ICSI : injection d\'un spermatozoide directement dans l\'ovocyte (infertilite masculine severe). 4) Don de gametes (ovocytes ou spermatozoïdes). En France, la PMA est ouverte aux couples et aux femmes seules depuis 2021.' },
                    { question: 'Comment le sexe est-il determine genetiquement chez l\'humain ?', answer: 'Le sexe est determine par les chromosomes sexuels : XX = femelle, XY = male. Le gene SRY (Sex-determining Region of Y) sur le chromosome Y declenche la differenciation des gonades en testicules (vers la 7eme semaine). Sans SRY, les gonades se developpent en ovaires. Les testicules secretent la testosterone (masculinisation) et l\'AMH (regression des canaux de Muller). 💡 ASTUCE MEMO : SRY = le Switch qui dit "Sois un gaRcon, Yes !" — sans lui, developpement feminin par defaut.' },
                    { question: 'Qu\'est-ce que la puberte et quelles hormones la declenchent ?', answer: 'La puberte est la periode de maturation sexuelle (10-16 ans) pendant laquelle l\'individu acquiert la capacite de se reproduire. Declenchement : reactivation de l\'axe hypothalamo-hypophysaire (secretion PULSATILE de GnRH → FSH + LH → hormones gonadiques). Garcons : testosterone → croissance, pilosite, mue de la voix, spermatogenese. Filles : oestrogenes → seins, pilosite, premieres regles (menarche). 🤯 Le savais-tu ? L\'age moyen de la puberte a recule de 2-3 ans en 150 ans, probablement a cause de la meilleure nutrition !' },
                    { question: 'Qu\'est-ce que l\'HCG et pourquoi est-elle importante ?', answer: 'L\'HCG (Human Chorionic Gonadotropin) est une hormone secretee par le TROPHOBLASTE de l\'embryon apres la nidation. Son role : maintenir le CORPS JAUNE actif (qui continue a secreter progesterone). Sans HCG, le corps jaune degenere, la progesterone chute et les regles surviennent = fin de la grossesse. C\'est l\'hormone detectee par les TESTS DE GROSSESSE (urinaires et sanguins). Son taux double toutes les 48h en debut de grossesse.' },
                    { question: 'Qu\'est-ce que le retrocontrole positif des oestrogenes ?', answer: 'En fin de phase folliculaire, le follicule dominant produit une GRANDE quantite d\'oestrogenes. Au-dela d\'un seuil, le retrocontrole bascule de negatif a POSITIF : les oestrogenes STIMULENT (au lieu d\'inhiber) la secretion de GnRH, FSH et surtout LH. Ce pic de LH declenche l\'OVULATION (~36h apres le pic de LH). C\'est le seul moment du cycle ou le retrocontrole est positif — une "exception qui confirme la regle".' },
                    { question: 'Quels sont les enjeux ethiques de la PMA et du diagnostic preimplantatoire ?', answer: 'Enjeux ethiques majeurs : 1) Le DPI (Diagnostic PreImplantatoire) permet de selectionner les embryons sains avant transfert (maladies genetiques graves) — risque de derive eugenique ? 2) Le statut de l\'embryon : a partir de quand est-il une personne ? 3) Le don de gametes et l\'anonymat. 4) La GPA (Gestation Pour Autrui) — interdite en France. 5) L\'acces egal a la PMA. La bioethique cherche a concilier progres medical et respect de la dignite humaine.' },
                    { question: 'Qu\'est-ce que la GnRH et comment est-elle secretee ?', answer: 'La GnRH (Gonadotropin-Releasing Hormone) est un neurohormone produite par l\'HYPOTHALAMUS de facon PULSATILE (secretion par "pulses" reguliers). Elle stimule l\'hypophyse anterieure qui secrete alors FSH et LH. La frequence des pulses de GnRH varie au cours du cycle : pulses rapides = plus de LH, pulses lents = plus de FSH. C\'est le "chef d\'orchestre" de tout l\'axe reproducteur.' },
                    { question: 'Qu\'est-ce que le corps jaune et son devenir ?', answer: 'Le corps jaune est le follicule transforme apres l\'ovulation. Il secrete PROGESTERONE (+ oestrogenes) pendant la phase luteale pour maintenir l\'endometre. Si PAS de fecondation : le corps jaune degenere apres ~14 jours → chute hormonale → regles. SI fecondation : l\'HCG secretee par l\'embryon MAINTIENT le corps jaune actif pendant les 3 premiers mois, jusqu\'a ce que le placenta prenne le relais. 💡 ASTUCE MEMO : Le corps jaune est le "gardien temporaire" de la grossesse — s\'il meurt trop tot, c\'est la fausse couche.' },
                    { question: 'Qu\'est-ce que la FSH et la LH ?', answer: 'FSH (Follicle-Stimulating Hormone) et LH (Luteinizing Hormone) sont des gonadotrophines secretees par l\'HYPOPHYSE anterieure. Chez la FEMME : FSH stimule la maturation des follicules ovariens. LH declenche l\'ovulation (pic de LH) et la formation du corps jaune. Chez l\'HOMME : FSH stimule la spermatogenese (via les cellules de Sertoli). LH stimule la production de testosterone (via les cellules de Leydig). 🧠 TRUC POUR RETENIR : FSH = Follicule/Spermatogenese. LH = Liberation (ovulation)/Leydig (testosterone).' },
                    { question: 'Qu\'est-ce que la menopause ?', answer: 'La menopause est l\'arret definitif des cycles menstruels (vers 50 ans en moyenne). Les ovaires ont epuise leur stock de follicules → plus d\'oestrogenes ni de progesterone → arret de l\'ovulation et des regles. Consequences : bouffees de chaleur, osteoporose (les oestrogenes protegent les os), secheresse vaginale. FSH et LH augmentent car il n\'y a plus de retrocontrole negatif par les hormones ovariennes.' },
                    { question: 'Qu\'est-ce que la reaction corticale lors de la fecondation ?', answer: 'La reaction corticale est un mecanisme de BLOCAGE DE LA POLYSPERMIE. Quand le premier spermatozoide fusionne avec l\'ovocyte, les granules corticaux liberent leur contenu, modifiant la zone pellucide (durcissement) pour empecher l\'entree de tout autre spermatozoide. Sans cette reaction, plusieurs spermatozoïdes entreraient → embryon polyploide → non viable. C\'est une course ou seul le premier gagne !' },
                    { question: 'Qu\'est-ce que le sterilet (DIU) au cuivre et comment agit-il ?', answer: 'Le DIU (Dispositif Intra-Uterin) au cuivre est un petit dispositif en forme de T place dans l\'uterus. Le cuivre est TOXIQUE pour les spermatozoïdes (les inactive) et provoque une inflammation locale de l\'endometre qui empeche la nidation. Ce n\'est PAS une methode hormonale : il n\'empeche pas l\'ovulation. Avantage : efficace pendant 5-10 ans sans y penser. C\'est l\'une des methodes les plus fiables (99,2%).' },
                    { question: 'Qu\'est-ce que le placenta et ses roles ?', answer: 'Le placenta est un organe temporaire qui se developpe pendant la grossesse a partir du trophoblaste. Roles : 1) Echanges mere-foetus (O2, nutriments, CO2, dechets) SANS melange des sangs. 2) Barriere protectrice (filtre partiel contre pathogenes). 3) Production d\'hormones (HCG, progesterone, oestrogenes des le 3eme mois). Le sang maternel et foetal ne se melangent PAS : les echanges se font par diffusion a travers les villosites choriales.' },
                    { question: 'Qu\'est-ce que l\'echographie et l\'amniocentese dans le suivi de grossesse ?', answer: 'L\'ECHOGRAPHIE utilise les ultrasons pour visualiser le foetus (non invasif, sans risque). Elle permet de suivre le developpement, detecter des anomalies morphologiques et determiner le sexe. L\'AMNIOCENTESE est un prelevement de liquide amniotique (cellules foetales) pour realiser un caryotype. Elle detecte les anomalies chromosomiques (trisomie 21) mais comporte un risque de fausse couche (~0,5%). Proposee si la mere a >35 ans ou si le depistage sanguin est positif.' },
                    { question: 'Comment fonctionne la pilule du lendemain ?', answer: 'La pilule du lendemain (contraception d\'urgence) contient du levonorgestrel (Norlevo, efficace jusqu\'a 72h) ou de l\'ulipristal (EllaOne, efficace jusqu\'a 120h). Mecanisme principal : retarder ou bloquer l\'OVULATION si elle n\'a pas encore eu lieu. Elle NE provoque PAS d\'avortement — si la nidation a deja eu lieu, elle est inefficace. Son efficacite diminue avec le temps : 95% dans les 24h, 85% entre 24-48h, 58% entre 48-72h. C\'est une methode d\'urgence, PAS une contraception reguliere.' },
                    { question: 'Qu\'est-ce que les cellules de Sertoli et les cellules de Leydig ?', answer: 'Dans les testicules, deux types de cellules ont des roles distincts. Les cellules de SERTOLI : situees dans les tubes seminiferes, elles "nourrissent" et soutiennent les spermatozoïdes en developpement. Elles secretent l\'inhibine (retrocontrole sur la FSH) et l\'ABP (proteine de liaison aux androgenes). Les cellules de LEYDIG : situees ENTRE les tubes seminiferes, elles produisent la TESTOSTERONE sous l\'action de la LH. 💡 ASTUCE MEMO : Sertoli = Support (dans les tubes). Leydig = Lieu de testosterone (entre les tubes).' },
                    { question: 'Qu\'est-ce que l\'implant contraceptif ?', answer: 'L\'implant contraceptif est un petit batonnet souple (4 cm) insere sous la peau du bras, qui libere en continu un progestatif (etonogestrel). Il agit en bloquant l\'ovulation (retrocontrole negatif permanent), en epaississant la glaire cervicale et en amincissant l\'endometre. Duree d\'efficacite : 3 ans. C\'est l\'une des methodes les plus fiables (99,9%) car il ne depend pas de l\'observance quotidienne (contrairement a la pilule). Reversible a tout moment en le retirant.' },
                    { question: 'Qu\'est-ce que l\'infertilite et quelles sont ses causes ?', answer: 'L\'infertilite est l\'incapacite de concevoir apres 12 mois de rapports reguliers sans contraception. Elle touche environ 1 couple sur 6 en France. Causes FEMININES (~40%) : troubles de l\'ovulation (SOPK), obstruction des trompes, endometriose, age avance. Causes MASCULINES (~40%) : oligospermie (peu de spermatozoïdes), azoospermie (absence), astenospermie (mobilite reduite). Causes MIXTES ou INEXPLIQUEES (~20%). Le bilan de fertilite examine les deux partenaires.' },
                    { question: 'Qu\'est-ce que le developpement embryonnaire precoce ?', answer: 'Apres la fecondation dans la trompe, le zygote (2n) se divise par mitoses successives : 2 cellules → 4 → 8 → morula (amas compact ~16 cellules, J3-J4) → blastocyste (cavite creuse, J5 : masse cellulaire interne = futur embryon, trophoblaste = futur placenta). Le blastocyste arrive dans l\'uterus vers J5 et s\'implante vers J7 (nidation). 🤯 Le savais-tu ? Pendant les 5 premiers jours, l\'embryon n\'a aucun apport de la mere — il vit sur les reserves de l\'ovocyte !' },
                    { question: 'Qu\'est-ce que la vaccination HPV et pourquoi est-elle recommandee ?', answer: 'Le HPV (Human Papillomavirus) est une IST tres courante qui peut causer des cancers (col de l\'uterus, gorge, anus). La vaccination (Gardasil 9) protege contre les souches les plus dangereuses. Recommandee pour les filles ET les garcons entre 11 et 14 ans (avant les premiers rapports sexuels). En Australie, ou la vaccination est generalisee depuis 2007, les cas de cancer du col ont chute de 75%. C\'est l\'un des rares cancers qu\'on peut PREVENIR par un vaccin !' },
                    { question: 'Qu\'est-ce que le consentement eclaire en sante sexuelle ?', answer: 'Le consentement eclaire est un principe ethique et legal fondamental : toute personne doit etre informee et donner son accord LIBRE pour tout acte medical ou sexuel. En sante : le patient doit comprendre le diagnostic, les traitements possibles, les risques et les alternatives avant de decider. En sexualite : le consentement doit etre LIBRE (sans pression), ECLAIRE (en toute connaissance), RECIPROQUE et REVOCABLE a tout moment. L\'absence de "non" n\'est pas un "oui". C\'est un enjeu majeur de sante publique et de respect des personnes.' },
                    { question: 'Comparer spermatogenese et ovogenese.', answer: 'SPERMATOGENESE : continue de la puberte a la mort, produit 4 spermatozoïdes par spermatogonie, ~200 millions/jour, dans les tubes seminiferes, cellules petites et mobiles. OVOGENESE : cyclique, UN ovocyte par cycle, stock fixe a la naissance (~1 million, ~400 ovules au total), dans les ovaires, cellule grosse et immobile (reserves). 💡 ASTUCE MEMO : La spermatogenese = usine de masse (quantite). L\'ovogenese = artisanat de luxe (qualite, un chef-d\'oeuvre a la fois). Le spermatozoïde est la plus petite cellule du corps, l\'ovocyte la plus grosse !' },
                    { question: 'Qu\'est-ce que l\'endometriose ?', answer: 'L\'endometriose est une maladie chronique ou du tissu semblable a l\'endometre se developpe EN DEHORS de l\'uterus (ovaires, trompes, peritoine). Ce tissu reagit aux hormones du cycle → saignements internes, inflammation, adhesions, douleurs intenses (surtout pendant les regles). Touche environ 10% des femmes en age de procreer. C\'est une cause importante d\'infertilite. Le diagnostic est souvent tardif (7 ans en moyenne). Traitements : antidouleurs, hormones, chirurgie. 🤯 Le savais-tu ? L\'endometriose touche 1 femme sur 10 mais reste encore trop meconnue et sous-diagnostiquee.' },
                    { question: 'Qu\'est-ce que la glaire cervicale et son role dans la fertilite ?', answer: 'La glaire cervicale est un mucus secrete par le col de l\'uterus. Sa consistance varie au cours du cycle sous l\'influence hormonale : 1) Hors ovulation : epaisse, collante, formant un "bouchon" muqueux qui bloque les spermatozoïdes. 2) Autour de l\'ovulation : fluide, transparente, filante (comme du blanc d\'oeuf) — elle facilite le passage et la survie des spermatozoïdes (jusqu\'a 5 jours). La glaire est donc un "filtre" naturel qui ne s\'ouvre qu\'en periode fertile. La pilule epaissit la glaire en permanence.' },
                    { question: 'Qu\'est-ce que la grossesse ectopique (extra-uterine) ?', answer: 'Une grossesse ectopique est une grossesse ou l\'embryon s\'implante EN DEHORS de l\'uterus, le plus souvent dans une TROMPE DE FALLOPE (95% des cas). La trompe ne peut pas s\'etirer suffisamment → risque de rupture et d\'hemorragie interne = URGENCE CHIRURGICALE. Causes : infections des trompes (IST, surtout chlamydia), endometriose, antecedent de chirurgie pelvienne. Symptomes : douleur abdominale laterale, saignements, malaise. C\'est la premiere cause de mortalite maternelle au 1er trimestre.' },
                    { question: 'Qu\'est-ce que la regulation hormonale de la lactation ?', answer: 'Apres l\'accouchement, deux hormones controlent la lactation : 1) PROLACTINE (hypophyse anterieure) : stimule la PRODUCTION de lait par les glandes mammaires. Secretee en reponse a la succion du bebe. 2) OCYTOCINE (hypophyse posterieure) : stimule l\'EJECTION du lait (contraction des cellules myoepitheliales autour des acini). L\'ocytocine est aussi l\'hormone de l\'attachement (liberee lors du contact peau-a-peau, du regard mere-bebe). 💡 ASTUCE MEMO : Prolactine = PROduit le lait. Ocytocine = fait sOrtir le lait (et cree le lien affectif).' },
                    { question: 'Qu\'est-ce que le diagnostic prenatal non invasif (DPNI) ?', answer: 'Le DPNI est une revolution recente : on analyse l\'ADN FOETAL circulant dans le sang MATERNEL (decouverte : des fragments d\'ADN du foetus passent dans le sang de la mere des les premieres semaines). Un simple prelevement sanguin maternel permet de detecter les trisomies 13, 18, 21 et les anomalies des chromosomes sexuels. Fiabilite >99% pour la trisomie 21. Avantage par rapport a l\'amniocentese : AUCUN risque de fausse couche (non invasif). Disponible des la 10eme semaine de grossesse.' },
                    { question: 'Qu\'est-ce que les jumeaux monozygotes vs dizygotes ?', answer: 'Jumeaux MONOZYGOTES (vrais jumeaux) : issus d\'un SEUL zygote qui se divise en deux embryons distincts. Ils sont genetiquement IDENTIQUES (meme ADN), toujours du meme sexe. Frequence : ~4/1000 naissances. Jumeaux DIZYGOTES (faux jumeaux) : issus de DEUX ovocytes fecondes par DEUX spermatozoïdes differents. Ils partagent ~50% de leurs genes (comme des freres/soeurs normaux), peuvent etre de sexes differents. Frequence : variable (~6-40/1000 selon les populations). 🧠 TRUC POUR RETENIR : MONO = UN oeuf divise en 2 = identiques. DI = DEUX oeufs = fraternels.' },
                    { question: 'Qu\'est-ce que la capacitation des spermatozoïdes ?', answer: 'La capacitation est une maturation FINALE des spermatozoïdes qui se produit dans les voies genitales feminines (uterus et trompes). Elle dure environ 6-7 heures. Modifications : destabilisation de la membrane, hyperactivation de la mobilite (mouvements vigoureux). Sans capacitation, les spermatozoïdes ne peuvent PAS feconder l\'ovocyte (ils ne peuvent pas realiser la reaction acrosomique). En FIV, on reproduit la capacitation in vitro. C\'est une etape meconnue mais INDISPENSABLE a la fecondation.' }
                ],
                quiz: [
                    { question: 'La spermatogenese se deroule dans :', options: ['L\'epididyme', 'Les tubes seminiferes des testicules', 'La prostate', 'Les vesicules seminales'], correctIndex: 1, explanation: 'La spermatogenese a lieu dans les tubes seminiferes des testicules. L\'epididyme sert a la maturation et au stockage des spermatozoides.' },
                    { question: 'L\'ovulation est declenchee par :', options: ['Un pic de FSH', 'Un pic de LH', 'Une chute de progesterone', 'Un pic de testosterone'], correctIndex: 1, explanation: 'Le pic de LH (declenche par le retrocontrole positif des oestrogenes a forte dose) provoque l\'ovulation environ 36 heures plus tard.' },
                    { question: 'Le retrocontrole positif des oestrogenes se produit :', options: ['Pendant les regles', 'En phase luteale', 'Juste avant l\'ovulation quand le taux est tres eleve', 'Pendant la grossesse uniquement'], correctIndex: 2, explanation: 'A forte dose (en fin de phase folliculaire), les oestrogenes stimulent l\'axe HHG au lieu de l\'inhiber, declenchant le pic de LH et l\'ovulation.' },
                    { question: 'La pilule contraceptive agit principalement en :', options: ['Detruisant les spermatozoïdes', 'Bloquant l\'ovulation par retrocontrole negatif', 'Accelerant le transit de l\'ovocyte', 'Augmentant la production de LH'], correctIndex: 1, explanation: 'Les hormones synthetiques de la pilule exercent un retrocontrole negatif permanent, empechant le pic de LH et donc l\'ovulation.' },
                    { question: 'La fecondation a lieu dans :', options: ['L\'uterus', 'Le vagin', 'La trompe de Fallope', 'L\'ovaire'], correctIndex: 2, explanation: 'La fecondation se produit dans le tiers superieur de la trompe de Fallope (trompe uterine). L\'embryon migre ensuite vers l\'uterus pour la nidation.' },
                    { question: 'Le gene SRY :', options: ['Se trouve sur le chromosome X', 'Determine le developpement masculin', 'Code les oestrogenes', 'Est present chez les deux sexes'], correctIndex: 1, explanation: 'Le gene SRY (Sex-determining Region of Y) sur le chromosome Y declenche la differenciation des gonades en testicules. Sans SRY = developpement ovarien.' },
                    { question: 'L\'HCG detectee par les tests de grossesse est produite par :', options: ['L\'ovaire', 'L\'hypothalamus', 'Le trophoblaste (embryon)', 'L\'hypophyse'], correctIndex: 2, explanation: 'L\'HCG est secretee par le trophoblaste apres la nidation. Elle maintient le corps jaune actif et est detectable dans l\'urine et le sang.' },
                    { question: 'Le seul moyen de contraception qui protege aussi contre les IST est :', options: ['La pilule', 'Le sterilet', 'Le preservatif', 'L\'implant'], correctIndex: 2, explanation: 'Le preservatif (masculin ou feminin) est le SEUL moyen de contraception qui protege egalement contre les IST (VIH, chlamydia, HPV, etc.).' },
                    { question: 'Le stock d\'ovocytes chez la femme :', options: ['Se renouvelle continuellement', 'Est fixe a la naissance (~1 million)', 'Augmente a la puberte', 'Est infini'], correctIndex: 1, explanation: 'A la naissance, une fille possede environ 1 million d\'ovocytes I (bloques en prophase I). Ce stock diminue avec l\'age. A la puberte, il en reste ~300 000. Environ 400 seront ovules au cours de la vie.' },
                    { question: 'La ICSI est une variante de la FIV qui :', options: ['Utilise uniquement des ovocytes congeles', 'Injecte directement un spermatozoide dans l\'ovocyte', 'Ne necessite pas de stimulation ovarienne', 'Utilise des gametes artificiels'], correctIndex: 1, explanation: 'L\'ICSI (Injection Intra-Cytoplasmique de Spermatozoide) est indiquee en cas d\'infertilite masculine severe : un spermatozoide est selectionne et micro-injecte directement dans l\'ovocyte.' },
                    { question: 'La phase luteale du cycle menstruel est dominee par :', options: ['Les oestrogenes seuls', 'La testosterone', 'La progesterone (+ oestrogenes)', 'La FSH'], correctIndex: 2, explanation: 'Apres l\'ovulation, le corps jaune secrete principalement de la progesterone (+ oestrogenes). La progesterone prepare l\'endometre a la nidation et exerce un retrocontrole negatif.' },
                    { question: 'La testosterone est produite par :', options: ['Les tubes seminiferes', 'Les cellules de Leydig des testicules', 'L\'hypophyse', 'Les vesicules seminales'], correctIndex: 1, explanation: 'Les cellules de Leydig, situees entre les tubes seminiferes, produisent la testosterone sous l\'action de la LH. La testosterone est indispensable a la spermatogenese et aux caracteres sexuels secondaires.' },
                    { question: 'La nidation correspond a :', options: ['La fecondation de l\'ovocyte', 'L\'implantation de l\'embryon dans l\'endometre', 'La liberation de l\'ovocyte par l\'ovaire', 'La division du zygote en 2 cellules'], correctIndex: 1, explanation: 'La nidation est l\'implantation du blastocyste (embryon de ~7 jours) dans l\'endometre uterin. Le trophoblaste s\'enfonce dans la muqueuse et commence a secreter l\'HCG.' },
                    { question: 'En France, la PMA est accessible :', options: ['Uniquement aux couples heterosexuels maries', 'Aux couples et aux femmes seules (depuis 2021)', 'A toute personne sans condition', 'Uniquement en cas de maladie genetique'], correctIndex: 1, explanation: 'Depuis la loi de bioethique de 2021, la PMA est ouverte en France aux couples de femmes et aux femmes seules, en plus des couples heterosexuels.' },
                    { question: 'La GnRH est secretee par :', options: ['L\'hypophyse', 'L\'hypothalamus', 'Les ovaires', 'Les testicules'], correctIndex: 1, explanation: 'La GnRH est un neurohormone produite par l\'HYPOTHALAMUS de facon pulsatile. Elle stimule l\'hypophyse qui secrete alors FSH et LH.' },
                    { question: 'Le corps jaune secrete principalement :', options: ['De la FSH', 'De la testosterone', 'De la progesterone', 'De la GnRH'], correctIndex: 2, explanation: 'Le corps jaune (follicule transforme apres ovulation) secrete surtout de la progesterone (+ oestrogenes) pendant la phase luteale pour maintenir l\'endometre pret a la nidation.' },
                    { question: 'La reaction corticale lors de la fecondation sert a :', options: ['Attirer plus de spermatozoïdes', 'Empecher l\'entree d\'autres spermatozoïdes (blocage de la polyspermie)', 'Declencher la division cellulaire', 'Nourrir l\'ovocyte'], correctIndex: 1, explanation: 'La reaction corticale durcit la zone pellucide de l\'ovocyte apres l\'entree du premier spermatozoide, empechant la polyspermie (qui donnerait un embryon polyploide non viable).' },
                    { question: 'Le placenta permet les echanges mere-foetus :', options: ['Par melange direct des sangs', 'Par diffusion a travers les villosites SANS melange des sangs', 'Par transfusion directe', 'Uniquement au 3eme trimestre'], correctIndex: 1, explanation: 'Le sang maternel et foetal ne se melangent PAS. Les echanges (O2, nutriments, CO2, dechets) se font par diffusion a travers la paroi fine des villosites choriales.' },
                    { question: 'La menopause s\'accompagne d\'une augmentation de :', options: ['Oestrogenes', 'Progesterone', 'FSH et LH', 'Testosterone'], correctIndex: 2, explanation: 'A la menopause, les ovaires n\'ayant plus de follicules, ils ne produisent plus d\'oestrogenes ni de progesterone. Le retrocontrole negatif disparait → FSH et LH augmentent fortement.' },
                    { question: 'L\'amniocentese permet de :', options: ['Visualiser le foetus par ultrasons', 'Realiser un caryotype foetal a partir du liquide amniotique', 'Determiner le groupe sanguin de la mere', 'Mesurer le taux d\'HCG'], correctIndex: 1, explanation: 'L\'amniocentese preleve du liquide amniotique contenant des cellules foetales. On peut en extraire l\'ADN et realiser un caryotype pour detecter les anomalies chromosomiques (trisomie 21).' },
                    { question: 'La FSH chez l\'homme stimule :', options: ['La production de testosterone', 'La spermatogenese via les cellules de Sertoli', 'L\'ovulation', 'La production de GnRH'], correctIndex: 1, explanation: 'Chez l\'homme, la FSH agit sur les cellules de Sertoli dans les tubes seminiferes pour stimuler et soutenir la spermatogenese. La LH agit sur les cellules de Leydig pour la testosterone.' },
                    { question: 'La pilule du lendemain agit principalement en :', options: ['Provoquant un avortement', 'Retardant ou bloquant l\'ovulation', 'Detruisant les spermatozoïdes', 'Epaississant l\'endometre'], correctIndex: 1, explanation: 'La pilule du lendemain retarde ou bloque l\'ovulation si elle n\'a pas encore eu lieu. Elle N\'est PAS abortive — si la nidation est deja faite, elle est inefficace. Efficacite max dans les 24h.' },
                    { question: 'Le DIU au cuivre agit en :', options: ['Bloquant l\'ovulation', 'Etant toxique pour les spermatozoïdes et empechant la nidation', 'Augmentant la secretion de LH', 'Epaississant la glaire cervicale uniquement'], correctIndex: 1, explanation: 'Le cuivre est toxique pour les spermatozoïdes et provoque une inflammation locale de l\'endometre qui empeche la nidation. Ce n\'est PAS une methode hormonale — l\'ovulation a lieu normalement.' },
                    { question: 'Le placenta produit :', options: ['Uniquement de l\'HCG', 'Des hormones (HCG, progesterone, oestrogenes) des le 3eme mois de grossesse', 'Uniquement du lait maternel', 'Des spermatozoïdes'], correctIndex: 1, explanation: 'Le placenta prend le relais du corps jaune vers le 3eme mois : il produit progesterone, oestrogenes et HCG pour maintenir la grossesse. Les echanges mere-foetus se font via les villosites choriales.' },
                    { question: 'Les jumeaux monozygotes sont :', options: ['Issus de deux ovocytes differents', 'Issus d\'un seul zygote qui se divise en deux', 'Toujours de sexes differents', 'Genetiquement differents'], correctIndex: 1, explanation: 'Les vrais jumeaux (monozygotes) proviennent d\'un SEUL zygote qui se scinde en deux embryons. Ils ont le meme ADN et sont toujours du meme sexe. Les faux jumeaux (dizygotes) viennent de deux ovocytes differents.' },
                    { question: 'La capacitation des spermatozoïdes :', options: ['Se produit dans les testicules', 'Est une maturation finale dans les voies genitales feminines necessaire a la fecondation', 'Est le processus de formation du spermatozoide', 'N\'est pas necessaire pour la FIV'], correctIndex: 1, explanation: 'La capacitation se produit dans l\'uterus et les trompes (6-7h). Elle modifie la membrane du spermatozoide pour le rendre capable de realiser la reaction acrosomique et donc de feconder l\'ovocyte.' }
                ]
            }
        ]
    });
})();
